  `cv_url` varchar(500) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'URL del CV',
  `genero` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Género',
  `fecha_nacimiento` date DEFAULT NULL COMMENT 'Fecha de nacimiento (para estadísticas generacionales)',
  `pais_nacimiento` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'País de nacimiento',
