  `idioma_nativo` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Idioma materno',
  `afiliacion_actual` varchar(500) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Institución actual',
  `departamento` varchar(300) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Departamento/División',
  `facultad` varchar(300) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Facultad/Escuela',
  `cargo_actual` varchar(200) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Cargo/Posición',
