  `h_index` int DEFAULT NULL COMMENT 'H-index',
  `h_index_fuente` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Fuente del h-index (Scopus, WoS, GScholar)',
  `i10_index` int DEFAULT NULL COMMENT 'i10-index (Google Scholar)',
