  `proyectos_actuales` text COLLATE utf8mb4_unicode_ci COMMENT 'Proyectos de investigación activos separados por ;',
  `fuentes_financiamiento` text COLLATE utf8mb4_unicode_ci COMMENT 'Agencias que lo financian separadas por ;',
  `laboratorio` varchar(300) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Laboratorio/Grupo de investigación',
  `url_laboratorio` varchar(500) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'URL del laboratorio',
  `premios` text COLLATE utf8mb4_unicode_ci COMMENT 'Premios recibidos separados por ; (formato: año|nombre|institución)',
  `becas` text COLLATE utf8mb4_unicode_ci COMMENT 'Becas/Fellowships separadas por ;',
  `honores` text COLLATE utf8mb4_unicode_ci COMMENT 'Honores académicos separados por ;',
