INSERT INTO `cmb_biblatex` VALUES (2,'biblatex_tipo','article','Artículo de revista o periódico',1),(3,'biblatex_tipo','book','Libro',1),(4,'biblatex_tipo','bookinbook','Libro dentro de otro libro',1),(5,'biblatex_tipo','booklet','Folleto o cuadernillo sin editor formal',1),(6,'biblatex_tipo','collection','Obra colectiva (libro con varios autores)',1),(7,'biblatex_tipo','conference','Ponencia o trabajo presentado en congreso (equivalente a inproceedings)',1),(8,'biblatex_tipo','inbook','Capítulo o sección de un libro',1),(9,'biblatex_tipo','incollection','Capítulo dentro de una obra colectiva',1),(10,'biblatex_tipo','inproceedings','Trabajo en actas de congreso',1),(11,'biblatex_tipo','inreference','Artículo en una obra de referencia',1),(12,'biblatex_tipo','manual','Manual o guía técnica',1),(13,'biblatex_tipo','misc','Miscelánea (documento no clasificable en otro tipo)',1),(14,'biblatex_tipo','movie','Película o material audiovisual',1),(15,'biblatex_tipo','mvbook','Obra en varios volúmenes (libro multivolumen)',1),(16,'biblatex_tipo','mvcollection','Colección multivolumen',1),(17,'biblatex_tipo','mvproceedings','Actas de congreso en varios volúmenes',1),(18,'biblatex_tipo','mvreference','Obra de referencia multivolumen',1),(19,'biblatex_tipo','online','Recurso en línea o sitio web',1),(20,'biblatex_tipo','patent','Patente',1),(21,'biblatex_tipo','periodical','Publicación periódica (revista, boletín, etc.)',1),(22,'biblatex_tipo','proceedings','Actas de congreso',1),(23,'biblatex_tipo','reference','Obra de referencia (diccionario, enciclopedia, etc.)',1),(24,'biblatex_tipo','report','Informe o documento técnico',1),(25,'biblatex_tipo','set','Conjunto de obras relacionadas',1),(26,'biblatex_tipo','software','Programa informático',1),(27,'biblatex_tipo','suppbook','Suplemento de un libro',1),(28,'biblatex_tipo','suppcollection','Suplemento de una obra colectiva',1),(29,'biblatex_tipo','suppperiodical','Suplemento de una publicación periódica',1),(30,'biblatex_tipo','thesis','Tesis',1),(31,'biblatex_tipo','unpublished','Material inédito',1),(32,'biblatex_tipo','xdata','Datos externos (tipo auxiliar de BibLaTeX, no bibliográfico)',1),(33,'editor_type','','',1),(34,'editor_type','collaborator','collaborator',1),(35,'editor_type','compiler','compiler',1),(36,'editor_type','continuator','continuator',1),(37,'editor_type','coordinator','coordinator',1),(38,'editor_type','direction','direction',1),(39,'editor_type','editor','editor',1),(41,'editor_type','organizer','organizer',1),(42,'editor_type','redactor','redactor',1),(43,'editor_type','reviser','reviser',1),(56,'pagination','page','page',1),(57,'pagination','column','column',1),(58,'pagination','line','line',1),(59,'pagination','verse','verse',1),(60,'pagination','section','section',1),(61,'pagination','paragraph','paragraph',1),(92,'language','spanish','spanish',1),(93,'language','portuguese','portuguese',1),(94,'language','english','english',1),(95,'language','french','french',1),(96,'language','armenian','armenian',1),(97,'language','korean','korean',1),(98,'language','german','german',1),(99,'language','italian','italian',1),(100,'language','japanese','japanese',1),(101,'language','norwegian','norwegian',1),(102,'language','turkish','turkish',1),(103,'language','chinese','chinese',1),(104,'language','greek','greek',1),(105,'language','hebrew','hebrew',1),(106,'language','swedish','swedish',1),(107,'language','slovak','slovak',1),(108,'language','russian','russian',1),(109,'language','hindi','hindi',1),(110,'language','vietnamese','vietnamese',1),(111,'language','latin','latin',1),(112,'language','czech','czech',1),(113,'language','bulgarian','bulgarian',1),(114,'language','romanian','romanian',1),(115,'language','slovenian','slovenian',1),(116,'language','scottish','scottish',1),(117,'language','dutch','dutch',1),(118,'language','catalan','catalan',1),(119,'language','galician','galician',1),(121,'eprint','arXiv','arXiv',1),(122,'eprint','PubMed','PubMed',1),(123,'eprint','J