','translatedas',1),(169,'related_type','multivolume','multivolume',1),(170,'pubstate','draft','draft',1),(171,'pubstate','manuscript','manuscript',1),(172,'pubstate','cancelled','cancelled',1),(173,'pubstate','outofprint','outofprint',1),(174,'pubstate','archival','archival',1);
