INSERT INTO `perfiles_shortcode` VALUES (1,'03_Perfil: Medicina','Perfil para revistas de ciencias médicas y de la salud. Incluye shortcodes para estructuras clínicas, fórmulas químicas y datos de ensayos.','JATS 1.3',1,'2025-12-19 02:23:35','2026-04-24 18:54:11'),(3,'04_Perfil: Ciencias Sociales','Perfil para revistas de sociología, antropología, ciencia política y economía. Incluye shortcodes para entrevistas, estudios de caso y datos cualitativos.','JATS 1.3',1,'2025-12-19 02:23:35','2026-04-24 18:54:27'),(4,'00_Comunes','Perfil genérico con shortcodes comunes a todas las disciplinas.','JATS 1.3',1,'2025-12-19 02:23:35','2026-04-24 18:53:20'),(5,'06_Perfil: Química','Shortcodes para publicaciones de química: estructuras moleculares, ecuaciones, esquemas de reacción','JATS 1.3',1,'2025-12-19 18:45:21','2026-04-24 18:54:56'),(6,'05_Perfil: Matemáticas y Física','Shortcodes para publicaciones de matemáticas y física: teoremas, demostraciones, ecuaciones','JATS 1.3',1,'2025-12-19 18:45:21','2026-04-24 18:54:42'),(7,'07_Perfil: Filología','Shortcodes para publicaciones filológicas: aparato crítico, glosas, transcripciones','JATS 1.3',1,'2025-12-19 18:45:21','2026-04-24 18:55:09'),(8,'01_Estructura interna','Modelos de sección (sec-type) para estructurar artículos académicos. No acumula shortcodes generales.','JATS 1.4',1,'2026-02-21 22:41:53','2026-04-24 18:50:46');
