LOCK TABLES `consultas` WRITE;
/*!40000 ALTER TABLE `consultas` DISABLE KEYS */;
INSERT INTO `consultas` VALUES (14,0,'AUT-REV-001: Pool de revisores disponibles por área','Muestra cantidad de revisores disponibles/no disponibles por área de investigación','SELECT \n    area_investigacion AS \'Área de Investigación\',\n    COUNT(*) AS \'Total Revisores\',\n    SUM(CASE WHEN disponible_revision = 1 THEN 1 ELSE 0 END) AS \'Disponibles\',\n    SUM(CASE WHEN disponible_revision = 0 THEN 1 ELSE 0 END) AS \'No Disponibles\',\n    ROUND(AVG(calificacion_colaboracion), 2) AS \'Calificación Promedio\'\nFROM autores\nWHERE estado_autor = \'activo\'\n    AND area_investigacion IS NOT NULL\nGROUP BY area_investigacion\nORDER BY Disponibles DESC;\n','Asignación rápida de manuscritos, identificación de gaps de cobertura. Frecuencia recomendada: Semanal','sistema','2026-01-31 02:36:08'),(15,0,'AUT-REV-002: Revisores con expertise específico','Lista de revisores disponibles con sus áreas de expertise detalladas','SELECT \n    apellidos_nombre AS \'Nombre Completo\',\n    email_principal AS \'Email\',\n    afiliacion_actual AS \'Institución\',\n    areas_revision AS \'Áreas de Revisión\',\n    expertise_revision AS \'Expertise Específico\',\n    calificacion_colaboracion AS \'Calificación\'\nFROM autores\nWHERE disponible_revision = 1\n    AND estado_autor = \'activo\'\n    AND areas_revision IS NOT NULL\nORDER BY calificacion_colaboracion DESC, apellidos;\n','Matching preciso de manuscritos con revisores. Frecuencia recomendada: Diaria','sistema','2026-01-31 02:40:33'),(16,0,'AUT-REV-003: Alertas de áreas críticas','Áreas con menos de 3 revisores disponibles (requiere atención urgente)','SELECT \n    area_investigacion AS \'Área Crítica\',\n    COUNT(*) AS \'Revisores Disponibles\',\n    GROUP_CONCAT(apellidos_nombre SEPARATOR \'; \') AS \'Nombres\'\nFROM autores\nWHERE disponible_revision = 1\n    AND estado_autor = \'activo\'\n    AND area_investigacion IS NOT NULL\nGROUP BY area_investigacion\nHAVING COUNT(*) < 3\nORDER BY COUNT(*), area_investigacion;\n','Planificación de convocatorias, identificación de necesidades. Frecuencia recomendada: Quincenal','sistema','2026-01-31 02:42:17'),(17,0,'AUT-REV-004: Carga de trabajo de revisores','Revisores activos con cantidad de revisiones asignadas','SELECT \n    a.apellidos_nombre AS \'Revisor\',\n    a.email_principal AS \'Email\',\n    COUNT(ar.id_revision) AS \'Revisiones Activas\',\n    SUM(CASE WHEN ar.decision IS NULL THEN 1 ELSE 0 END) AS \'Pendientes\',\n    SUM(CASE WHEN ar.decision IS NOT NULL THEN 1 ELSE 0 END) AS \'Completadas\',\n    a.calificacion_colaboracion AS \'Calificación\'\nFROM autores a\nLEFT JOIN articulo_revisor ar ON a.id_autor = ar.id_autor\nWHERE a.disponible_revision = 1\n    AND a.estado_autor = \'activo\'\nGROUP BY a.id_autor\nORDER BY COUNT(ar.id_revision) DESC;\n','Balance de carga, identificación de sobrecarga. Frecuencia recomendada: Semanal','sistema','2026-01-31 02:44:19'),(18,0,'AUT-REV-005: Revisores con conflictos de interés','Lista de revisores con conflictos permanentes registrados','SELECT \n    apellidos_nombre AS \'Revisor\',\n    email_principal AS \'Email\',\n    conflictos_permanentes AS \'Conflictos Registrados\',\n    areas_revision AS \'Áreas de Revisión\'\nFROM autores\nWHERE conflictos_permanentes IS NOT NULL\n    AND conflictos_permanentes != \'\'\n    AND estado_autor = \'activo\'\nORDER BY apellidos;\n','Evitar asignaciones problemáticas. Frecuencia recomendada: Mensual (auditoría)','sistema','2026-01-31 02:45:38'),(19,0,'AUT-BIB-001: Top 20 autores por h-index','Ranking de autores con mayor impacto académico','SELECT \n    apellidos_nombre AS \'Autor\',\n    h_index AS \'h-index\',\n    i10_index AS \'i10-index\',\n    numero_publicaciones AS \'Publicaciones\',\n    numero_citas AS \'Citas\',\n    afiliacion_actual AS \'Institución\',\n    pais_afiliacion AS \'País\'\nFROM autores\nWHERE h_index IS NOT NULL\n    AND estado_autor = \'activo\'\nORDER BY h_index DESC, numero_citas DESC\nLIMIT 20;\n','Identificar autores líderes para invitaciones especiales. Frecuencia recomendada: Trimestral','sistema','2026-01-31 02:46:56'),(20,0,'AUT-BIB-002: Distribución por rangos de h-index','Segmentación de autores por nivel de impacto académico','SELECT \n    CASE \n        WHEN h_index BETWEEN 0 AND 5 THEN \'0-5 (Emergentes)\'\n        WHEN h_index BETWEEN 6 AND 10 THEN \'6-10 (Intermedios)\'\n        WHEN h_index BETWEEN 11 AND 20 THEN \'11-20 (Consolidados)\'\n        WHEN h_index > 20 THEN \'21+ (Líderes)\'\n        ELSE \'Sin datos\'\n    END AS \'Rango h-index\',\n    COUNT(*) AS \'Cantidad de Autores\',\n    ROUND(COUNT(*) * 100.0 / (SELECT COUNT(*) FROM autores WHERE estado_autor = \'activo\'), 2) AS \'Porcentaje\'\nFROM autores\nWHERE estado_autor = \'activo\'\nGROUP BY \n    CASE \n        WHEN h_index BETWEEN 0 AND 5 THEN \'0-5 (Emergentes)\'\n        WHEN h_index BETWEEN 6 AND 10 THEN \'6-10 (Intermedios)\'\n        WHEN h_index BETWEEN 11 AND 20 THEN \'11-20 (Consolidados)\'\n        WHEN h_index > 20 THEN \'21+ (Líderes)\'\n        ELSE \'Sin datos\'\n    END\nORDER BY MIN(COALESCE(h_index, 999));\n','Análisis de perfil de la comunidad de autores. Frecuencia recomendada: Semestral','sistema','2026-01-31 02:48:12'),(21,0,'AUT-BIB-003: Métricas desactualizadas (GOBERNANZA)','Autores con métricas que necesitan actualización (>6 meses)','SELECT \n    apellidos_nombre AS \'Autor\',\n    h_index AS \'h-index\',\n    fecha_actualizacion_metricas AS \'Última Actualización\',\n    DATEDIFF(CURDATE(), fecha_actualizacion_metricas) AS \'Días Desactualizado\',\n    email_principal AS \'Email\',\n    estado_autor AS \'Estado\'\nFROM autores\nWHERE fecha_actualizacion_metricas < DATE_SUB(CURDATE(), INTERVAL 6 MONTH)\n    AND estado_autor = \'activo\'\n    AND h_index IS NOT NULL\nORDER BY fecha_actualizacion_metricas ASC;\n','Mantenimiento de base de datos, control de calidad. Frecuencia recomendada: Mensual','sistema','2026-01-31 02:50:26'),(22,0,'AUT-INST-001: Top 20 instituciones por cantidad de autores','Ranking de instituciones más representadas','SELECT \n    afiliacion_actual AS \'Institución\',\n    pais_afiliacion AS \'País\',\n    COUNT(*) AS \'Cantidad de Autores\',\n    COUNT(CASE WHEN ror_id IS NOT NULL AND ror_id != \'\' THEN 1 END) AS \'Con ROR ID\',\n    ROUND(COUNT(*) * 100.0 / (SELECT COUNT(*) FROM autores WHERE estado_autor = \'activo\'), 2) AS \'Porcentaje\'\nFROM autores\nWHERE estado_autor = \'activo\'\n    AND afiliacion_actual IS NOT NULL\nGROUP BY afiliacion_actual, pais_afiliacion\nORDER BY COUNT(*) DESC\nLIMIT 20;\n','Reportes institucionales, identificación de colaboradores estratégicos. Frecuencia recomendada: Trimestral','sistema','2026-01-31 02:51:41'),(23,0,'AUT-INST-002: Distribución geográfica','Autores por país de afiliación','SELECT \n    pais_afiliacion AS \'País\',\n    COUNT(*) AS \'Autores\',\n    ROUND(COUNT(*) * 100.0 / (SELECT COUNT(*) FROM autores WHERE estado_autor = \'activo\'), 2) AS \'Porcentaje del Total\'\nFROM autores\nWHERE estado_autor = \'activo\'\n    AND pais_afiliacion IS NOT NULL\nGROUP BY pais_afiliacion\nORDER BY COUNT(*) DESC;\n','Análisis de alcance geográfico, reportes para indexadores. Frecuencia recomendada: Semestral','sistema','2026-01-31 02:52:42'),(24,0,'AUT-INST-003: Instituciones sin ROR ID (GOBERNANZA)','Instituciones que necesitan estandarización con ROR','SELECT DISTINCT\n    afiliacion_actual AS \'Institución\',\n    pais_afiliacion AS \'País\',\n    COUNT(*) AS \'Autores Afectados\'\nFROM autores\nWHERE estado_autor = \'activo\'\n    AND afiliacion_actual IS NOT NULL\n    AND (ror_id IS NULL OR ror_id = \'\')\nGROUP BY afiliacion_actual, pais_afiliacion\nORDER BY COUNT(*) DESC;\n','Mejora de calidad de metadatos para indexadores (requisito SciELO/PubMed). Frecuencia recomendada: Mensual','sistema','2026-01-31 02:53:58'),(25,0,'AUT-DISC-001: Distribución por área UNESCO','Cobertura disciplinaria según clasificación UNESCO (códigos de 2 dígitos)','SELECT \n    SUBSTRING(clasificacion_unesco, 1, 2) AS \'Código UNESCO\',\n    COUNT(*) AS \'Autores\',\n    ROUND(COUNT(*) * 100.0 / (SELECT COUNT(*) FROM autores WHERE clasificacion_unesco IS NOT NULL AND estado_autor = \'activo\'), 2) AS \'Porcentaje\',\n    GROUP_CONCAT(DISTINCT area_investigacion SEPARATOR \'; \') AS \'Áreas Relacionadas\'\nFROM autores\nWHERE clasificacion_unesco IS NOT NULL\n    AND estado_autor = \'activo\'\nGROUP BY SUBSTRING(clasificacion_unesco, 1, 2)\nORDER BY COUNT(*) DESC;\n','Reportes institucionales, evaluación de alcance temático. Frecuencia recomendada: Semestral','sistema','2026-01-31 02:55:04'),(26,0,'AUT-DISC-002: Áreas de investigación más frecuentes','Top 15 áreas de investigación','SELECT \n    area_investigacion AS \'Área de Investigación\',\n    COUNT(*) AS \'Autores\',\n    ROUND(COUNT(*) * 100.0 / (SELECT COUNT(*) FROM autores WHERE estado_autor = \'activo\' AND area_investigacion IS NOT NULL), 2) AS \'Porcentaje\'\nFROM autores\nWHERE estado_autor = \'activo\'\n    AND area_investigacion IS NOT NULL\nGROUP BY area_investigacion\nORDER BY COUNT(*) DESC\nLIMIT 15;\n','Identificar fortalezas temáticas de la revista. Frecuencia recomendada: Trimestral','sistema','2026-01-31 02:56:05'),(27,0,'AUT-DISC-003: Cobertura por clasificación OECD','Distribución según campos OECD','SELECT \n    clasificacion_oecd AS \'Campo OECD\',\n    COUNT(*) AS \'Autores\',\n    GROUP_CONCAT(DISTINCT pais_afiliacion SEPARATOR \', \') AS \'Países Representados\'\nFROM autores\nWHERE clasificacion_oecd IS NOT NULL\n    AND estado_autor = \'activo\'\nGROUP BY clasificacion_oecd\nORDER BY COUNT(*) DESC;\n','Reportes para agencias de financiamiento. Frecuencia recomendada: Anual','sistema','2026-01-31 02:58:42'),(28,0,'AUT-ID-001: Autores sin ORCID (GOBERNANZA - CRÍTICO)','Lista de autores activos que necesitan ORCID','SELECT \n    apellidos_nombre AS \'Autor\',\n    email_principal AS \'Email\',\n    afiliacion_actual AS \'Institución\',\n    pais_afiliacion AS \'País\',\n    estado_autor AS \'Estado\'\nFROM autores\nWHERE (orcid IS NULL OR orcid = \'\')\n    AND estado_autor = \'activo\'\nORDER BY apellidos;\n','Cumplimiento de requisitos de indexadores (SciELO, PubMed, DOAJ). Frecuencia recomendada: Semanal','sistema','2026-01-31 02:59:43'),(29,0,'AUT-ID-002: Cobertura de identificadores persistentes','Porcentaje de autores con cada tipo de ID','SELECT \n    \'ORCID\' AS \'Tipo de Identificador\',\n    COUNT(CASE WHEN orcid IS NOT NULL AND orcid != \'\' THEN 1 END) AS \'Con ID\',\n    COUNT(*) AS \'Total Autores\',\n    ROUND(COUNT(CASE WHEN orcid IS NOT NULL AND orcid != \'\' THEN 1 END) * 100.0 / COUNT(*), 2) AS \'Porcentaje\'\nFROM autores\nWHERE estado_autor = \'activo\'\n\nUNION ALL\n\nSELECT \n    \'Scopus ID\',\n    COUNT(CASE WHEN scopus_id IS NOT NULL AND scopus_id != \'\' THEN 1 END),\n    COUNT(*),\n    ROUND(COUNT(CASE WHEN scopus_id IS NOT NULL AND scopus_id != \'\' THEN 1 END) * 100.0 / COUNT(*), 2)\nFROM autores\nWHERE estado_autor = \'activo\'\n\nUNION ALL\n\nSELECT \n    \'Researcher ID\',\n    COUNT(CASE WHEN researcher_id IS NOT NULL AND researcher_id != \'\' THEN 1 END),\n    COUNT(*),\n    ROUND(COUNT(CASE WHEN researcher_id IS NOT NULL AND researcher_id != \'\' THEN 1 END) * 100.0 / COUNT(*), 2)\nFROM autores\nWHERE estado_autor = \'activo\'\n\nUNION ALL\n\nSELECT \n    \'Google Scholar\',\n    COUNT(CASE WHEN google_scholar_id IS NOT NULL AND google_scholar_id != \'\' THEN 1 END),\n    COUNT(*),\n    ROUND(COUNT(CASE WHEN google_scholar_id IS NOT NULL AND google_scholar_id != \'\' THEN 1 END) * 100.0 / COUNT(*), 2)\nFROM autores\nWHERE estado_autor = \'activo\';\n','Dashboard de calidad de metadatos. Frecuencia recomendada: Mensual','sistema','2026-01-31 03:01:00'),(30,0,'AUT-CAL-001: Autores sin verificar (GOBERNANZA)','Registros pendientes de verificación','SELECT \n    apellidos_nombre AS \'Autor\',\n    fecha_creacion_registro AS \'Fecha de Creación\',\n    DATEDIFF(CURDATE(), fecha_creacion_registro) AS \'Días sin Verificar\',\n    fuente_registro AS \'Fuente\',\n    usuario_creacion AS \'Creado Por\',\n    email_principal AS \'Email\'\nFROM autores\nWHERE (verificado = 0 OR verificado IS NULL)\n    AND estado_autor = \'activo\'\nORDER BY fecha_creacion_registro DESC;\n','Control de calidad de la base de datos. Frecuencia recomendada: Semanal','sistema','2026-01-31 03:02:49'),(31,0,'AUT-CAL-002: Registros desactualizados (GOBERNANZA)','Autores con datos no actualizados en más de 1 año','SELECT \n    apellidos_nombre AS \'Autor\',\n    email_principal AS \'Email\',\n    afiliacion_actual AS \'Institución\',\n    fecha_actualizacion_registro AS \'Última Actualización\',\n    DATEDIFF(CURDATE(), fecha_actualizacion_registro) AS \'Días sin Actualizar\',\n    estado_autor AS \'Estado\'\nFROM autores\nWHERE fecha_actualizacion_registro < DATE_SUB(CURDATE(), INTERVAL 1 YEAR)\n    AND estado_autor = \'activo\'\nORDER BY fecha_actualizacion_registro ASC;\n','Planificación de actualización de base de datos. Frecuencia recomendada: Trimestral','sistema','2026-01-31 03:04:10'),(32,0,'AUT-CAL-003: Campos críticos incompletos (GOBERNANZA)','Autores con datos faltantes en campos esenciales','SELECT \n    apellidos_nombre AS \'Autor\',\n    CASE WHEN email_principal IS NULL OR email_principal = \'\' THEN \'SIN EMAIL\' ELSE \'\' END AS \'Email\',\n    CASE WHEN afiliacion_actual IS NULL OR afiliacion_actual = \'\' THEN \'SIN AFILIACIÓN\' ELSE \'\' END AS \'Afiliación\',\n    CASE WHEN pais_afiliacion IS NULL OR pais_afiliacion = \'\' THEN \'SIN PAÍS\' ELSE \'\' END AS \'País\',\n    CASE WHEN area_investigacion IS NULL OR area_investigacion = \'\' THEN \'SIN ÁREA\' ELSE \'\' END AS \'Área\',\n    CASE WHEN orcid IS NULL OR orcid = \'\' THEN \'SIN ORCID\' ELSE \'\' END AS \'ORCID\',\n    estado_autor AS \'Estado\'\nFROM autores\nWHERE estado_autor = \'activo\'\n    AND (\n        email_principal IS NULL OR email_principal = \'\'\n        OR afiliacion_actual IS NULL OR afiliacion_actual = \'\'\n        OR pais_afiliacion IS NULL OR pais_afiliacion = \'\'\n        OR area_investigacion IS NULL OR area_investigacion = \'\'\n        OR orcid IS NULL OR orcid = \'\'\n    )\nORDER BY apellidos;\n','Identificar registros que necesitan completarse. Frecuencia recomendada: Mensual','sistema','2026-01-31 03:06:44'),(33,0,'AUT-EST-001: Distribución por estado (GOBERNANZA)','Resumen de autores por estado','SELECT \n    estado_autor AS \'Estado\',\n    COUNT(*) AS \'Cantidad\',\n    ROUND(COUNT(*) * 100.0 / (SELECT COUNT(*) FROM autores), 2) AS \'Porcentaje\'\nFROM autores\nGROUP BY estado_autor\nORDER BY COUNT(*) DESC;\n','Dashboard general de la base de datos. Frecuencia recomendada: Mensual','sistema','2026-01-31 03:07:42'),(34,0,'AUT-EST-002: Autores inactivos recientes (GOBERNANZA)','Autores marcados como inactivos en los últimos 6 meses','SELECT \n    apellidos_nombre AS \'Autor\',\n    fecha_inactividad AS \'Fecha Inactividad\',\n    DATEDIFF(CURDATE(), fecha_inactividad) AS \'Días Inactivo\',\n    afiliacion_actual AS \'Última Institución Conocida\',\n    email_principal AS \'Email\'\nFROM autores\nWHERE estado_autor = \'inactivo\'\n    AND fecha_inactividad >= DATE_SUB(CURDATE(), INTERVAL 6 MONTH)\nORDER BY fecha_inactividad DESC;\n','Seguimiento de rotación, auditoría de cambios de estado. Frecuencia recomendada: Mensual','sistema','2026-01-31 03:08:46'),(35,0,'AUT-ROL-001: Autores con roles duales (GOBERNANZA)','Identificar posibles conflictos de interés (autor + editor)','SELECT \n    apellidos_nombre AS \'Nombre\',\n    tipo_autor AS \'Tipo de Autor\',\n    editor_revista AS \'Editor en Revistas\',\n    comite_editorial AS \'Comités Editoriales\',\n    afiliacion_actual AS \'Institución\'\nFROM autores\nWHERE estado_autor = \'activo\'\n    AND (\n        (editor_revista IS NOT NULL AND editor_revista != \'\')\n        OR (comite_editorial IS NOT NULL AND comite_editorial != \'\')\n    )\nORDER BY apellidos;\n','Transparencia editorial, control de conflictos. Frecuencia recomendada: Por cada número','sistema','2026-01-31 03:09:48'),(36,0,'AUT-ROL-002: Distribución de tipos de autor','Clasificación de autores por tipo','SELECT \n    tipo_autor AS \'Tipo de Autor\',\n    COUNT(*) AS \'Cantidad\',\n    ROUND(COUNT(*) * 100.0 / (SELECT COUNT(*) FROM autores WHERE estado_autor = \'activo\'), 2) AS \'Porcentaje\'\nFROM autores\nWHERE estado_autor = \'activo\'\n    AND tipo_autor IS NOT NULL\nGROUP BY tipo_autor\nORDER BY COUNT(*) DESC;\n','Análisis de composición de la comunidad. Frecuencia recomendada: Trimestral','sistema','2026-01-31 03:10:39'),(37,0,'AUT-FORM-001: Distribución de grados máximos','Autores por nivel de formación','SELECT \n    grado_maximo AS \'Grado Máximo\',\n    COUNT(*) AS \'Cantidad\',\n    ROUND(COUNT(*) * 100.0 / (SELECT COUNT(*) FROM autores WHERE estado_autor = \'activo\'), 2) AS \'Porcentaje\'\nFROM autores\nWHERE estado_autor = \'activo\'\n    AND grado_maximo IS NOT NULL\nGROUP BY grado_maximo\nORDER BY COUNT(*) DESC;\n','Perfil académico de la comunidad. Frecuencia recomendada: Anual','sistema','2026-01-31 03:11:36'),(38,0,'AUT-FORM-002: Top universidades de formación doctoral','Instituciones donde se doctoraron los autores','SELECT \n    universidad_doctorado AS \'Universidad\',\n    COUNT(*) AS \'Doctores\',\n    MIN(ano_doctorado) AS \'Año Más Antiguo\',\n    MAX(ano_doctorado) AS \'Año Más Reciente\'\nFROM autores\nWHERE universidad_doctorado IS NOT NULL\n    AND estado_autor = \'activo\'\nGROUP BY universidad_doctorado\nORDER BY COUNT(*) DESC\nLIMIT 15;\n','Redes académicas y prestigio. Frecuencia recomendada: Anual','sistema','2026-01-31 03:13:09'),(39,0,'ART-WF-001: Estado actual del pipeline editorial','Distribución de artículos por estado','SELECT \n    estado_articulo AS \'Estado\',\n    COUNT(*) AS \'Cantidad\',\n    ROUND(COUNT(*) * 100.0 / (SELECT COUNT(*) FROM articulos), 2) AS \'Porcentaje\',\n    ROUND(AVG(DATEDIFF(CURDATE(), fecha_creacion_registro)), 0) AS \'Días Promedio en Estado\'\nFROM articulos\nGROUP BY estado_articulo\nORDER BY \n    CASE estado_articulo\n        WHEN \'borrador\' THEN 1\n        WHEN \'en_revision\' THEN 2\n        WHEN \'aceptado\' THEN 3\n        WHEN \'publicado\' THEN 4\n        WHEN \'rechazado\' THEN 5\n        WHEN \'retractado\' THEN 6\n        ELSE 99\n    END;\n','Dashboard ejecutivo, detección de cuellos de botella. Frecuencia recomendada: Diaria','sistema','2026-01-31 03:14:20'),(40,0,'ART-WF-002: Artículos estancados en revisión (GOBERNANZA - CRÍTICO)','Manuscritos en revisión por más de 60 días','SELECT \n    a.id_articulo AS \'ID\',\n    a.titulo_articulo AS \'Título\',\n    a.fecha_recepcion AS \'Fecha Recepción\',\n    DATEDIFF(CURDATE(), a.fecha_recepcion) AS \'Días en Revisión\',\n    a.responsable_edicion AS \'Editor Responsable\',\n    COUNT(ar.id_revision) AS \'Revisores Asignados\',\n    SUM(CASE WHEN ar.decision IS NOT NULL THEN 1 ELSE 0 END) AS \'Revisiones Completadas\'\nFROM articulos a\nLEFT JOIN articulo_revisor ar ON a.id_articulo = ar.id_articulo\nWHERE a.estado_articulo = \'en_revision\'\n    AND a.fecha_recepcion < DATE_SUB(CURDATE(), INTERVAL 60 DAY)\nGROUP BY a.id_articulo\nORDER BY DATEDIFF(CURDATE(), a.fecha_recepcion) DESC;\n','Identificar retrasos, intervención editorial urgente. Frecuencia recomendada: Semanal','sistema','2026-01-31 03:19:48'),(41,0,'ART-WF-003: Borradores sin actividad reciente (GOBERNANZA)','Artículos en borrador sin actualización en 30 días','SELECT \n    id_articulo AS \'ID\',\n    titulo_articulo AS \'Título\',\n    responsable_edicion AS \'Responsable\',\n    fecha_creacion_registro AS \'Fecha Creación\',\n    fecha_actualizacion_registro AS \'Última Actualización\',\n    DATEDIFF(CURDATE(), fecha_actualizacion_registro) AS \'Días sin Actividad\'\nFROM articulos\nWHERE estado_articulo = \'borrador\'\n    AND fecha_actualizacion_registro < DATE_SUB(CURDATE(), INTERVAL 30 DAY)\nORDER BY fecha_actualizacion_registro ASC;\n','Limpieza de base de datos, seguimiento con responsables. Frecuencia recomendada: Mensual','sistema','2026-01-31 03:21:05'),(42,0,'ART-WF-004: Artículos aceptados pendientes de publicación (GOBERNANZA)','Manuscritos aceptados que aún no se publican','SELECT \n    id_articulo AS \'ID\',\n    titulo_articulo AS \'Título\',\n    fecha_aceptacion AS \'Fecha Aceptación\',\n    DATEDIFF(CURDATE(), fecha_aceptacion) AS \'Días desde Aceptación\',\n    tipo_articulo AS \'Tipo\',\n    responsable_edicion AS \'Editor Responsable\',\n    notas_internas AS \'Notas\'\nFROM articulos\nWHERE estado_articulo = \'aceptado\'\n    AND fecha_publicacion_online IS NULL\nORDER BY fecha_aceptacion ASC;\n','Planificación de números, control de backlog. Frecuencia recomendada: Semanal','sistema','2026-01-31 03:22:04'),(43,0,'ART-WF-005: Trazabilidad de cambios de estado (AUDITORÍA)','Artículos con cambios de estado en el último mes','SELECT \n    id_articulo AS \'ID\',\n    titulo_articulo AS \'Título\',\n    estado_articulo AS \'Estado Actual\',\n    fecha_actualizacion_registro AS \'Fecha Cambio\',\n    responsable_edicion AS \'Responsable\',\n    usuario_creacion AS \'Usuario que Modificó\'\nFROM articulos\nWHERE fecha_actualizacion_registro >= DATE_SUB(CURDATE(), INTERVAL 1 MONTH)\nORDER BY fecha_actualizacion_registro DESC;\n','Auditoría de workflow, registro de decisiones editoriales. Frecuencia recomendada: Mensual','sistema','2026-01-31 03:24:01'),(44,0,'ART-CAL-001: Artículos sin DOI asignado (CRÍTICO)','Artículos publicados sin DOI','SELECT \n    id_articulo AS \'ID\',\n    titulo_articulo AS \'Título\',\n    estado_articulo AS \'Estado\',\n    fecha_publicacion_online AS \'Fecha Publicación\',\n    responsable_edicion AS \'Editor Responsable\'\nFROM articulos\nWHERE estado_articulo IN (\'aceptado\', \'publicado\')\n    AND (doi IS NULL OR doi = \'\')\nORDER BY fecha_publicacion_online DESC;\n','Cumplimiento de estándares de identificación persistente. Frecuencia recomendada: Semanal','sistema','2026-01-31 03:25:31'),(45,0,'ART-CAL-002: Validación JATS pendiente (GOBERNANZA)','Artículos sin validación JATS completa','SELECT \n    id_articulo AS \'ID\',\n    titulo_articulo AS \'Título\',\n    estado_articulo AS \'Estado\',\n    validado_jats AS \'Validado JATS\',\n    errores_validacion AS \'Errores\',\n    responsable_edicion AS \'Responsable\'\nFROM articulos\nWHERE estado_articulo IN (\'aceptado\', \'publicado\')\n    AND (validado_jats = 0 OR validado_jats IS NULL)\nORDER BY fecha_aceptacion DESC;\n','Control de calidad técnica para indexadores. Frecuencia recomendada: Por cada número','sistema','2026-01-31 03:26:32'),(46,0,'ART-CAL-003: Completitud de metadatos (GOBERNANZA)','Artículos con baja completitud de metadatos (<80%)','SELECT \n    id_articulo AS \'ID\',\n    titulo_articulo AS \'Título\',\n    estado_articulo AS \'Estado\',\n    completitud_metadatos AS \'Completitud (%)\',\n    calidad_metadatos AS \'Calidad Score\',\n    responsable_edicion AS \'Responsable\'\nFROM articulos\nWHERE completitud_metadatos < 80\n    AND estado_articulo != \'rechazado\'\nORDER BY completitud_metadatos ASC;\n','Mejora de calidad antes de publicación. Frecuencia recomendada: Por cada número','sistema','2026-01-31 03:29:29'),(47,0,'ART-CAL-004: Artículos sin autor de correspondencia (CRÍTICO)','Manuscritos sin autor de correspondencia asignado','SELECT \n    a.id_articulo AS \'ID\',\n    a.titulo_articulo AS \'Título\',\n    a.estado_articulo AS \'Estado\',\n    a.responsable_edicion AS \'Editor Responsable\',\n    COUNT(aa.id_autor) AS \'Total Autores\'\nFROM articulos a\nLEFT JOIN articulo_autor aa ON a.id_articulo = aa.id_articulo\nWHERE a.autor_correspondencia IS NULL\n    AND a.estado_articulo IN (\'en_revision\', \'aceptado\', \'publicado\')\nGROUP BY a.id_articulo\nORDER BY a.fecha_aceptacion DESC;\n','Requisito obligatorio para publicación. Frecuencia recomendada: Semanal','sistema','2026-01-31 03:30:44'),(48,0,'ART-CAL-005: Errores de validación XML (GOBERNANZA)','Artículos con errores de validación XML/JATS','SELECT \n    id_articulo AS \'ID\',\n    titulo_articulo AS \'Título\',\n    errores_validacion AS \'Errores Detectados\',\n    validado_jats AS \'Validado\',\n    responsable_edicion AS \'Responsable\'\nFROM articulos\nWHERE errores_validacion IS NOT NULL\n    AND errores_validacion != \'\'\n    AND estado_articulo != \'rechazado\'\nORDER BY fecha_actualizacion_registro DESC;\n','Corrección técnica antes de envío a indexadores. Frecuencia recomendada: Por cada número','sistema','2026-01-31 03:31:52'),(49,0,'ART-STD-001: Cumplimiento de guías de reporte','Artículos por tipo de guía cumplida (ARRIVE, CONSORT, etc.)','SELECT \n    \'ARRIVE (Animales)\' AS \'Guía\',\n    SUM(cumple_arrive) AS \'Artículos Cumplen\',\n    COUNT(*) AS \'Total Aplicable\',\n    ROUND(SUM(cumple_arrive) * 100.0 / COUNT(*), 2) AS \'Porcentaje\'\nFROM articulos\nWHERE tipo_sujetos_investigacion IN (\'animales\', \'humanos_y_animales\')\n    AND estado_articulo = \'publicado\'\n\nUNION ALL\n\nSELECT \n    \'CONSORT (Ensayos Clínicos)\',\n    SUM(cumple_consort),\n    COUNT(*),\n    ROUND(SUM(cumple_consort) * 100.0 / COUNT(*), 2)\nFROM articulos\nWHERE tipo_sujetos_investigacion IN (\'humanos\', \'humanos_y_animales\')\n    AND estado_articulo = \'publicado\'\n\nUNION ALL\n\nSELECT \n    \'STROBE (Observacionales)\',\n    SUM(cumple_strobe),\n    COUNT(*),\n    ROUND(SUM(cumple_strobe) * 100.0 / COUNT(*), 2)\nFROM articulos\nWHERE tipo_sujetos_investigacion = \'humanos\'\n    AND estado_articulo = \'publicado\'\n\nUNION ALL\n\nSELECT \n    \'PRISMA (Revisiones)\',\n    SUM(cumple_prisma),\n    COUNT(*),\n    ROUND(SUM(cumple_prisma) * 100.0 / COUNT(*), 2)\nFROM articulos\nWHERE tipo_articulo LIKE \'%revision%\'\n    AND estado_articulo = \'publicado\';\n','Dashboard de transparencia metodológica. Frecuencia recomendada: Trimestral','sistema','2026-01-31 03:33:00'),(50,0,'ART-STD-002: Artículos con sujetos humanos sin aprobación ética (CRÍTICO)','Estudios con humanos sin aprobación de comité ético','SELECT \n    id_articulo AS \'ID\',\n    titulo_articulo AS \'Título\',\n    tipo_sujetos_investigacion AS \'Tipo Sujetos\',\n    aprobacion_comite_etica AS \'Tiene Aprobación\',\n    numero_aprobacion_etica AS \'Número Aprobación\',\n    consentimiento_informado AS \'Consentimiento\',\n    responsable_edicion AS \'Editor Responsable\'\nFROM articulos\nWHERE tipo_sujetos_investigacion IN (\'humanos\', \'humanos_y_animales\')\n    AND (aprobacion_comite_etica = 0 OR aprobacion_comite_etica IS NULL)\n    AND estado_articulo IN (\'en_revision\', \'aceptado\', \'publicado\')\nORDER BY fecha_recepcion DESC;\n','Control de cumplimiento ético obligatorio. Frecuencia recomendada: Semanal','sistema','2026-01-31 03:33:58'),(51,0,'ART-STD-003: Artículos con animales sin aprobación CICUAL (CRÍTICO)','Estudios con animales sin aprobación de comité de ética animal','SELECT \n    id_articulo AS \'ID\',\n    titulo_articulo AS \'Título\',\n    estudios_animales_especies AS \'Especies\',\n    numero_animales AS \'N Animales\',\n    aprobacion_comite_animal AS \'Tiene Aprobación\',\n    numero_aprobacion_animal AS \'Número Aprobación\',\n    protocolo_bienestar_animal AS \'Protocolo\',\n    responsable_edicion AS \'Editor Responsable\'\nFROM articulos\nWHERE tipo_sujetos_investigacion IN (\'animales\', \'humanos_y_animales\')\n    AND (aprobacion_comite_animal = 0 OR aprobacion_comite_animal IS NULL)\n    AND estado_articulo IN (\'en_revision\', \'aceptado\', \'publicado\')\nORDER BY fecha_recepcion DESC;\n','Control de cumplimiento normativo obligatorio. Frecuencia recomendada: Semanal','sistema','2026-01-31 03:34:59'),(52,0,'ART-STD-004: Ensayos clínicos sin registro (CRÍTICO)','Artículos de ensayos clínicos sin número de registro','SELECT \n    id_articulo AS \'ID\',\n    titulo_articulo AS \'Título\',\n    estudios_humanos_tipo AS \'Tipo Estudio\',\n    registro_ensayo_clinico AS \'Registro\',\n    aprobacion_comite_etica AS \'Aprobación Ética\',\n    responsable_edicion AS \'Editor Responsable\'\nFROM articulos\nWHERE estudios_humanos_tipo LIKE \'%ensayo%\'\n    AND (registro_ensayo_clinico IS NULL OR registro_ensayo_clinico = \'\')\n    AND estado_articulo IN (\'en_revision\', \'aceptado\', \'publicado\')\nORDER BY fecha_recepcion DESC;\n','Requisito obligatorio (Declaración de Helsinki). Frecuencia recomendada: Semanal','sistema','2026-01-31 03:35:53'),(53,0,'ART-PROD-001: Artículos por tipo','Distribución de artículos por tipo de publicación','SELECT \n    tipo_articulo AS \'Tipo de Artículo\',\n    COUNT(*) AS \'Cantidad\',\n    ROUND(COUNT(*) * 100.0 / (SELECT COUNT(*) FROM articulos WHERE estado_articulo = \'publicado\'), 2) AS \'Porcentaje\'\nFROM articulos\nWHERE estado_articulo = \'publicado\'\n    AND tipo_articulo IS NOT NULL\nGROUP BY tipo_articulo\nORDER BY COUNT(*) DESC;\n','Análisis de composición editorial. Frecuencia recomendada: Trimestral','sistema','2026-01-31 03:36:50'),(54,0,'ART-PROD-002: Productividad por editor responsable (GOBERNANZA)','Cantidad de artículos gestionados por cada editor','SELECT \n    responsable_edicion AS \'Editor\',\n    COUNT(*) AS \'Total Artículos\',\n    SUM(CASE WHEN estado_articulo = \'publicado\' THEN 1 ELSE 0 END) AS \'Publicados\',\n    SUM(CASE WHEN estado_articulo = \'en_revision\' THEN 1 ELSE 0 END) AS \'En Revisión\',\n    SUM(CASE WHEN estado_articulo = \'aceptado\' THEN 1 ELSE 0 END) AS \'Aceptados\',\n    SUM(CASE WHEN estado_articulo = \'rechazado\' THEN 1 ELSE 0 END) AS \'Rechazados\',\n    ROUND(AVG(DATEDIFF(fecha_aceptacion, fecha_recepcion)), 0) AS \'Días Prom. Decisión\'\nFROM articulos\nWHERE responsable_edicion IS NOT NULL\nGROUP BY responsable_edicion\nORDER BY COUNT(*) DESC;\n','Balance de carga editorial, evaluación de desempeño. Frecuencia recomendada: Trimestral','sistema','2026-01-31 03:39:40'),(55,0,'ART-PROD-003: Artículos publicados por año','Evolución temporal de la producción editorial','SELECT \n    ano_publicacion AS \'Año\',\n    COUNT(*) AS \'Artículos Publicados\',\n    AVG(numero_paginas) AS \'Páginas Promedio\',\n    SUM(numero_referencias) AS \'Referencias Totales\'\nFROM articulos\nWHERE estado_articulo = \'publicado\'\n    AND ano_publicacion IS NOT NULL\nGROUP BY ano_publicacion\nORDER BY ano_publicacion DESC;\n','Análisis de tendencias. Frecuencia recomendada: Anual','sistema','2026-01-31 03:40:55'),(56,0,'ART-PROD-004: Tasa de aceptación (GOBERNANZA)','Proporción de artículos aceptados vs rechazados','SELECT \n    YEAR(fecha_recepcion) AS \'Año\',\n    COUNT(*) AS \'Total Manuscritos\',\n    SUM(CASE WHEN estado_articulo = \'publicado\' THEN 1 ELSE 0 END) AS \'Publicados\',\n    SUM(CASE WHEN estado_articulo = \'rechazado\' THEN 1 ELSE 0 END) AS \'Rechazados\',\n    ROUND(SUM(CASE WHEN estado_articulo = \'publicado\' THEN 1 ELSE 0 END) * 100.0 / COUNT(*), 2) AS \'Tasa Aceptación (%)\'\nFROM articulos\nWHERE estado_articulo IN (\'publicado\', \'rechazado\')\n    AND fecha_recepcion IS NOT NULL\nGROUP BY YEAR(fecha_recepcion)\nORDER BY YEAR(fecha_recepcion) DESC;\n','Indicador de selectividad editorial. Frecuencia recomendada: Semestral','sistema','2026-01-31 03:41:57'),(57,0,'ART-MET-001: Artículos más vistos/descargados','Top 20 artículos por visualizaciones y descargas','SELECT \n    id_articulo AS \'ID\',\n    titulo_articulo AS \'Título\',\n    visualizaciones AS \'Vistas\',\n    descargas AS \'Descargas\',\n    (visualizaciones + descargas) AS \'Total Interacciones\',\n    fecha_publicacion_online AS \'Fecha Publicación\'\nFROM articulos\nWHERE estado_articulo = \'publicado\'\n    AND (visualizaciones > 0 OR descargas > 0)\nORDER BY (visualizaciones + descargas) DESC\nLIMIT 20;\n','Identificar contenido de alto impacto. Frecuencia recomendada: Mensual','sistema','2026-01-31 03:43:02'),(58,0,'ART-MET-002: Artículos con mayor impacto altmétrico','Artículos ordenados por Altmetric Score','SELECT \n    id_articulo AS \'ID\',\n    titulo_articulo AS \'Título\',\n    altmetric_score AS \'Altmetric Score\',\n    menciones_redes AS \'Menciones en Redes\',\n    fecha_publicacion_online AS \'Fecha Publicación\',\n    doi AS \'DOI\'\nFROM articulos\nWHERE estado_articulo = \'publicado\'\n    AND altmetric_score IS NOT NULL\nORDER BY altmetric_score DESC\nLIMIT 20;\n','Análisis de impacto en redes sociales y medios. Frecuencia recomendada: Trimestral','sistema','2026-01-31 03:43:56'),(59,0,'ART-MET-003: Distribución de citas por base de datos','Cobertura de citas en Scopus, WoS y Google Scholar','SELECT \n    \'Scopus\' AS \'Base de Datos\',\n    COUNT(CASE WHEN citas_scopus > 0 THEN 1 END) AS \'Artículos Citados\',\n    SUM(citas_scopus) AS \'Total Citas\',\n    ROUND(AVG(citas_scopus), 2) AS \'Promedio Citas\'\nFROM articulos\nWHERE estado_articulo = \'publicado\'\n\nUNION ALL\n\nSELECT \n    \'Web of Science\',\n    COUNT(CASE WHEN citas_wos > 0 THEN 1 END),\n    SUM(citas_wos),\n    ROUND(AVG(citas_wos), 2)\nFROM articulos\nWHERE estado_articulo = \'publicado\'\n\nUNION ALL\n\nSELECT \n    \'Google Scholar\',\n    COUNT(CASE WHEN citas_google_scholar > 0 THEN 1 END),\n    SUM(citas_google_scholar),\n    ROUND(AVG(citas_google_scholar), 2)\nFROM articulos\nWHERE estado_articulo = \'publicado\';\n','Análisis de indexación y visibilidad. Frecuencia recomendada: Semestral','sistema','2026-01-31 03:44:55'),(60,0,'ART-REV-001: Revisiones pendientes por revisor (CRÍTICO)','Revisiones asignadas sin completar','SELECT \n    aut.apellidos_nombre AS \'Revisor\',\n    aut.email_principal AS \'Email\',\n    art.id_articulo AS \'ID Artículo\',\n    art.titulo_articulo AS \'Título\',\n    ar.fecha_asignacion AS \'Fecha Asignación\',\n    DATEDIFF(CURDATE(), ar.fecha_asignacion) AS \'Días Asignado\',\n    ar.tipo_revision AS \'Tipo Revisión\',\n    ar.ronda_revision AS \'Ronda\'\nFROM articulo_revisor ar\nJOIN autores aut ON ar.id_autor = aut.id_autor\nJOIN articulos art ON ar.id_articulo = art.id_articulo\nWHERE ar.decision IS NULL\n    AND art.estado_articulo = \'en_revision\'\nORDER BY DATEDIFF(CURDATE(), ar.fecha_asignacion) DESC;\n','Seguimiento a revisores, detección de retrasos. Frecuencia recomendada: Semanal','sistema','2026-01-31 03:45:56'),(61,0,'ART-REV-002: Tiempo promedio de revisión por revisor (GOBERNANZA)','Performance de revisores (días promedio para completar)','SELECT \n    aut.apellidos_nombre AS \'Revisor\',\n    COUNT(ar.id_revision) AS \'Revisiones Completadas\',\n    ROUND(AVG(DATEDIFF(ar.fecha_revision, ar.fecha_asignacion)), 0) AS \'Días Promedio\',\n    MIN(DATEDIFF(ar.fecha_revision, ar.fecha_asignacion)) AS \'Más Rápida\',\n    MAX(DATEDIFF(ar.fecha_revision, ar.fecha_asignacion)) AS \'Más Lenta\'\nFROM articulo_revisor ar\nJOIN autores aut ON ar.id_autor = aut.id_autor\nWHERE ar.decision IS NOT NULL\n    AND ar.fecha_revision IS NOT NULL\nGROUP BY ar.id_autor\nHAVING COUNT(ar.id_revision) >= 3\nORDER BY AVG(DATEDIFF(ar.fecha_revision, ar.fecha_asignacion)) ASC;\n','Evaluación de revisores, asignación futura. Frecuencia recomendada: Trimestral','sistema','2026-01-31 03:46:52'),(62,0,'ART-REV-003: Distribución de decisiones de revisores','Tipos de decisión por revisor (aceptar, rechazar, cambios)','SELECT \n    aut.apellidos_nombre AS \'Revisor\',\n    COUNT(*) AS \'Total Revisiones\',\n    SUM(CASE WHEN ar.decision = \'aceptar\' THEN 1 ELSE 0 END) AS \'Aceptar\',\n    SUM(CASE WHEN ar.decision = \'rechazar\' THEN 1 ELSE 0 END) AS \'Rechazar\',\n    SUM(CASE WHEN ar.decision = \'cambios_mayores\' THEN 1 ELSE 0 END) AS \'Cambios Mayores\',\n    SUM(CASE WHEN ar.decision = \'cambios_menores\' THEN 1 ELSE 0 END) AS \'Cambios Menores\',\n    ROUND(SUM(CASE WHEN ar.decision = \'aceptar\' THEN 1 ELSE 0 END) * 100.0 / COUNT(*), 2) AS \'% Aceptación\'\nFROM articulo_revisor ar\nJOIN autores aut ON ar.id_autor = aut.id_autor\nWHERE ar.decision IS NOT NULL\nGROUP BY ar.id_autor\nHAVING COUNT(*) >= 5\nORDER BY COUNT(*) DESC;\n','Análisis de criterio editorial. Frecuencia recomendada: Semestral','sistema','2026-01-31 03:48:16'),(63,0,'ART-REV-004: Artículos con múltiples rondas de revisión (GOBERNANZA)','Manuscritos con más de 2 rondas de revisión','SELECT \n    a.id_articulo AS \'ID\',\n    a.titulo_articulo AS \'Título\',\n    MAX(ar.ronda_revision) AS \'Rondas Totales\',\n    a.fecha_recepcion AS \'Fecha Recepción\',\n    DATEDIFF(CURDATE(), a.fecha_recepcion) AS \'Días en Proceso\',\n    a.responsable_edicion AS \'Editor Responsable\'\nFROM articulos a\nJOIN articulo_revisor ar ON a.id_articulo = ar.id_articulo\nWHERE a.estado_articulo = \'en_revision\'\nGROUP BY a.id_articulo\nHAVING MAX(ar.ronda_revision) > 2\nORDER BY MAX(ar.ronda_revision) DESC;\n','Identificar casos problemáticos. Frecuencia recomendada: Mensual','sistema','2026-01-31 03:49:13'),(64,0,'ART-TIME-001: Tiempo promedio de decisión editorial','Días promedio entre recepción y aceptación/rechazo','SELECT \n    estado_articulo AS \'Decisión\',\n    COUNT(*) AS \'Cantidad\',\n    ROUND(AVG(DATEDIFF(fecha_aceptacion, fecha_recepcion)), 0) AS \'Días Promedio\',\n    MIN(DATEDIFF(fecha_aceptacion, fecha_recepcion)) AS \'Mínimo\',\n    MAX(DATEDIFF(fecha_aceptacion, fecha_recepcion)) AS \'Máximo\'\nFROM articulos\nWHERE fecha_recepcion IS NOT NULL\n    AND fecha_aceptacion IS NOT NULL\n    AND estado_articulo IN (\'aceptado\', \'publicado\')\nGROUP BY estado_articulo;\n','KPI de eficiencia editorial. Frecuencia recomendada: Trimestral','sistema','2026-01-31 03:50:07'),(65,0,'ART-TIME-002: Tiempo entre aceptación y publicación (GOBERNANZA)','Días entre fecha de aceptación y publicación online','SELECT \n    id_articulo AS \'ID\',\n    titulo_articulo AS \'Título\',\n    fecha_aceptacion AS \'Fecha Aceptación\',\n    fecha_publicacion_online AS \'Fecha Publicación\',\n    DATEDIFF(fecha_publicacion_online, fecha_aceptacion) AS \'Días hasta Publicación\',\n    responsable_edicion AS \'Editor Responsable\'\nFROM articulos\nWHERE estado_articulo = \'publicado\'\n    AND fecha_aceptacion IS NOT NULL\n    AND fecha_publicacion_online IS NOT NULL\nORDER BY DATEDIFF(fecha_publicacion_online, fecha_aceptacion) DESC;\n','Medición de backlog, eficiencia de producción. Frecuencia recomendada: Mensual','sistema','2026-01-31 03:51:37'),(66,0,'ART-TIME-003: Artículos publicados fuera de plazo objetivo (GOBERNANZA)','Artículos con más de 90 días entre aceptación y publicación','SELECT \n    id_articulo AS \'ID\',\n    titulo_articulo AS \'Título\',\n    fecha_aceptacion AS \'Fecha Aceptación\',\n    fecha_publicacion_online AS \'Fecha Publicación\',\n    DATEDIFF(fecha_publicacion_online, fecha_aceptacion) AS \'Días Retraso\',\n    responsable_edicion AS \'Editor Responsable\',\n    notas_internas AS \'Notas\'\nFROM articulos\nWHERE estado_articulo = \'publicado\'\n    AND fecha_aceptacion IS NOT NULL\n    AND fecha_publicacion_online IS NOT NULL\n    AND DATEDIFF(fecha_publicacion_online, fecha_aceptacion) > 90\nORDER BY DATEDIFF(fecha_publicacion_online, fecha_aceptacion) DESC;\n','Identificar cuellos de botella en producción. Frecuencia recomendada: Mensual','sistema','2026-01-31 03:53:05'),(67,0,'REV-META-001: Revistas con campos obligatorios incompletos (CRÍTICO)','Identificar revistas con metadatos críticos faltantes','SELECT \n    id_revista AS \'ID\',\n    titulo_revista AS \'Título\',\n    CASE WHEN issn_impreso IS NULL OR issn_impreso = \'\' THEN \'FALTA ISSN IMPRESO\' ELSE \'\' END AS \'ISSN Impreso\',\n    CASE WHEN issn_electronico IS NULL OR issn_electronico = \'\' THEN \'FALTA ISSN ELECTRÓNICO\' ELSE \'\' END AS \'ISSN Electrónico\',\n    CASE WHEN doi_prefix IS NULL OR doi_prefix = \'\' THEN \'FALTA DOI PREFIX\' ELSE \'\' END AS \'DOI Prefix\',\n    CASE WHEN url_revista IS NULL OR url_revista = \'\' THEN \'FALTA URL\' ELSE \'\' END AS \'URL\',\n    CASE WHEN licencia_defecto IS NULL OR licencia_defecto = \'\' THEN \'FALTA LICENCIA\' ELSE \'\' END AS \'Licencia\',\n    estado_publicacion AS \'Estado\'\nFROM revistas_md\nWHERE estado_publicacion = \'activa\'\n    AND (\n        issn_impreso IS NULL OR issn_impreso = \'\'\n        OR issn_electronico IS NULL OR issn_electronico = \'\'\n        OR doi_prefix IS NULL OR doi_prefix = \'\'\n        OR url_revista IS NULL OR url_revista = \'\'\n        OR licencia_defecto IS NULL OR licencia_defecto = \'\'\n    );\n','Control de calidad antes de publicación. Frecuencia recomendada: Mensual','sistema','2026-01-31 04:13:34'),(68,0,'REV-META-002: Validación de ISSN (GOBERNANZA)','Verificar formato correcto de ISSN (####-####)','SELECT \n    id_revista AS \'ID\',\n    titulo_revista AS \'Título\',\n    issn_impreso AS \'ISSN Impreso\',\n    issn_electronico AS \'ISSN Electrónico\',\n    CASE \n        WHEN issn_impreso NOT REGEXP \'^[0-9]{4}-[0-9]{3}[0-9X]$\' THEN \'FORMATO INVÁLIDO\'\n        ELSE \'OK\'\n    END AS \'Validación Impreso\',\n    CASE \n        WHEN issn_electronico NOT REGEXP \'^[0-9]{4}-[0-9]{3}[0-9X]$\' THEN \'FORMATO INVÁLIDO\'\n        ELSE \'OK\'\n    END AS \'Validación Electrónico\'\nFROM revistas_md\nWHERE estado_publicacion = \'activa\'\n    AND (\n        (issn_impreso IS NOT NULL AND issn_impreso != \'\')\n        OR (issn_electronico IS NOT NULL AND issn_electronico != \'\')\n    );\n','Control de calidad de identificadores. Frecuencia recomendada: Trimestral','sistema','2026-01-31 04:14:59'),(69,0,'REV-META-003: Revistas sin repositorio de preservación (GOBERNANZA)','Revistas sin estrategia de preservación digital','SELECT \n    id_revista AS \'ID\',\n    titulo_revista AS \'Título\',\n    repositorio_produccion_plataforma AS \'Plataforma Producción\',\n    repositorio_preservacion_plataforma AS \'Plataforma Preservación\',\n    sistema_gestion_contenidos AS \'CMS\',\n    estado_publicacion AS \'Estado\'\nFROM revistas_md\nWHERE estado_publicacion = \'activa\'\n    AND (repositorio_preservacion_url IS NULL OR repositorio_preservacion_url = \'\');\n','Cumplimiento de buenas prácticas. Frecuencia recomendada: Semestral','sistema','2026-01-31 04:15:50'),(70,0,'REV-STD-001: Revistas con acceso abierto sin licencia CC (CRÍTICO)','Revistas declaradas como acceso abierto sin licencia Creative Commons','SELECT \n    id_revista AS \'ID\',\n    titulo_revista AS \'Título\',\n    tipo_acceso AS \'Tipo Acceso\',\n    licencia_defecto AS \'Licencia\',\n    url_licencia AS \'URL Licencia\',\n    politica_acceso_abierto AS \'Política\'\nFROM revistas_md\nWHERE tipo_acceso IN (\'abierto\', \'mixto\')\n    AND (\n        licencia_defecto IS NULL \n        OR licencia_defecto = \'\'\n        OR licencia_defecto NOT LIKE \'%CC%\'\n    )\n    AND estado_publicacion = \'activa\';\n','Cumplimiento de políticas de acceso abierto. Frecuencia recomendada: Trimestral','sistema','2026-01-31 04:17:13'),(71,0,'REV-STD-002: Verificación de indexación (GOBERNANZA)','Estado de indexación en bases de datos principales','SELECT \n    titulo_revista AS \'Título\',\n    indexada_en AS \'Indexada en\',\n    categoria_scielo AS \'Categoría SciELO\',\n    categoria_latindex AS \'Categoría Latindex\',\n    cuartil_scimago AS \'Cuartil Scimago\',\n    factor_impacto AS \'Factor Impacto\',\n    estado_publicacion AS \'Estado\'\nFROM revistas_md\nWHERE estado_publicacion = \'activa\'\nORDER BY titulo_revista;\n','Seguimiento de indexación. Frecuencia recomendada: Semestral','sistema','2026-01-31 04:18:05'),(72,0,'REV-STD-003: Revistas sin OAI-PMH configurado (GOBERNANZA)','Revistas sin URL de OAI-PMH (requisito para SciELO/Redalyc)','SELECT \n    id_revista AS \'ID\',\n    titulo_revista AS \'Título\',\n    url_revista AS \'URL Revista\',\n    url_oai_pmh AS \'OAI-PMH\',\n    sistema_gestion_contenidos AS \'CMS\',\n    indexada_en AS \'Indexada en\'\nFROM revistas_md\nWHERE estado_publicacion = \'activa\'\n    AND (url_oai_pmh IS NULL OR url_oai_pmh = \'\');\n','Preparación para indexadores. Frecuencia recomendada: Trimestral','sistema','2026-01-31 04:19:41'),(73,0,'REV-EST-001: Distribución de revistas por estado','Resumen de revistas por estado de publicación','SELECT \n    estado_publicacion AS \'Estado\',\n    COUNT(*) AS \'Cantidad\',\n    GROUP_CONCAT(titulo_revista SEPARATOR \'; \') AS \'Títulos\'\nFROM revistas_md\nGROUP BY estado_publicacion;\n','Dashboard ejecutivo. Frecuencia recomendada: Mensual','sistema','2026-01-31 04:20:58'),(74,0,'REV-EST-002: Revistas suspendidas o finalizadas (AUDITORÍA)','Historial de revistas no activas','SELECT \n    titulo_revista AS \'Título\',\n    estado_publicacion AS \'Estado\',\n    ano_inicio AS \'Año Inicio\',\n    ano_fin AS \'Año Fin\',\n    fecha_actualizacion AS \'Última Actualización\',\n    notas_internas AS \'Notas\'\nFROM revistas_md\nWHERE estado_publicacion IN (\'suspendida\', \'finalizada\')\nORDER BY fecha_actualizacion DESC;\n','Auditoría histórica. Frecuencia recomendada: Anual','sistema','2026-01-31 04:22:00'),(75,0,'REV-AUD-001: Revistas sin actualización reciente (GOBERNANZA)','Revistas activas sin modificación de metadatos en >6 meses','SELECT \n    id_revista AS \'ID\',\n    titulo_revista AS \'Título\',\n    fecha_actualizacion AS \'Última Actualización\',\n    DATEDIFF(CURDATE(), fecha_actualizacion) AS \'Días sin Actualizar\',\n    usuario_creacion AS \'Usuario Responsable\',\n    estado_publicacion AS \'Estado\'\nFROM revistas_md\nWHERE estado_publicacion = \'activa\'\n    AND fecha_actualizacion < DATE_SUB(CURDATE(), INTERVAL 6 MONTH)\nORDER BY fecha_actualizacion ASC;\n','Control de mantenimiento. Frecuencia recomendada: Trimestral','sistema','2026-01-31 04:23:22'),(76,0,'REV-AUD-002: Cambios recientes en configuración (AUDITORÍA)','Revistas con modificaciones en el último mes','SELECT \n    titulo_revista AS \'Título\',\n    fecha_actualizacion AS \'Fecha Modificación\',\n    usuario_creacion AS \'Usuario\',\n    estado_publicacion AS \'Estado Actual\',\n    notas_internas AS \'Notas de Cambio\'\nFROM revistas_md\nWHERE fecha_actualizacion >= DATE_SUB(CURDATE(), INTERVAL 1 MONTH)\nORDER BY fecha_actualizacion DESC;\n','Trazabilidad de cambios. Frecuencia recomendada: Mensual','sistema','2026-01-31 04:24:17'),(77,0,'REV-AUD-003: Coherencia de tipo de acceso y licencia (GOBERNANZA)','Detectar inconsistencias entre tipo de acceso y licencia','SELECT \n    titulo_revista AS \'Título\',\n    tipo_acceso AS \'Tipo Acceso\',\n    licencia_defecto AS \'Licencia\',\n    periodo_embargo AS \'Período Embargo\',\n    CASE \n        WHEN tipo_acceso = \'abierto\' AND (licencia_defecto IS NULL OR licencia_defecto = \'\') THEN \'INCONSISTENTE: Acceso abierto sin licencia\'\n        WHEN tipo_acceso = \'suscripcion\' AND licencia_defecto LIKE \'%CC%\' THEN \'INCONSISTENTE: Suscripción con licencia CC\'\n        WHEN tipo_acceso = \'embargado\' AND (periodo_embargo IS NULL OR periodo_embargo = 0) THEN \'INCONSISTENTE: Embargo sin período\'\n        ELSE \'OK\'\n    END AS \'Validación\'\nFROM revistas_md\nWHERE estado_publicacion = \'activa\'\nHAVING Validación != \'OK\';\n','Control de calidad. Frecuencia recomendada: Trimestral','sistema','2026-01-31 04:25:35'),(78,0,'CROSS-001: Red de coautorías','Autores que colaboran frecuentemente','SELECT \n    a1.apellidos_nombre AS \'Autor 1\',\n    a2.apellidos_nombre AS \'Autor 2\',\n    COUNT(DISTINCT aa1.id_articulo) AS \'Artículos Conjuntos\',\n    GROUP_CONCAT(DISTINCT art.titulo_articulo SEPARATOR \'; \') AS \'Títulos\'\nFROM articulo_autor aa1\nJOIN articulo_autor aa2 ON aa1.id_articulo = aa2.id_articulo AND aa1.id_autor < aa2.id_autor\nJOIN autores a1 ON aa1.id_autor = a1.id_autor\nJOIN autores a2 ON aa2.id_autor = a2.id_autor\nJOIN articulos art ON aa1.id_articulo = art.id_articulo\nWHERE art.estado_articulo = \'publicado\'\nGROUP BY aa1.id_autor, aa2.id_autor\nHAVING COUNT(DISTINCT aa1.id_articulo) >= 3\nORDER BY COUNT(DISTINCT aa1.id_articulo) DESC;\n','Análisis de redes académicas. Frecuencia recomendada: Anual','sistema','2026-01-31 04:26:31'),(79,0,'CROSS-002: Autores más prolíficos por revista','Top autores por cantidad de publicaciones','SELECT \n    r.titulo_revista AS \'Revista\',\n    a.apellidos_nombre AS \'Autor\',\n    a.afiliacion_actual AS \'Institución\',\n    COUNT(DISTINCT art.id_articulo) AS \'Publicaciones\',\n    MIN(art.fecha_publicacion_online) AS \'Primera Publicación\',\n    MAX(art.fecha_publicacion_online) AS \'Última Publicación\'\nFROM articulo_autor aa\nJOIN autores a ON aa.id_autor = a.id_autor\nJOIN articulos art ON aa.id_articulo = art.id_articulo\nJOIN revistas_md r ON art.id_revista = r.id_revista\nWHERE art.estado_articulo = \'publicado\'\nGROUP BY r.id_revista, a.id_autor\nHAVING COUNT(DISTINCT art.id_articulo) >= 2\nORDER BY r.titulo_revista, COUNT(DISTINCT art.id_articulo) DESC;\n','Identificar colaboradores clave. Frecuencia recomendada: Anual','sistema','2026-01-31 04:28:02'),(80,0,'CROSS-003: Colaboración internacional','Artículos con autores de múltiples países','SELECT \n    art.id_articulo AS \'ID\',\n    art.titulo_articulo AS \'Título\',\n    COUNT(DISTINCT a.pais_afiliacion) AS \'Países Diferentes\',\n    GROUP_CONCAT(DISTINCT a.pais_afiliacion SEPARATOR \', \') AS \'Países Participantes\',\n    art.fecha_publicacion_online AS \'Fecha Publicación\'\nFROM articulos art\nJOIN articulo_autor aa ON art.id_articulo = aa.id_articulo\nJOIN autores a ON aa.id_autor = a.id_autor\nWHERE art.estado_articulo = \'publicado\'\n    AND a.pais_afiliacion IS NOT NULL\nGROUP BY art.id_articulo\nHAVING COUNT(DISTINCT a.pais_afiliacion) >= 3\nORDER BY COUNT(DISTINCT a.pais_afiliacion) DESC;\n','Análisis de internacionalización. Frecuencia recomendada: Anual','sistema','2026-01-31 04:28:50'),(81,0,'CROSS-004: Dashboard ejecutivo completo','Resumen integral de métricas clave','SELECT \n    \'Autores Activos\' AS \'Métrica\',\n    COUNT(*) AS \'Valor\'\nFROM autores\nWHERE estado_autor = \'activo\'\n\nUNION ALL\n\nSELECT \n    \'Revisores Disponibles\',\n    COUNT(*)\nFROM autores\nWHERE disponible_revision = 1 AND estado_autor = \'activo\'\n\nUNION ALL\n\nSELECT \n    \'Artículos en Revisión\',\n    COUNT(*)\nFROM articulos\nWHERE estado_articulo = \'en_revision\'\n\nUNION ALL\n\nSELECT \n    \'Artículos Publicados (Año Actual)\',\n    COUNT(*)\nFROM articulos\nWHERE estado_articulo = \'publicado\' AND YEAR(fecha_publicacion_online) = YEAR(CURDATE())\n\nUNION ALL\n\nSELECT \n    \'Revistas Activas\',\n    COUNT(*)\nFROM revistas_md\nWHERE estado_publicacion = \'activa\'\n\nUNION ALL\n\nSELECT \n    \'Artículos sin ORCID (CRÍTICO)\',\n    COUNT(DISTINCT aa.id_articulo)\nFROM articulo_autor aa\nJOIN autores a ON aa.id_autor = a.id_autor\nJOIN articulos art ON aa.id_articulo = art.id_articulo\nWHERE (a.orcid IS NULL OR a.orcid = \'\')\n    AND art.estado_articulo IN (\'aceptado\', \'publicado\')\n\nUNION ALL\n\nSELECT \n    \'Artículos sin DOI (CRÍTICO)\',\n    COUNT(*)\nFROM articulos\nWHERE estado_articulo IN (\'aceptado\', \'publicado\')\n    AND (doi IS NULL OR doi = \'\');\n','Reporte ejecutivo mensual. Frecuencia recomendada: Mensual','sistema','2026-01-31 04:30:10'),(82,0,'CROSS-005: Tiempo promedio de proceso por tipo de artículo (GOBERNANZA)','Eficiencia editorial segmentada','SELECT \n    tipo_articulo AS \'Tipo de Artículo\',\n    COUNT(*) AS \'Cantidad\',\n    ROUND(AVG(DATEDIFF(fecha_aceptacion, fecha_recepcion)), 0) AS \'Días Promedio Decisión\',\n    ROUND(AVG(DATEDIFF(fecha_publicacion_online, fecha_aceptacion)), 0) AS \'Días Promedio Publicación\',\n    ROUND(AVG(DATEDIFF(fecha_publicacion_online, fecha_recepcion)), 0) AS \'Días Totales\'\nFROM articulos\nWHERE estado_articulo = \'publicado\'\n    AND fecha_recepcion IS NOT NULL\n    AND fecha_aceptacion IS NOT NULL\n    AND fecha_publicacion_online IS NOT NULL\n    AND tipo_articulo IS NOT NULL\nGROUP BY tipo_articulo\nORDER BY COUNT(*) DESC;\n','Identificar tipos de artículo que requieren más tiempo. Frecuencia recomendada: Trimestral','sistema','2026-01-31 04:31:54'),(83,0,'CROSS-006: Autores sin artículos publicados (GOBERNANZA)','Autores registrados sin publicaciones en el sistema','SELECT \n    a.apellidos_nombre AS \'Autor\',\n    a.email_principal AS \'Email\',\n    a.afiliacion_actual AS \'Institución\',\n    a.estado_autor AS \'Estado\',\n    a.fecha_creacion_registro AS \'Fecha Creación\',\n    DATEDIFF(CURDATE(), a.fecha_creacion_registro) AS \'Días en Sistema\'\nFROM autores a\nLEFT JOIN articulo_autor aa ON a.id_autor = aa.id_autor\nLEFT JOIN articulos art ON aa.id_articulo = art.id_articulo AND art.estado_articulo = \'publicado\'\nWHERE art.id_articulo IS NULL\n    AND a.estado_autor = \'activo\'\nORDER BY a.fecha_creacion_registro DESC;\n','Limpieza de base de datos. Frecuencia recomendada: Anual','sistema','2026-01-31 04:33:03'),(84,0,'BIB-001: Distribución por tipo de entrada','Distribución de referencias por tipo de entrada','SELECT \n    tipo_de_entrada AS \'Tipo de Entrada\',\n    COUNT(*) AS \'Cantidad\',\n    ROUND(COUNT(*) * 100.0 / (SELECT COUNT(*) FROM bibtex), 2) AS \'Porcentaje\'\nFROM bibtex\nGROUP BY tipo_de_entrada\nORDER BY COUNT(*) DESC;\n','Identificar tipos de fuentes más citadas (artículos, libros, conferencias, etc.)','sistema','2026-01-31 04:35:48'),(85,0,'BIB-002: Distribución temporal de referencias','Distribución temporal de referencias','SELECT \r\n    COALESCE(SUBSTRING(date, 1, 4), year) AS \'Año\',\r\n    COUNT(*) AS \'Referencias\',\r\n    tipo_de_entrada AS \'Tipo\'\r\nFROM bibtex\r\nGROUP BY COALESCE(SUBSTRING(date, 1, 4), year), tipo_de_entrada\r\nORDER BY COUNT(*) DESC;\r\n','Actualidad de las referencias citadas','sistema','2026-01-31 04:43:10'),(86,0,'BIB-003: Idioma de las referencias','Idioma de las referencias','SELECT \n    COALESCE(hyphenation, language) AS \'Idioma\',\n    COUNT(*) AS \'Referencias\',\n    ROUND(COUNT(*) * 100.0 / (SELECT COUNT(*) FROM bibtex WHERE hyphenation IS NOT NULL OR language IS NOT NULL), 2) AS \'Porcentaje\'\nFROM bibtex\nWHERE hyphenation IS NOT NULL OR language IS NOT NULL\nGROUP BY COALESCE(hyphenation, language)\nORDER BY COUNT(*) DESC;\n','Diversidad lingüística de fuentes','sistema','2026-01-31 05:06:38'),(87,0,'BIB-004: Revistas más citadas','Revistas más citadas','SELECT \n    journal_title AS \'Revista\',\n    COUNT(*) AS \'Veces Citada\',\n    COUNT(DISTINCT id_articulo) AS \'Artículos que la Citan\'\nFROM bibtex\nWHERE journal_title IS NOT NULL\nGROUP BY journal_title\nORDER BY COUNT(*) DESC\nLIMIT 10;\n','Identificar revistas de referencia en la disciplina','sistema','2026-01-31 05:20:20'),(88,0,'BIB-005: Editoriales más citadas','Editoriales más citadas','SELECT \n    publisher AS \'Editorial\',\n    COUNT(*) AS \'Veces Citada\',\n    GROUP_CONCAT(DISTINCT location SEPARATOR \'; \') AS \'Ubicaciones\'\nFROM bibtex\nWHERE publisher IS NOT NULL\nGROUP BY publisher\nORDER BY COUNT(*) DESC\nLIMIT 10;\n','Prestigio de editoriales en el campo','sistema','2026-01-31 05:23:03'),(89,0,'BIB-006: Autores más citados','Autores más citados','SELECT \r\n    author AS \'Autor\',\r\n    COUNT(*) AS \'Veces Citado\',\r\n    COUNT(DISTINCT id_articulo) AS \'Artículos que lo Citan\',\r\n    GROUP_CONCAT(DISTINCT COALESCE(SUBSTRING(date, 1, 4), year) ORDER BY COALESCE(SUBSTRING(date, 1, 4), year) DESC SEPARATOR \', \') AS \'Años\'\r\nFROM bibtex\r\nWHERE author IS NOT NULL\r\nGROUP BY author\r\nORDER BY COUNT(*) DESC\r\nLIMIT 20;\r\n','Identificar autores influyentes en la disciplina','sistema','2026-01-31 05:25:11'),(90,0,'BIB-CAL-001: Referencias sin DOI','Referencias sin DOI (control de calidad)','SELECT \n    id_articulo AS \'ID Artículo\',\n    tipo_de_entrada AS \'Tipo\',\n    author AS \'Autor\',\n    title AS \'Título\',\n    COALESCE(SUBSTRING(date, 1, 4), year) AS \'Año\',\n    COALESCE(journal_title, book_title, event_title) AS \'Publicado en\'\nFROM bibtex\nWHERE (doi IS NULL OR doi = \'\')\n    AND tipo_de_entrada IN (\'article\', \'inproceedings\', \'incollection\', \'inbook\')\n    AND COALESCE(SUBSTRING(date, 1, 4), year) >= \'2010\'\nORDER BY CAST(COALESCE(SUBSTRING(date, 1, 4), year) AS UNSIGNED) DESC;\n','Identificar referencias modernas sin DOI (pérdida de rastreabilidad)','sistema','2026-01-31 05:36:40'),(92,0,'BIB-CAL-002: Referencias sin año','Referencias sin año','SELECT \n    id AS \'ID Referencia\',\n    id_articulo AS \'ID Artículo\',\n    tipo_de_entrada AS \'Tipo\',\n    author AS \'Autor\',\n    title AS \'Título\',\n    publisher AS \'Editorial/Revista\'\nFROM bibtex\nWHERE COALESCE(SUBSTRING(date, 1, 4), year, \'\') = \'\'\nORDER BY id_articulo;\n','Control de calidad bibliográfica','sistema','2026-01-31 16:20:26'),(93,0,'BIB-CAL-003: Referencias sin autor ni editor','Referencias sin autor ni editor','SELECT \n    id AS \'ID Referencia\',\n    id_articulo AS \'ID Artículo\',\n    tipo_de_entrada AS \'Tipo\',\n    title AS \'Título\',\n    COALESCE(SUBSTRING(date, 1, 4), year) AS \'Año\'\nFROM bibtex\nWHERE (author IS NULL OR author = \'\')\n    AND (editor IS NULL OR editor = \'\')\nORDER BY id_articulo;\n','Identificar referencias incompletas','sistema','2026-01-31 16:31:01'),(94,0,'BIB-ART-001: Cantidad de referencias por artículo','Cantidad de referencias por artículo','SELECT \n    a.id_articulo AS \'ID\',\n    a.titulo_articulo AS \'Título\',\n    COUNT(b.id) AS \'Referencias\',\n    a.tipo_articulo AS \'Tipo\',\n    a.estado_articulo AS \'Estado\'\nFROM articulos a\nLEFT JOIN bibtex b ON a.id_articulo = b.id_articulo\nGROUP BY a.id_articulo\nORDER BY COUNT(b.id) DESC;\n','Identificar artículos con bibliografía extensa o insuficiente','sistema','2026-01-31 16:33:45'),(95,0,'BIB-ART-002: Antigüedad promedio de referencias por artículo','Antigüedad promedio de referencias por artículo','SELECT \n    a.id_articulo AS \'ID\',\n    a.titulo_articulo AS \'Título\',\n    COUNT(b.id) AS \'Total Referencias\',\n    ROUND(AVG(CAST(a.ano_publicacion AS SIGNED) - CAST(b.anio_normalizado AS SIGNED)), 1) AS \'Antigüedad Promedio\',\n    MIN(b.anio_normalizado) AS \'Ref. Más Antigua\',\n    MAX(b.anio_normalizado) AS \'Ref. Más Reciente\'\nFROM articulos a\nJOIN (\n    SELECT \n        id,\n        id_articulo,\n        COALESCE(SUBSTRING(date, 1, 4), year) AS anio_normalizado\n    FROM bibtex\n    WHERE (year REGEXP \'^[0-9]{4}$\') OR (date REGEXP \'^[0-9]{4}\')\n) b ON a.id_articulo = b.id_articulo\nWHERE a.ano_publicacion IS NOT NULL\nGROUP BY a.id_articulo\nORDER BY AVG(CAST(a.ano_publicacion AS SIGNED) - CAST(b.anio_normalizado AS SIGNED)) DESC;\n','Evaluar actualidad bibliográfica','sistema','2026-01-31 16:37:30'),(96,0,'BIB-GEO-001: Ubicación de publicación de referencias','Ubicación de publicación de referencias','SELECT \n    location AS \'Ubicación\',\n    COUNT(*) AS \'Referencias\',\n    GROUP_CONCAT(DISTINCT publisher SEPARATOR \'; \') AS \'Editoriales\'\nFROM bibtex\nWHERE location IS NOT NULL\nGROUP BY location\nORDER BY COUNT(*) DESC\nLIMIT 20;\n','Identificar centros de producción académica citados','sistema','2026-01-31 16:40:27');
