/*!40000 ALTER TABLE `manual_ayudas` DISABLE KEYS */;
INSERT INTO `manual_ayudas` VALUES (50,'sponsors','sponsors','es','<!-- ESPAÑOL -->\n<h3>¿Qué es un sponsor?</h3>\n<p>Un sponsor (patrocinador o financiador) es la organización o institución que proporciona apoyo financiero o recursos para la realización de la investigación que se reporta en el artículo científico.</p>\n\n<h4>Tipos de sponsors comunes</h4>\n<p>Los sponsors pueden incluir diferentes tipos de entidades:</p>\n<ul>\n<li><strong>Agencias gubernamentales</strong>: Organismos estatales que financian investigación (ej: CONICET, CNPq, CONACYT)</li>\n<li><strong>Fundaciones privadas</strong>: Organizaciones sin fines de lucro dedicadas al apoyo científico</li>\n<li><strong>Empresas</strong>: Compañías privadas que financian investigación relacionada con sus intereses</li>\n<li><strong>Instituciones académicas</strong>: Universidades o centros de investigación que proveen fondos internos</li>\n<li><strong>Organismos internacionales</strong>: Entidades multilaterales (ej: OMS, UNESCO)</li>\n</ul>\n\n<h4>¿Cómo registrar el sponsor?</h4>\n<p>Ingrese el nombre oficial completo de la organización patrocinadora. Si hay múltiples sponsors, liste cada uno en una línea separada o separados por punto y coma.</p>\n<p><strong>Ejemplo correcto</strong>:</p>\n<pre>Consejo Nacional de Investigaciones Científicas y Técnicas (CONICET)</pre>\n\n<h4>Información complementaria</h4>\n<p>El registro del sponsor es importante para:</p>\n<ul>\n<li>Cumplir con requisitos de transparencia en la investigación</li>\n<li>Facilitar la identificación de fuentes de financiamiento</li>\n<li>Permitir análisis bibliométricos sobre patrones de financiamiento</li>\n<li>Satisfacer requisitos de indexación en bases de datos internacionales (PubMed, Scopus, Web of Science)</li>\n</ul>\n\n<h4>Relación con otros campos</h4>\n<p>Este campo se complementa con:</p>\n<ul>\n<li><strong>Award ID</strong>: Número de identificación del proyecto o beca</li>\n<li><strong>Funding Statement</strong>: Declaración completa de financiamiento</li>\n<li><strong>Conflict of Interest</strong>: Declaración de conflictos de interés relacionados con el financiamiento</li>\n</ul>\n','elisa','2026-01-08 23:20:09','elisa','2026-01-08 23:20:09'),(51,'sponsors','sponsors','pt','<!-- PORTUGUÉS -->\n<h3>O que é um sponsor?</h3>\n<p>Um sponsor (patrocinador ou financiador) é a organização ou instituição que fornece apoio financeiro ou recursos para a realização da pesquisa relatada no artigo científico.</p>\n\n<h4>Tipos comuns de sponsors</h4>\n<p>Os sponsors podem incluir diferentes tipos de entidades:</p>\n<ul>\n<li><strong>Agências governamentais</strong>: Órgãos estatais que financiam pesquisa (ex: CONICET, CNPq, CONACYT)</li>\n<li><strong>Fundações privadas</strong>: Organizações sem fins lucrativos dedicadas ao apoio científico</li>\n<li><strong>Empresas</strong>: Companhias privadas que financiam pesquisa relacionada aos seus interesses</li>\n<li><strong>Instituições acadêmicas</strong>: Universidades ou centros de pesquisa que fornecem fundos internos</li>\n<li><strong>Organismos internacionais</strong>: Entidades multilaterais (ex: OMS, UNESCO)</li>\n</ul>\n\n<h4>Como registrar o sponsor?</h4>\n<p>Insira o nome oficial completo da organização patrocinadora. Se houver múltiplos sponsors, liste cada um em uma linha separada ou separados por ponto e vírgula.</p>\n<p><strong>Exemplo correto</strong>:</p>\n<pre>Consejo Nacional de Investigaciones Científicas y Técnicas (CONICET)</pre>\n\n<h4>Informação complementar</h4>\n<p>O registro do sponsor é importante para:</p>\n<ul>\n<li>Cumprir com requisitos de transparência na pesquisa</li>\n<li>Facilitar a identificação de fontes de financiamento</li>\n<li>Permitir análises bibliométricas sobre padrões de financiamento</li>\n<li>Satisfazer requisitos de indexação em bases de dados internacionais (PubMed, Scopus, Web of Science)</li>\n</ul>\n\n<h4>Relação com outros campos</h4>\n<p>Este campo se complementa com:</p>\n<ul>\n<li><strong>Award ID</strong>: Número de identificação do projeto ou bolsa</li>\n<li><strong>Funding Statement</strong>: Declaração completa de financiamento</li>\n<li><strong>Conflict of Interest</strong>: Declaração de conflitos de interesse relacionados ao financiamento</li>\n</ul>\n','elisa','2026-01-08 23:20:09','elisa','2026-01-08 23:20:09'),(52,'sponsors','sponsors','en','<!-- INGLÉS -->\n<h3>What is a sponsor?</h3>\n<p>A sponsor (funder or funding organization) is the organization or institution that provides financial support or resources for conducting the research reported in the scientific article.</p>\n\n<h4>Common types of sponsors</h4>\n<p>Sponsors may include different types of entities:</p>\n<ul>\n<li><strong>Government agencies</strong>: State organizations that fund research (e.g., CONICET, CNPq, CONACYT)</li>\n<li><strong>Private foundations</strong>: Non-profit organizations dedicated to scientific support</li>\n<li><strong>Companies</strong>: Private corporations funding research related to their interests</li>\n<li><strong>Academic institutions</strong>: Universities or research centers providing internal funds</li>\n<li><strong>International organizations</strong>: Multilateral entities (e.g., WHO, UNESCO)</li>\n</ul>\n\n<h4>How to register the sponsor?</h4>\n<p>Enter the full official name of the sponsoring organization. If there are multiple sponsors, list each one on a separate line or separated by semicolons.</p>\n<p><strong>Correct example</strong>:</p>\n<pre>Consejo Nacional de Investigaciones Científicas y Técnicas (CONICET)</pre>\n\n<h4>Additional information</h4>\n<p>Recording the sponsor is important to:</p>\n<ul>\n<li>Comply with research transparency requirements</li>\n<li>Facilitate identification of funding sources</li>\n<li>Enable bibliometric analyses of funding patterns</li>\n<li>Meet indexing requirements in international databases (PubMed, Scopus, Web of Science)</li>\n</ul>\n\n<h4>Relationship with other fields</h4>\n<p>This field complements:</p>\n<ul>\n<li><strong>Award ID</strong>: Project or grant identification number</li>\n<li><strong>Funding Statement</strong>: Complete funding declaration</li>\n<li><strong>Conflict of Interest</strong>: Declaration of conflicts of interest related to funding</li>\n</ul>\n','elisa','2026-01-08 23:20:09','elisa','2026-01-08 23:20:09'),(53,'sponsors','sponsors','it','<!-- ITALIANO -->\n<h3>Cos\'è uno sponsor?</h3>\n<p>Uno sponsor (finanziatore o ente finanziatore) è l\'organizzazione o istituzione che fornisce supporto finanziario o risorse per la realizzazione della ricerca presentata nell\'articolo scientifico.</p>\n\n<h4>Tipi comuni di sponsor</h4>\n<p>Gli sponsor possono includere diversi tipi di entità:</p>\n<ul>\n<li><strong>Agenzie governative</strong>: Organismi statali che finanziano la ricerca (es: CONICET, CNPq, CONACYT)</li>\n<li><strong>Fondazioni private</strong>: Organizzazioni senza scopo di lucro dedicate al sostegno scientifico</li>\n<li><strong>Aziende</strong>: Società private che finanziano ricerche correlate ai loro interessi</li>\n<li><strong>Istituzioni accademiche</strong>: Università o centri di ricerca che forniscono fondi interni</li>\n<li><strong>Organismi internazionali</strong>: Entità multilaterali (es: OMS, UNESCO)</li>\n</ul>\n\n<h4>Come registrare lo sponsor?</h4>\n<p>Inserire il nome ufficiale completo dell\'organizzazione sponsor. Se ci sono più sponsor, elencare ciascuno su una riga separata o separati da punto e virgola.</p>\n<p><strong>Esempio corretto</strong>:</p>\n<pre>Consejo Nacional de Investigaciones Científicas y Técnicas (CONICET)</pre>\n\n<h4>Informazioni complementari</h4>\n<p>La registrazione dello sponsor è importante per:</p>\n<ul>\n<li>Rispettare i requisiti di trasparenza nella ricerca</li>\n<li>Facilitare l\'identificazione delle fonti di finanziamento</li>\n<li>Consentire analisi bibliometriche sui modelli di finanziamento</li>\n<li>Soddisfare i requisiti di indicizzazione nelle banche dati internazionali (PubMed, Scopus, Web of Science)</li>\n</ul>\n\n<h4>Relazione con altri campi</h4>\n<p>Questo campo si integra con:</p>\n<ul>\n<li><strong>Award ID</strong>: Numero di identificazione del progetto o della borsa</li>\n<li><strong>Funding Statement</strong>: Dichiarazione completa di finanziamento</li>\n<li><strong>Conflict of Interest</strong>: Dichiarazione di conflitti di interesse relativi al finanziamento</li>\n</ul>','elisa','2026-01-08 23:20:09','elisa','2026-01-08 23:20:09'),(54,'sponsors','sponsors','fr','<!-- FRANCÉS -->\n<h3>Qu\'est-ce qu\'un sponsor?</h3>\n<p>Un sponsor (commanditaire ou organisme de financement) est l\'organisation ou l\'institution qui fournit un soutien financier ou des ressources pour la réalisation de la recherche présentée dans l\'article scientifique.</p>\n\n<h4>Types courants de sponsors</h4>\n<p>Les sponsors peuvent inclure différents types d\'entités:</p>\n<ul>\n<li><strong>Agences gouvernementales</strong>: Organismes étatiques qui financent la recherche (ex: CONICET, CNPq, CONACYT)</li>\n<li><strong>Fondations privées</strong>: Organisations à but non lucratif dédiées au soutien scientifique</li>\n<li><strong>Entreprises</strong>: Sociétés privées qui financent des recherches liées à leurs intérêts</li>\n<li><strong>Institutions académiques</strong>: Universités ou centres de recherche fournissant des fonds internes</li>\n<li><strong>Organismes internationaux</strong>: Entités multilatérales (ex: OMS, UNESCO)</li>\n</ul>\n\n<h4>Comment enregistrer le sponsor?</h4>\n<p>Saisissez le nom officiel complet de l\'organisation sponsor. S\'il y a plusieurs sponsors, listez chacun sur une ligne séparée ou séparés par des points-virgules.</p>\n<p><strong>Exemple correct</strong>:</p>\n<pre>Consejo Nacional de Investigaciones Científicas y Técnicas (CONICET)</pre>\n\n<h4>Information complémentaire</h4>\n<p>L\'enregistrement du sponsor est important pour:</p>\n<ul>\n<li>Respecter les exigences de transparence dans la recherche</li>\n<li>Faciliter l\'identification des sources de financement</li>\n<li>Permettre des analyses bibliométriques sur les modèles de financement</li>\n<li>Satisfaire les exigences d\'indexation dans les bases de données internationales (PubMed, Scopus, Web of Science)</li>\n</ul>\n\n<h4>Relation avec d\'autres champs</h4>\n<p>Ce champ complète:</p>\n<ul>\n<li><strong>Award ID</strong>: Numéro d\'identification du projet ou de la bourse</li>\n<li><strong>Funding Statement</strong>: Déclaration complète de financement</li>\n<li><strong>Conflict of Interest</strong>: Déclaration de conflits d\'intérêts liés au financement</li>\n</ul>\n','elisa','2026-01-08 23:20:09','elisa','2026-01-08 23:20:09'),(55,'sponsors','sponsors','de','<!-- ALEMÁN -->\n<h3>Was ist ein Sponsor?</h3>\n<p>Ein Sponsor (Förderer oder Finanzierungsorganisation) ist die Organisation oder Institution, die finanzielle Unterstützung oder Ressourcen für die Durchführung der im wissenschaftlichen Artikel berichteten Forschung bereitstellt.</p>\n\n<h4>Häufige Arten von Sponsoren</h4>\n<p>Sponsoren können verschiedene Arten von Einrichtungen umfassen:</p>\n<ul>\n<li><strong>Regierungsbehörden</strong>: Staatliche Organisationen, die Forschung finanzieren (z.B.: CONICET, CNPq, CONACYT)</li>\n<li><strong>Private Stiftungen</strong>: Gemeinnützige Organisationen, die sich der wissenschaftlichen Förderung widmen</li>\n<li><strong>Unternehmen</strong>: Private Firmen, die Forschung im Zusammenhang mit ihren Interessen finanzieren</li>\n<li><strong>Akademische Einrichtungen</strong>: Universitäten oder Forschungszentren, die interne Mittel bereitstellen</li>\n<li><strong>Internationale Organisationen</strong>: Multilaterale Einrichtungen (z.B.: WHO, UNESCO)</li>\n</ul>\n\n<h4>Wie registriert man den Sponsor?</h4>\n<p>Geben Sie den vollständigen offiziellen Namen der fördernden Organisation ein. Falls es mehrere Sponsoren gibt, listen Sie jeden in einer separaten Zeile auf oder getrennt durch Semikolons.</p>\n<p><strong>Korrektes Beispiel</strong>:</p>\n<pre>Consejo Nacional de Investigaciones Científicas y Técnicas (CONICET)</pre>\n\n<h4>Zusätzliche Informationen</h4>\n<p>Die Registrierung des Sponsors ist wichtig, um:</p>\n<ul>\n<li>Transparenzanforderungen in der Forschung zu erfüllen</li>\n<li>Die Identifizierung von Finanzierungsquellen zu erleichtern</li>\n<li>Bibliometrische Analysen zu Finanzierungsmustern zu ermöglichen</li>\n<li>Indexierungsanforderungen in internationalen Datenbanken zu erfüllen (PubMed, Scopus, Web of Science)</li>\n</ul>\n\n<h4>Beziehung zu anderen Feldern</h4>\n<p>Dieses Feld ergänzt:</p>\n<ul>\n<li><strong>Award ID</strong>: Identifikationsnummer des Projekts oder Stipendiums</li>\n<li><strong>Funding Statement</strong>: Vollständige Finanzierungserklärung</li>\n<li><strong>Conflict of Interest</strong>: Erklärung von Interessenkonflikten im Zusammenhang mit der Finanzierung</li>\n</ul>','elisa','2026-01-08 23:20:09','elisa','2026-01-08 23:20:09'),(56,'book-author','book_author','es','<!-- ESPAÑOL -->\n<h3>¿Qué es bookauthor?</h3>\n<p>El campo <code>bookauthor</code> se utiliza para especificar el autor o autores de la obra principal (<code>booktitle</code>) cuando se está citando una parte específica de un libro que tiene su propio título (<code>title</code>).</p>\n\n<h4>¿Cuándo usar bookauthor?</h4>\n<p>Este campo es especialmente útil en los siguientes casos:</p>\n<ul>\n<li><strong>Capítulos en libros con autor principal</strong>: Cuando se cita un capítulo o sección de un libro donde el autor del libro completo es diferente del autor del capítulo específico</li>\n<li><strong>Obras en colecciones de un mismo autor</strong>: Cuando se referencia un ensayo o trabajo específico dentro de las obras completas de un autor</li>\n<li><strong>Traducciones y comentarios</strong>: Cuando la obra principal tiene un autor y el comentario, introducción o capítulo específico tiene otro autor</li>\n</ul>\n\n<h4>Ejemplo de uso correcto</h4>\n<pre>@InBook{lear,\n  author = {Shakespeare, William},\n  bookauthor = {Shakespeare, William},\n  maintitle = {Collected Works},\n  booktitle = {Tragedies},\n  title = {King Lear},\n  volume = {1},\n  pages = {53-159}\n}</pre>\n<p>En el ejemplo anterior, <code>author</code> se refiere al autor de \"King Lear\" y <code>bookauthor</code> al autor de \"Tragedies\".</p>\n\n<h4>Diferencias con otros campos de autoría</h4>\n<ul>\n<li><strong>author</strong>: Autor del trabajo específico (<code>title</code>)</li>\n<li><strong>bookauthor</strong>: Autor de la obra que contiene el trabajo (<code>booktitle</code>)</li>\n<li><strong>editor</strong>: Editor de la obra, cuando no hay un autor principal</li>\n</ul>\n\n<h4>Concatenación automática</h4>\n<p>Los estilos bibliográficos estándar de BibLaTeX concatenan automáticamente los campos <code>bookauthor</code>, <code>editor</code> y <code>translator</code> cuando son idénticos, evitando repeticiones innecesarias en la bibliografía.</p>\n\n<h4>Tipos de entrada donde se usa</h4>\n<p>Este campo es opcional y relevante principalmente en:</p>\n<ul>\n<li><strong>@InBook</strong>: Para partes de libros con título propio</li>\n<li><strong>@BookInBook</strong>: Para obras originalmente independientes reimpresas en colecciones</li>\n</ul>\n','franco','2026-01-09 00:34:24','franco','2026-01-09 14:07:56'),(57,'book-author','book_author','pt','<!-- PORTUGUÉS -->\n<h3>O que é bookauthor?</h3>\n<p>O campo <code>bookauthor</code> é usado para especificar o autor ou autores da obra principal (<code>booktitle</code>) quando se cita uma parte específica de um livro que tem seu próprio título (<code>title</code>).</p>\n\n<h4>Quando usar bookauthor?</h4>\n<p>Este campo é especialmente útil nos seguintes casos:</p>\n<ul>\n<li><strong>Capítulos em livros com autor principal</strong>: Quando se cita um capítulo ou seção de um livro onde o autor do livro completo é diferente do autor do capítulo específico</li>\n<li><strong>Obras em coleções do mesmo autor</strong>: Quando se referencia um ensaio ou trabalho específico dentro das obras completas de um autor</li>\n<li><strong>Traduções e comentários</strong>: Quando a obra principal tem um autor e o comentário, introdução ou capítulo específico tem outro autor</li>\n</ul>\n\n<h4>Exemplo de uso correto</h4>\n<pre>@InBook{lear,\n  author = {Shakespeare, William},\n  bookauthor = {Shakespeare, William},\n  maintitle = {Collected Works},\n  booktitle = {Tragedies},\n  title = {King Lear},\n  volume = {1},\n  pages = {53-159}\n}</pre>\n<p>No exemplo acima, <code>author</code> refere-se ao autor de \"King Lear\" e <code>bookauthor</code> ao autor de \"Tragedies\".</p>\n\n<h4>Diferenças com outros campos de autoria</h4>\n<ul>\n<li><strong>author</strong>: Autor do trabalho específico (<code>title</code>)</li>\n<li><strong>bookauthor</strong>: Autor da obra que contém o trabalho (<code>booktitle</code>)</li>\n<li><strong>editor</strong>: Editor da obra, quando não há um autor principal</li>\n</ul>\n\n<h4>Concatenação automática</h4>\n<p>Os estilos bibliográficos padrão do BibLaTeX concatenam automaticamente os campos <code>bookauthor</code>, <code>editor</code> e <code>translator</code> quando são idênticos, evitando repetições desnecessárias na bibliografia.</p>\n\n<h4>Tipos de entrada onde se usa</h4>\n<p>Este campo é opcional e relevante principalmente em:</p>\n<ul>\n<li><strong>@InBook</strong>: Para partes de livros com título próprio</li>\n<li><strong>@BookInBook</strong>: Para obras originalmente independentes reimpresas em coleções</li>\n</ul>\n','franco','2026-01-09 00:34:24','franco','2026-01-09 14:08:08'),(58,'book-author','book_author','en','<!-- INGLÉS -->\n<h3>What is bookauthor?</h3>\n<p>The <code>bookauthor</code> field is used to specify the author(s) of the main work (<code>booktitle</code>) when citing a specific part of a book that has its own title (<code>title</code>).</p>\n\n<h4>When to use bookauthor?</h4>\n<p>This field is especially useful in the following cases:</p>\n<ul>\n<li><strong>Chapters in books with a main author</strong>: When citing a chapter or section of a book where the author of the complete book differs from the author of the specific chapter</li>\n<li><strong>Works in collections by the same author</strong>: When referencing a specific essay or work within an author\'s collected works</li>\n<li><strong>Translations and commentaries</strong>: When the main work has one author and the commentary, introduction, or specific chapter has another author</li>\n</ul>\n\n<h4>Correct usage example</h4>\n<pre>@InBook{lear,\n  author = {Shakespeare, William},\n  bookauthor = {Shakespeare, William},\n  maintitle = {Collected Works},\n  booktitle = {Tragedies},\n  title = {King Lear},\n  volume = {1},\n  pages = {53-159}\n}</pre>\n<p>In the example above, <code>author</code> refers to the author of \"King Lear\" and <code>bookauthor</code> to the author of \"Tragedies\".</p>\n\n<h4>Differences with other authorship fields</h4>\n<ul>\n<li><strong>author</strong>: Author of the specific work (<code>title</code>)</li>\n<li><strong>bookauthor</strong>: Author of the work containing the piece (<code>booktitle</code>)</li>\n<li><strong>editor</strong>: Editor of the work, when there is no main author</li>\n</ul>\n\n<h4>Automatic concatenation</h4>\n<p>BibLaTeX\'s standard bibliographic styles automatically concatenate the <code>bookauthor</code>, <code>editor</code>, and <code>translator</code> fields when they are identical, avoiding unnecessary repetitions in the bibliography.</p>\n\n<h4>Entry types where it is used</h4>\n<p>This field is optional and mainly relevant in:</p>\n<ul>\n<li><strong>@InBook</strong>: For parts of books with their own title</li>\n<li><strong>@BookInBook</strong>: For originally independent works reprinted in collections</li>\n</ul>\n','franco','2026-01-09 00:34:24','franco','2026-01-09 14:08:21'),(59,'bookauthor','book_author','it','<!-- ITALIANO -->\n<h3>Cos\'è bookauthor?</h3>\n<p>Il campo <code>bookauthor</code> viene utilizzato per specificare l\'autore o gli autori dell\'opera principale (<code>booktitle</code>) quando si cita una parte specifica di un libro che ha un proprio titolo (<code>title</code>).</p>\n\n<h4>Quando usare bookauthor?</h4>\n<p>Questo campo è particolarmente utile nei seguenti casi:</p>\n<ul>\n<li><strong>Capitoli in libri con un autore principale</strong>: Quando si cita un capitolo o una sezione di un libro dove l\'autore del libro completo è diverso dall\'autore del capitolo specifico</li>\n<li><strong>Opere in raccolte dello stesso autore</strong>: Quando si fa riferimento a un saggio o lavoro specifico all\'interno delle opere complete di un autore</li>\n<li><strong>Traduzioni e commenti</strong>: Quando l\'opera principale ha un autore e il commento, l\'introduzione o il capitolo specifico ha un altro autore</li>\n</ul>\n\n<h4>Esempio di uso corretto</h4>\n<pre>@InBook{lear,\n  author = {Shakespeare, William},\n  bookauthor = {Shakespeare, William},\n  maintitle = {Collected Works},\n  booktitle = {Tragedies},\n  title = {King Lear},\n  volume = {1},\n  pages = {53-159}\n}</pre>\n<p>Nell\'esempio sopra, <code>author</code> si riferisce all\'autore di \"King Lear\" e <code>bookauthor</code> all\'autore di \"Tragedies\".</p>\n\n<h4>Differenze con altri campi di autore</h4>\n<ul>\n<li><strong>author</strong>: Autore del lavoro specifico (<code>title</code>)</li>\n<li><strong>bookauthor</strong>: Autore dell\'opera che contiene il lavoro (<code>booktitle</code>)</li>\n<li><strong>editor</strong>: Editore dell\'opera, quando non c\'è un autore principale</li>\n</ul>\n\n<h4>Concatenazione automatica</h4>\n<p>Gli stili bibliografici standard di BibLaTeX concatenano automaticamente i campi <code>bookauthor</code>, <code>editor</code> e <code>translator</code> quando sono identici, evitando ripetizioni non necessarie nella bibliografia.</p>\n\n<h4>Tipi di voce dove viene utilizzato</h4>\n<p>Questo campo è opzionale e principalmente rilevante in:</p>\n<ul>\n<li><strong>@InBook</strong>: Per parti di libri con titolo proprio</li>\n<li><strong>@BookInBook</strong>: Per opere originariamente indipendenti ristampate in raccolte</li>\n</ul>\n','franco','2026-01-09 00:34:24','franco','2026-01-09 00:34:24'),(60,'book-author','book_author','fr','<!-- FRANCÉS -->\n<h3>Qu\'est-ce que bookauthor?</h3>\n<p>Le champ <code>bookauthor</code> est utilisé pour spécifier l\'auteur ou les auteurs de l\'œuvre principale (<code>booktitle</code>) lorsqu\'on cite une partie spécifique d\'un livre qui a son propre titre (<code>title</code>).</p>\n\n<h4>Quand utiliser bookauthor?</h4>\n<p>Ce champ est particulièrement utile dans les cas suivants:</p>\n<ul>\n<li><strong>Chapitres dans des livres avec un auteur principal</strong>: Lorsqu\'on cite un chapitre ou une section d\'un livre où l\'auteur du livre complet diffère de l\'auteur du chapitre spécifique</li>\n<li><strong>Œuvres dans des collections d\'un même auteur</strong>: Lorsqu\'on référence un essai ou un travail spécifique au sein des œuvres complètes d\'un auteur</li>\n<li><strong>Traductions et commentaires</strong>: Lorsque l\'œuvre principale a un auteur et que le commentaire, l\'introduction ou le chapitre spécifique a un autre auteur</li>\n</ul>\n\n<h4>Exemple d\'utilisation correcte</h4>\n<pre>@InBook{lear,\n  author = {Shakespeare, William},\n  bookauthor = {Shakespeare, William},\n  maintitle = {Collected Works},\n  booktitle = {Tragedies},\n  title = {King Lear},\n  volume = {1},\n  pages = {53-159}\n}</pre>\n<p>Dans l\'exemple ci-dessus, <code>author</code> fait référence à l\'auteur de \"King Lear\" et <code>bookauthor</code> à l\'auteur de \"Tragedies\".</p>\n\n<h4>Différences avec les autres champs d\'auteur</h4>\n<ul>\n<li><strong>author</strong>: Auteur du travail spécifique (<code>title</code>)</li>\n<li><strong>bookauthor</strong>: Auteur de l\'œuvre contenant le travail (<code>booktitle</code>)</li>\n<li><strong>editor</strong>: Éditeur de l\'œuvre, lorsqu\'il n\'y a pas d\'auteur principal</li>\n</ul>\n\n<h4>Concaténation automatique</h4>\n<p>Les styles bibliographiques standard de BibLaTeX concatènent automatiquement les champs <code>bookauthor</code>, <code>editor</code> et <code>translator</code> lorsqu\'ils sont identiques, évitant les répétitions inutiles dans la bibliographie.</p>\n\n<h4>Types d\'entrée où il est utilisé</h4>\n<p>Ce champ est optionnel et principalement pertinent dans:</p>\n<ul>\n<li><strong>@InBook</strong>: Pour les parties de livres avec leur propre titre</li>\n<li><strong>@BookInBook</strong>: Pour les œuvres originellement indépendantes réimprimées dans des collections</li>\n</ul>\n','franco','2026-01-09 00:34:24','franco','2026-01-09 14:08:33'),(61,'book-author','book_author','de','<!-- ALEMÁN -->\n<h3>Was ist bookauthor?</h3>\n<p>Das Feld <code>bookauthor</code> wird verwendet, um den Autor oder die Autoren des Hauptwerks (<code>booktitle</code>) anzugeben, wenn ein bestimmter Teil eines Buches zitiert wird, der einen eigenen Titel (<code>title</code>) hat.</p>\n\n<h4>Wann verwendet man bookauthor?</h4>\n<p>Dieses Feld ist besonders nützlich in den folgenden Fällen:</p>\n<ul>\n<li><strong>Kapitel in Büchern mit einem Hauptautor</strong>: Beim Zitieren eines Kapitels oder Abschnitts eines Buches, bei dem sich der Autor des vollständigen Buches vom Autor des spezifischen Kapitels unterscheidet</li>\n<li><strong>Werke in Sammlungen desselben Autors</strong>: Beim Verweis auf einen bestimmten Essay oder ein Werk innerhalb der gesammelten Werke eines Autors</li>\n<li><strong>Übersetzungen und Kommentare</strong>: Wenn das Hauptwerk einen Autor hat und der Kommentar, die Einleitung oder das spezifische Kapitel einen anderen Autor hat</li>\n</ul>\n\n<h4>Beispiel für korrekte Verwendung</h4>\n<pre>@InBook{lear,\n  author = {Shakespeare, William},\n  bookauthor = {Shakespeare, William},\n  maintitle = {Collected Works},\n  booktitle = {Tragedies},\n  title = {King Lear},\n  volume = {1},\n  pages = {53-159}\n}</pre>\n<p>Im obigen Beispiel bezieht sich <code>author</code> auf den Autor von \"King Lear\" und <code>bookauthor</code> auf den Autor von \"Tragedies\".</p>\n\n<h4>Unterschiede zu anderen Autorenfeldern</h4>\n<ul>\n<li><strong>author</strong>: Autor des spezifischen Werks (<code>title</code>)</li>\n<li><strong>bookauthor</strong>: Autor des Werks, das die Arbeit enthält (<code>booktitle</code>)</li>\n<li><strong>editor</strong>: Herausgeber des Werks, wenn es keinen Hauptautor gibt</li>\n</ul>\n\n<h4>Automatische Verkettung</h4>\n<p>Die Standard-Bibliographiestile von BibLaTeX verketten automatisch die Felder <code>bookauthor</code>, <code>editor</code> und <code>translator</code>, wenn sie identisch sind, wodurch unnötige Wiederholungen in der Bibliographie vermieden werden.</p>\n\n<h4>Eintragstypen, in denen es verwendet wird</h4>\n<p>Dieses Feld ist optional und hauptsächlich relevant in:</p>\n<ul>\n<li><strong>@InBook</strong>: Für Teile von Büchern mit eigenem Titel</li>\n<li><strong>@BookInBook</strong>: Für ursprünglich eigenständige Werke, die in Sammlungen nachgedruckt wurden</li>\n</ul>','franco','2026-01-09 00:34:24','franco','2026-01-09 14:08:46'),(68,'clasificacion-oecd','clasificacion_oecd','es','<!-- ESPAÑOL -->\n<h3>¿Qué es clasificacion-oecd?</h3>\n<p>El campo <code>clasificacion-oecd</code> contiene la clasificación de Campos de Ciencia y Tecnología (FOS - Fields of Science and Technology) según el estándar establecido por la Organización para la Cooperación y el Desarrollo Económicos (OECD) en el Manual de Frascati.</p>\n\n<h4>Estructura de la clasificación</h4>\n<p>La clasificación OECD se organiza en una estructura jerárquica de dos niveles:</p>\n<ul>\n<li><strong>Nivel principal (1 dígito)</strong>: 6 campos mayores</li>\n<li><strong>Nivel secundario (2 dígitos)</strong>: 42 subcategorías</li>\n</ul>\n\n<h4>Campos principales de la clasificación OECD</h4>\n<p>Los seis campos principales son:</p>\n<ol>\n<li><strong>Ciencias Naturales</strong> (Natural Sciences)</li>\n<li><strong>Ingeniería y Tecnología</strong> (Engineering and Technology)</li>\n<li><strong>Ciencias Médicas y de la Salud</strong> (Medical and Health Sciences)</li>\n<li><strong>Ciencias Agrícolas y Veterinarias</strong> (Agricultural and Veterinary Sciences)</li>\n<li><strong>Ciencias Sociales</strong> (Social Sciences)</li>\n<li><strong>Humanidades y Artes</strong> (Humanities and Arts)</li>\n</ol>\n\n<h4>¿Para qué sirve este campo?</h4>\n<p>La clasificación OECD se utiliza para:</p>\n<ul>\n<li><strong>Indexación internacional</strong>: Facilita la inclusión en bases de datos académicas globales</li>\n<li><strong>Análisis bibliométricos</strong>: Permite comparaciones entre disciplinas y áreas de investigación</li>\n<li><strong>Estadísticas de I+D</strong>: Estandariza la recopilación de datos sobre investigación y desarrollo</li>\n<li><strong>Interoperabilidad de datos</strong>: Permite el intercambio de información entre instituciones y países</li>\n</ul>\n\n<h4>Formato de entrada</h4>\n<p>El campo debe contener el código numérico de la clasificación OECD en formato de dos dígitos separados por punto.</p>\n<p><strong>Ejemplos correctos</strong>:</p>\n<p>Una sola clasificación:</p>\n<pre>3.2</pre>\n<p>(Corresponde a \"Medicina Clínica\" dentro de \"Ciencias Médicas y de la Salud\")</p>\n<p>Múltiples clasificaciones (separadas por punto y coma):</p>\n<pre>1.2; 2.3</pre>\n<p>(Corresponde a \"Ciencias de la Computación e Información\" y \"Otras Ingenierías y Tecnologías\")</p>\n\n<h4>Relación con otros sistemas de clasificación</h4>\n<p>La clasificación OECD es compatible y se mapea con otros sistemas como:</p>\n<ul>\n<li>Web of Science Research Areas</li>\n<li>ANZSRC (Australian and New Zealand Standard Research Classification)</li>\n<li>UNESCO FOS</li>\n<li>Essential Science Indicators</li>\n</ul>\n\n<h4>Importancia para revistas académicas</h4>\n<p>Para revistas científicas, especialmente aquellas indexadas en bases internacionales como Scopus, Web of Science o SciELO, este campo es fundamental para:</p>\n<ul>\n<li>Mejorar la visibilidad de los artículos</li>\n<li>Facilitar búsquedas temáticas</li>\n<li>Cumplir con requisitos de indexación internacional</li>\n<li>Permitir análisis multidisciplinarios cuando se asignan múltiples clasificaciones</li>\n</ul>\n','elisa','2026-01-09 01:07:26','elisa','2026-01-09 01:07:26'),(69,'clasificacion-oecd','clasificacion_oecd','pt','<!-- PORTUGUÉS -->\n<h3>O que é clasificacion-oecd?</h3>\n<p>O campo <code>clasificacion-oecd</code> contém a classificação de Campos de Ciência e Tecnologia (FOS - Fields of Science and Technology) segundo o padrão estabelecido pela Organização para a Cooperação e Desenvolvimento Econômico (OCDE) no Manual de Frascati.</p>\n\n<h4>Estrutura da classificação</h4>\n<p>A classificação OCDE está organizada em uma estrutura hierárquica de dois níveis:</p>\n<ul>\n<li><strong>Nível principal (1 dígito)</strong>: 6 campos principais</li>\n<li><strong>Nível secundário (2 dígitos)</strong>: 42 subcategorias</li>\n</ul>\n\n<h4>Campos principais da classificação OCDE</h4>\n<p>Os seis campos principais são:</p>\n<ol>\n<li><strong>Ciências Naturais</strong> (Natural Sciences)</li>\n<li><strong>Engenharia e Tecnologia</strong> (Engineering and Technology)</li>\n<li><strong>Ciências Médicas e da Saúde</strong> (Medical and Health Sciences)</li>\n<li><strong>Ciências Agrárias e Veterinárias</strong> (Agricultural and Veterinary Sciences)</li>\n<li><strong>Ciências Sociais</strong> (Social Sciences)</li>\n<li><strong>Humanidades e Artes</strong> (Humanities and Arts)</li>\n</ol>\n\n<h4>Para que serve este campo?</h4>\n<p>A classificação OCDE é utilizada para:</p>\n<ul>\n<li><strong>Indexação internacional</strong>: Facilita a inclusão em bases de dados acadêmicas globais</li>\n<li><strong>Análises bibliométricas</strong>: Permite comparações entre disciplinas e áreas de pesquisa</li>\n<li><strong>Estatísticas de P&D</strong>: Padroniza a coleta de dados sobre pesquisa e desenvolvimento</li>\n<li><strong>Interoperabilidade de dados</strong>: Permite o intercâmbio de informação entre instituições e países</li>\n</ul>\n\n<h4>Formato de entrada</h4>\n<p>O campo deve conter o código numérico da classificação OCDE em formato de dois dígitos separados por ponto.</p>\n<p><strong>Exemplos corretos</strong>:</p>\n<p>Uma única classificação:</p>\n<pre>3.2</pre>\n<p>(Corresponde a \"Medicina Clínica\" dentro de \"Ciências Médicas e da Saúde\")</p>\n<p>Múltiplas classificações (separadas por ponto e vírgula):</p>\n<pre>1.2; 2.3</pre>\n<p>(Corresponde a \"Ciências da Computação e Informação\" e \"Outras Engenharias e Tecnologias\")</p>\n\n<h4>Relação com outros sistemas de classificação</h4>\n<p>A classificação OCDE é compatível e se mapeia com outros sistemas como:</p>\n<ul>\n<li>Web of Science Research Areas</li>\n<li>ANZSRC (Australian and New Zealand Standard Research Classification)</li>\n<li>UNESCO FOS</li>\n<li>Essential Science Indicators</li>\n</ul>\n\n<h4>Importância para revistas acadêmicas</h4>\n<p>Para revistas científicas, especialmente aquelas indexadas em bases internacionais como Scopus, Web of Science ou SciELO, este campo é fundamental para:</p>\n<ul>\n<li>Melhorar a visibilidade dos artigos</li>\n<li>Facilitar buscas temáticas</li>\n<li>Cumprir com requisitos de indexação internacional</li>\n<li>Permitir análises multidisciplinares quando são atribuídas múltiplas classificações</li>\n</ul>\n','elisa','2026-01-09 01:07:26','elisa','2026-01-09 01:07:26'),(70,'clasificacion-oecd','clasificacion_oecd','en','<!-- INGLÉS -->\n<h3>What is clasificacion-oecd?</h3>\n<p>The <code>clasificacion-oecd</code> field contains the Fields of Science and Technology (FOS) classification according to the standard established by the Organisation for Economic Co-operation and Development (OECD) in the Frascati Manual.</p>\n\n<h4>Classification structure</h4>\n<p>The OECD classification is organized in a two-level hierarchical structure:</p>\n<ul>\n<li><strong>Major level (1 digit)</strong>: 6 major fields</li>\n<li><strong>Minor level (2 digits)</strong>: 42 subcategories</li>\n</ul>\n\n<h4>Main OECD classification fields</h4>\n<p>The six main fields are:</p>\n<ol>\n<li><strong>Natural Sciences</strong></li>\n<li><strong>Engineering and Technology</strong></li>\n<li><strong>Medical and Health Sciences</strong></li>\n<li><strong>Agricultural and Veterinary Sciences</strong></li>\n<li><strong>Social Sciences</strong></li>\n<li><strong>Humanities and Arts</strong></li>\n</ol>\n\n<h4>What is this field used for?</h4>\n<p>The OECD classification is used for:</p>\n<ul>\n<li><strong>International indexing</strong>: Facilitates inclusion in global academic databases</li>\n<li><strong>Bibliometric analysis</strong>: Enables comparisons between disciplines and research areas</li>\n<li><strong>R&D statistics</strong>: Standardizes the collection of research and development data</li>\n<li><strong>Data interoperability</strong>: Allows information exchange between institutions and countries</li>\n</ul>\n\n<h4>Input format</h4>\n<p>The field must contain the OECD classification numerical code in two-digit format separated by a period.</p>\n<p><strong>Correct examples</strong>:</p>\n<p>Single classification:</p>\n<pre>3.2</pre>\n<p>(Corresponds to \"Clinical Medicine\" within \"Medical and Health Sciences\")</p>\n<p>Multiple classifications (separated by semicolons):</p>\n<pre>1.2; 2.3</pre>\n<p>(Corresponds to \"Computer and Information Sciences\" and \"Other Engineering and Technologies\")</p>\n\n<h4>Relationship with other classification systems</h4>\n<p>The OECD classification is compatible and maps to other systems such as:</p>\n<ul>\n<li>Web of Science Research Areas</li>\n<li>ANZSRC (Australian and New Zealand Standard Research Classification)</li>\n<li>UNESCO FOS</li>\n<li>Essential Science Indicators</li>\n</ul>\n\n<h4>Importance for academic journals</h4>\n<p>For scientific journals, especially those indexed in international databases such as Scopus, Web of Science or SciELO, this field is essential for:</p>\n<ul>\n<li>Improving article visibility</li>\n<li>Facilitating thematic searches</li>\n<li>Meeting international indexing requirements</li>\n<li>Enabling multidisciplinary analysis when multiple classifications are assigned</li>\n</ul>\n','elisa','2026-01-09 01:07:26','elisa','2026-01-09 01:07:26'),(71,'clasificacion-oecd','clasificacion_oecd','it','<!-- ITALIANO -->\n<h3>Cos\'è clasificacion-oecd?</h3>\n<p>Il campo <code>clasificacion-oecd</code> contiene la classificazione dei Campi della Scienza e della Tecnologia (FOS - Fields of Science and Technology) secondo lo standard stabilito dall\'Organizzazione per la Cooperazione e lo Sviluppo Economico (OCSE) nel Manuale di Frascati.</p>\n\n<h4>Struttura della classificazione</h4>\n<p>La classificazione OCSE è organizzata in una struttura gerarchica a due livelli:</p>\n<ul>\n<li><strong>Livello principale (1 cifra)</strong>: 6 campi principali</li>\n<li><strong>Livello secondario (2 cifre)</strong>: 42 sottocategorie</li>\n</ul>\n\n<h4>Campi principali della classificazione OCSE</h4>\n<p>I sei campi principali sono:</p>\n<ol>\n<li><strong>Scienze Naturali</strong> (Natural Sciences)</li>\n<li><strong>Ingegneria e Tecnologia</strong> (Engineering and Technology)</li>\n<li><strong>Scienze Mediche e della Salute</strong> (Medical and Health Sciences)</li>\n<li><strong>Scienze Agricole e Veterinarie</strong> (Agricultural and Veterinary Sciences)</li>\n<li><strong>Scienze Sociali</strong> (Social Sciences)</li>\n<li><strong>Scienze Umane e Arti</strong> (Humanities and Arts)</li>\n</ol>\n\n<h4>A cosa serve questo campo?</h4>\n<p>La classificazione OCSE è utilizzata per:</p>\n<ul>\n<li><strong>Indicizzazione internazionale</strong>: Facilita l\'inclusione nelle banche dati accademiche globali</li>\n<li><strong>Analisi bibliometriche</strong>: Consente confronti tra discipline e aree di ricerca</li>\n<li><strong>Statistiche di R&S</strong>: Standardizza la raccolta di dati su ricerca e sviluppo</li>\n<li><strong>Interoperabilità dei dati</strong>: Permette lo scambio di informazioni tra istituzioni e paesi</li>\n</ul>\n\n<h4>Formato di inserimento</h4>\n<p>Il campo deve contenere il codice numerico della classificazione OCSE in formato di due cifre separate da punto.</p>\n<p><strong>Esempi corretti</strong>:</p>\n<p>Una singola classificazione:</p>\n<pre>3.2</pre>\n<p>(Corrisponde a \"Medicina Clinica\" all\'interno di \"Scienze Mediche e della Salute\")</p>\n<p>Classificazioni multiple (separate da punto e virgola):</p>\n<pre>1.2; 2.3</pre>\n<p>(Corrisponde a \"Scienze dell\'Informatica e dell\'Informazione\" e \"Altre Ingegnerie e Tecnologie\")</p>\n\n<h4>Relazione con altri sistemi di classificazione</h4>\n<p>La classificazione OCSE è compatibile e si mappa con altri sistemi come:</p>\n<ul>\n<li>Web of Science Research Areas</li>\n<li>ANZSRC (Australian and New Zealand Standard Research Classification)</li>\n<li>UNESCO FOS</li>\n<li>Essential Science Indicators</li>\n</ul>\n\n<h4>Importanza per le riviste accademiche</h4>\n<p>Per le riviste scientifiche, specialmente quelle indicizzate in banche dati internazionali come Scopus, Web of Science o SciELO, questo campo è fondamentale per:</p>\n<ul>\n<li>Migliorare la visibilità degli articoli</li>\n<li>Facilitare le ricerche tematiche</li>\n<li>Soddisfare i requisiti di indicizzazione internazionale</li>\n<li>Consentire analisi multidisciplinari quando vengono assegnate classificazioni multiple</li>\n</ul>\n','elisa','2026-01-09 01:07:26','elisa','2026-01-09 01:07:26'),(72,'clasificacion-oecd','clasificacion_oecd','fr','<!-- FRANCÉS -->\n<h3>Qu\'est-ce que clasificacion-oecd?</h3>\n<p>Le champ <code>clasificacion-oecd</code> contient la classification des Domaines de la Science et de la Technologie (FOS - Fields of Science and Technology) selon la norme établie par l\'Organisation de Coopération et de Développement Économiques (OCDE) dans le Manuel de Frascati.</p>\n\n<h4>Structure de la classification</h4>\n<p>La classification OCDE est organisée en une structure hiérarchique à deux niveaux:</p>\n<ul>\n<li><strong>Niveau principal (1 chiffre)</strong>: 6 domaines majeurs</li>\n<li><strong>Niveau secondaire (2 chiffres)</strong>: 42 sous-catégories</li>\n</ul>\n\n<h4>Domaines principaux de la classification OCDE</h4>\n<p>Les six domaines principaux sont:</p>\n<ol>\n<li><strong>Sciences Naturelles</strong> (Natural Sciences)</li>\n<li><strong>Ingénierie et Technologie</strong> (Engineering and Technology)</li>\n<li><strong>Sciences Médicales et de la Santé</strong> (Medical and Health Sciences)</li>\n<li><strong>Sciences Agricoles et Vétérinaires</strong> (Agricultural and Veterinary Sciences)</li>\n<li><strong>Sciences Sociales</strong> (Social Sciences)</li>\n<li><strong>Sciences Humaines et Arts</strong> (Humanities and Arts)</li>\n</ol>\n\n<h4>À quoi sert ce champ?</h4>\n<p>La classification OCDE est utilisée pour:</p>\n<ul>\n<li><strong>Indexation internationale</strong>: Facilite l\'inclusion dans les bases de données académiques mondiales</li>\n<li><strong>Analyses bibliométriques</strong>: Permet des comparaisons entre disciplines et domaines de recherche</li>\n<li><strong>Statistiques de R&D</strong>: Standardise la collecte de données sur la recherche et le développement</li>\n<li><strong>Interopérabilité des données</strong>: Permet l\'échange d\'informations entre institutions et pays</li>\n</ul>\n\n<h4>Format de saisie</h4>\n<p>Le champ doit contenir le code numérique de la classification OCDE au format de deux chiffres séparés par un point.</p>\n<p><strong>Exemples corrects</strong>:</p>\n<p>Une seule classification:</p>\n<pre>3.2</pre>\n<p>(Correspond à \"Médecine Clinique\" dans \"Sciences Médicales et de la Santé\")</p>\n<p>Classifications multiples (séparées par des points-virgules):</p>\n<pre>1.2; 2.3</pre>\n<p>(Correspond à \"Sciences de l\'Informatique et de l\'Information\" et \"Autres Ingénieries et Technologies\")</p>\n\n<h4>Relation avec d\'autres systèmes de classification</h4>\n<p>La classification OCDE est compatible et se mappe avec d\'autres systèmes tels que:</p>\n<ul>\n<li>Web of Science Research Areas</li>\n<li>ANZSRC (Australian and New Zealand Standard Research Classification)</li>\n<li>UNESCO FOS</li>\n<li>Essential Science Indicators</li>\n</ul>\n\n<h4>Importance pour les revues académiques</h4>\n<p>Pour les revues scientifiques, particulièrement celles indexées dans les bases de données internationales comme Scopus, Web of Science ou SciELO, ce champ est fondamental pour:</p>\n<ul>\n<li>Améliorer la visibilité des articles</li>\n<li>Faciliter les recherches thématiques</li>\n<li>Répondre aux exigences d\'indexation internationale</li>\n<li>Permettre des analyses multidisciplinaires lorsque plusieurs classifications sont attribuées</li>\n</ul>\n','elisa','2026-01-09 01:07:26','elisa','2026-01-09 01:07:26'),(73,'clasificacion-oecd','clasificacion_oecd','de','<!-- ALEMÁN -->\n<h3>Was ist clasificacion-oecd?</h3>\n<p>Das Feld <code>clasificacion-oecd</code> enthält die Klassifizierung der Wissenschafts- und Technologiefelder (FOS - Fields of Science and Technology) gemäß dem von der Organisation für wirtschaftliche Zusammenarbeit und Entwicklung (OECD) im Frascati-Handbuch festgelegten Standard.</p>\n\n<h4>Struktur der Klassifizierung</h4>\n<p>Die OECD-Klassifizierung ist in einer zweistufigen hierarchischen Struktur organisiert:</p>\n<ul>\n<li><strong>Hauptebene (1 Ziffer)</strong>: 6 Hauptfelder</li>\n<li><strong>Unterebene (2 Ziffern)</strong>: 42 Unterkategorien</li>\n</ul>\n\n<h4>Hauptfelder der OECD-Klassifizierung</h4>\n<p>Die sechs Hauptfelder sind:</p>\n<ol>\n<li><strong>Naturwissenschaften</strong> (Natural Sciences)</li>\n<li><strong>Ingenieurwesen und Technologie</strong> (Engineering and Technology)</li>\n<li><strong>Medizinische und Gesundheitswissenschaften</strong> (Medical and Health Sciences)</li>\n<li><strong>Agrar- und Veterinärwissenschaften</strong> (Agricultural and Veterinary Sciences)</li>\n<li><strong>Sozialwissenschaften</strong> (Social Sciences)</li>\n<li><strong>Geisteswissenschaften und Künste</strong> (Humanities and Arts)</li>\n</ol>\n\n<h4>Wozu dient dieses Feld?</h4>\n<p>Die OECD-Klassifizierung wird verwendet für:</p>\n<ul>\n<li><strong>Internationale Indexierung</strong>: Erleichtert die Aufnahme in globale akademische Datenbanken</li>\n<li><strong>Bibliometrische Analysen</strong>: Ermöglicht Vergleiche zwischen Disziplinen und Forschungsbereichen</li>\n<li><strong>F&E-Statistiken</strong>: Standardisiert die Erfassung von Forschungs- und Entwicklungsdaten</li>\n<li><strong>Dateninteroperabilität</strong>: Ermöglicht den Informationsaustausch zwischen Institutionen und Ländern</li>\n</ul>\n\n<h4>Eingabeformat</h4>\n<p>Das Feld muss den numerischen Code der OECD-Klassifizierung im Format von zwei durch einen Punkt getrennten Ziffern enthalten.</p>\n<p><strong>Korrekte Beispiele</strong>:</p>\n<p>Eine einzelne Klassifizierung:</p>\n<pre>3.2</pre>\n<p>(Entspricht \"Klinische Medizin\" innerhalb von \"Medizinische und Gesundheitswissenschaften\")</p>\n<p>Mehrere Klassifizierungen (durch Semikolons getrennt):</p>\n<pre>1.2; 2.3</pre>\n<p>(Entspricht \"Computer- und Informationswissenschaften\" und \"Andere Ingenieurwissenschaften und Technologien\")</p>\n\n<h4>Beziehung zu anderen Klassifizierungssystemen</h4>\n<p>Die OECD-Klassifizierung ist kompatibel und lässt sich mit anderen Systemen wie folgenden verknüpfen:</p>\n<ul>\n<li>Web of Science Research Areas</li>\n<li>ANZSRC (Australian and New Zealand Standard Research Classification)</li>\n<li>UNESCO FOS</li>\n<li>Essential Science Indicators</li>\n</ul>\n\n<h4>Bedeutung für akademische Zeitschriften</h4>\n<p>Für wissenschaftliche Zeitschriften, insbesondere solche, die in internationalen Datenbanken wie Scopus, Web of Science oder SciELO indexiert sind, ist dieses Feld grundlegend für:</p>\n<ul>\n<li>Verbesserung der Sichtbarkeit von Artikeln</li>\n<li>Erleichterung thematischer Suchen</li>\n<li>Erfüllung internationaler Indexierungsanforderungen</li>\n<li>Ermöglichung multidisziplinärer Analysen bei Zuweisung mehrerer Klassifizierungen</li>\n</ul>','elisa','2026-01-09 01:07:26','elisa','2026-01-09 01:07:26'),(74,'handle-system','handle_system','es','<!-- ESPAÑOL -->\n<h3>¿Qué es un handle?</h3>\n<p>El campo <code>handle</code> contiene un identificador persistente basado en el Handle System, un sistema distribuido de identificación diseñado para proporcionar nombres únicos y permanentes para recursos digitales en Internet.</p>\n\n<h4>Características del Handle System</h4>\n<p>El Handle System es una infraestructura que proporciona:</p>\n<ul>\n<li><strong>Identificación única</strong>: Cada handle identifica inequívocamente un solo recurso digital</li>\n<li><strong>Persistencia</strong>: El identificador permanece válido incluso si cambia la ubicación del recurso</li>\n<li><strong>Resolución global</strong>: Sistema centralizado que resuelve handles a sus ubicaciones actuales</li>\n<li><strong>Independencia de ubicación</strong>: No depende de URLs que pueden cambiar con el tiempo</li>\n</ul>\n\n<h4>Estructura de un handle</h4>\n<p>Un handle se compone de dos partes separadas por una barra diagonal:</p>\n<pre>prefijo/sufijo</pre>\n<ul>\n<li><strong>Prefijo</strong>: Identifica la autoridad de nombramiento (institución u organización)</li>\n<li><strong>Sufijo</strong>: Describe el nombre local del recurso</li>\n</ul>\n<p><strong>Ejemplo</strong>:</p>\n<pre>11577/3159842</pre>\n<p>En este ejemplo, <code>11577</code> identifica al repositorio institucional y <code>3159842</code> identifica el recurso específico dentro de ese repositorio.</p>\n\n<h4>Relación con DOI</h4>\n<p>El DOI (Digital Object Identifier) es en realidad una implementación especializada del Handle System. Todo DOI es un handle, pero no todo handle es un DOI. Los DOIs añaden:</p>\n<ul>\n<li>Metadata estructurada adicional</li>\n<li>Infraestructura social y de gobernanza específica</li>\n<li>Registro centralizado a través de agencias como Crossref o DataCite</li>\n</ul>\n\n<h4>¿Para qué sirve el handle?</h4>\n<p>En el contexto de artículos científicos, el handle se utiliza para:</p>\n<ul>\n<li><strong>Citación persistente</strong>: Garantizar que las referencias permanezcan válidas a largo plazo</li>\n<li><strong>Acceso permanente</strong>: Permitir localizar el artículo incluso si cambia de servidor o repositorio</li>\n<li><strong>Identificación en repositorios</strong>: Especialmente común en repositorios institucionales que usan software como DSpace</li>\n<li><strong>Interoperabilidad</strong>: Facilitar el intercambio de metadatos entre sistemas</li>\n</ul>\n\n<h4>Formato de entrada</h4>\n<p>El campo debe contener el handle completo en formato <code>prefijo/sufijo</code>.</p>\n<p><strong>Ejemplos correctos</strong>:</p>\n<p>Handle de un repositorio institucional:</p>\n<pre>11577/3159842</pre>\n<p>Handle de un archivo digital:</p>\n<pre>2381/29652</pre>\n\n<h4>Diferencias con otros identificadores persistentes</h4>\n<table border=\"1\" cellpadding=\"5\" cellspacing=\"0\">\n<tr>\n<th>Identificador</th>\n<th>Uso principal</th>\n<th>Gobernanza</th>\n</tr>\n<tr>\n<td><strong>Handle</strong></td>\n<td>Infraestructura base para identificación persistente</td>\n<td>Handle.Net Registry</td>\n</tr>\n<tr>\n<td><strong>DOI</strong></td>\n<td>Publicaciones académicas, datos de investigación</td>\n<td>International DOI Foundation</td>\n</tr>\n<tr>\n<td><strong>ARK</strong></td>\n<td>Objetos digitales en bibliotecas y archivos</td>\n<td>California Digital Library</td>\n</tr>\n<tr>\n<td><strong>URN</strong></td>\n<td>Identificación independiente de ubicación</td>\n<td>IETF</td>\n</tr>\n</table>\n\n<h4>Importancia para revistas académicas</h4>\n<p>Para artículos científicos en repositorios institucionales o sistemas de archivo digital:</p>\n<ul>\n<li><strong>Preservación digital</strong>: Mantiene acceso al contenido a largo plazo</li>\n<li><strong>Trazabilidad</strong>: Permite seguimiento de versiones y cambios</li>\n<li><strong>Cumplimiento normativo</strong>: Satisface requisitos de acceso abierto en muchas instituciones</li>\n<li><strong>Integración con CRIS</strong>: Facilita la integración con sistemas de información de investigación actual</li>\n</ul>\n\n<h4>Uso junto con DOI</h4>\n<p>Es común que un artículo tenga tanto DOI como handle:</p>\n<ul>\n<li><strong>DOI</strong>: Para la citación académica estándar</li>\n<li><strong>Handle</strong>: Para el acceso a través del repositorio institucional</li>\n</ul>\n<p>Ambos identificadores pueden coexistir y apuntar al mismo recurso desde diferentes puntos de acceso.</p>\n','elisa','2026-01-09 07:43:26','elisa','2026-01-09 08:16:10'),(75,'handle-system','handle_system','pt','<!-- PORTUGUÉS -->\n<h3>O que é um handle?</h3>\n<p>O campo <code>handle</code> contém um identificador persistente baseado no Handle System, um sistema distribuído de identificação projetado para fornecer nomes únicos e permanentes para recursos digitais na Internet.</p>\n\n<h4>Características do Handle System</h4>\n<p>O Handle System é uma infraestrutura que fornece:</p>\n<ul>\n<li><strong>Identificação única</strong>: Cada handle identifica inequivocamente um único recurso digital</li>\n<li><strong>Persistência</strong>: O identificador permanece válido mesmo se a localização do recurso mudar</li>\n<li><strong>Resolução global</strong>: Sistema centralizado que resolve handles para suas localizações atuais</li>\n<li><strong>Independência de localização</strong>: Não depende de URLs que podem mudar com o tempo</li>\n</ul>\n\n<h4>Estrutura de um handle</h4>\n<p>Um handle é composto por duas partes separadas por uma barra:</p>\n<pre>prefixo/sufixo</pre>\n<ul>\n<li><strong>Prefixo</strong>: Identifica a autoridade de nomeação (instituição ou organização)</li>\n<li><strong>Sufixo</strong>: Descreve o nome local do recurso</li>\n</ul>\n<p><strong>Exemplo</strong>:</p>\n<pre>11577/3159842</pre>\n<p>Neste exemplo, <code>11577</code> identifica o repositório institucional e <code>3159842</code> identifica o recurso específico dentro desse repositório.</p>\n\n<h4>Relação com DOI</h4>\n<p>O DOI (Digital Object Identifier) é na verdade uma implementação especializada do Handle System. Todo DOI é um handle, mas nem todo handle é um DOI. Os DOIs adicionam:</p>\n<ul>\n<li>Metadados estruturados adicionais</li>\n<li>Infraestrutura social e de governança específica</li>\n<li>Registro centralizado através de agências como Crossref ou DataCite</li>\n</ul>\n\n<h4>Para que serve o handle?</h4>\n<p>No contexto de artigos científicos, o handle é utilizado para:</p>\n<ul>\n<li><strong>Citação persistente</strong>: Garantir que as referências permaneçam válidas a longo prazo</li>\n<li><strong>Acesso permanente</strong>: Permitir localizar o artigo mesmo se mudar de servidor ou repositório</li>\n<li><strong>Identificação em repositórios</strong>: Especialmente comum em repositórios institucionais que usam software como DSpace</li>\n<li><strong>Interoperabilidade</strong>: Facilitar o intercâmbio de metadados entre sistemas</li>\n</ul>\n\n<h4>Formato de entrada</h4>\n<p>O campo deve conter o handle completo no formato <code>prefixo/sufixo</code>.</p>\n<p><strong>Exemplos corretos</strong>:</p>\n<p>Handle de um repositório institucional:</p>\n<pre>11577/3159842</pre>\n<p>Handle de um arquivo digital:</p>\n<pre>2381/29652</pre>\n\n<h4>Diferenças com outros identificadores persistentes</h4>\n<table border=\"1\" cellpadding=\"5\" cellspacing=\"0\">\n<tr>\n<th>Identificador</th>\n<th>Uso principal</th>\n<th>Governança</th>\n</tr>\n<tr>\n<td><strong>Handle</strong></td>\n<td>Infraestrutura base para identificação persistente</td>\n<td>Handle.Net Registry</td>\n</tr>\n<tr>\n<td><strong>DOI</strong></td>\n<td>Publicações acadêmicas, dados de pesquisa</td>\n<td>International DOI Foundation</td>\n</tr>\n<tr>\n<td><strong>ARK</strong></td>\n<td>Objetos digitais em bibliotecas e arquivos</td>\n<td>California Digital Library</td>\n</tr>\n<tr>\n<td><strong>URN</strong></td>\n<td>Identificação independente de localização</td>\n<td>IETF</td>\n</tr>\n</table>\n\n<h4>Importância para revistas acadêmicas</h4>\n<p>Para artigos científicos em repositórios institucionais ou sistemas de arquivo digital:</p>\n<ul>\n<li><strong>Preservação digital</strong>: Mantém acesso ao conteúdo a longo prazo</li>\n<li><strong>Rastreabilidade</strong>: Permite acompanhamento de versões e mudanças</li>\n<li><strong>Cumprimento normativo</strong>: Satisfaz requisitos de acesso aberto em muitas instituições</li>\n<li><strong>Integração com CRIS</strong>: Facilita a integração com sistemas de informação de pesquisa atual</li>\n</ul>\n\n<h4>Uso conjunto com DOI</h4>\n<p>É comum que um artigo tenha tanto DOI quanto handle:</p>\n<ul>\n<li><strong>DOI</strong>: Para a citação acadêmica padrão</li>\n<li><strong>Handle</strong>: Para o acesso através do repositório institucional</li>\n</ul>\n<p>Ambos os identificadores podem coexistir e apontar para o mesmo recurso a partir de diferentes pontos de acesso.</p>\n','elisa','2026-01-09 07:43:26','elisa','2026-01-09 08:16:32'),(76,'handle-system','handle_system','en','<!-- INGLÉS -->\n<h3>What is a handle?</h3>\n<p>The <code>handle</code> field contains a persistent identifier based on the Handle System, a distributed identification system designed to provide unique and permanent names for digital resources on the Internet.</p>\n\n<h4>Handle System characteristics</h4>\n<p>The Handle System is an infrastructure that provides:</p>\n<ul>\n<li><strong>Unique identification</strong>: Each handle unambiguously identifies a single digital resource</li>\n<li><strong>Persistence</strong>: The identifier remains valid even if the resource location changes</li>\n<li><strong>Global resolution</strong>: Centralized system that resolves handles to their current locations</li>\n<li><strong>Location independence</strong>: Does not depend on URLs that may change over time</li>\n</ul>\n\n<h4>Handle structure</h4>\n<p>A handle consists of two parts separated by a forward slash:</p>\n<pre>prefix/suffix</pre>\n<ul>\n<li><strong>Prefix</strong>: Identifies the naming authority (institution or organization)</li>\n<li><strong>Suffix</strong>: Describes the local name of the resource</li>\n</ul>\n<p><strong>Example</strong>:</p>\n<pre>11577/3159842</pre>\n<p>In this example, <code>11577</code> identifies the institutional repository and <code>3159842</code> identifies the specific resource within that repository.</p>\n\n<h4>Relationship with DOI</h4>\n<p>The DOI (Digital Object Identifier) is actually a specialized implementation of the Handle System. Every DOI is a handle, but not every handle is a DOI. DOIs add:</p>\n<ul>\n<li>Additional structured metadata</li>\n<li>Specific social and governance infrastructure</li>\n<li>Centralized registration through agencies such as Crossref or DataCite</li>\n</ul>\n\n<h4>What is the handle used for?</h4>\n<p>In the context of scientific articles, the handle is used for:</p>\n<ul>\n<li><strong>Persistent citation</strong>: Ensuring that references remain valid long-term</li>\n<li><strong>Permanent access</strong>: Allowing the article to be located even if it changes servers or repositories</li>\n<li><strong>Repository identification</strong>: Especially common in institutional repositories using software like DSpace</li>\n<li><strong>Interoperability</strong>: Facilitating metadata exchange between systems</li>\n</ul>\n\n<h4>Input format</h4>\n<p>The field must contain the complete handle in <code>prefix/suffix</code> format.</p>\n<p><strong>Correct examples</strong>:</p>\n<p>Institutional repository handle:</p>\n<pre>11577/3159842</pre>\n<p>Digital archive handle:</p>\n<pre>2381/29652</pre>\n\n<h4>Differences from other persistent identifiers</h4>\n<table border=\"1\" cellpadding=\"5\" cellspacing=\"0\">\n<tr>\n<th>Identifier</th>\n<th>Main use</th>\n<th>Governance</th>\n</tr>\n<tr>\n<td><strong>Handle</strong></td>\n<td>Base infrastructure for persistent identification</td>\n<td>Handle.Net Registry</td>\n</tr>\n<tr>\n<td><strong>DOI</strong></td>\n<td>Academic publications, research data</td>\n<td>International DOI Foundation</td>\n</tr>\n<tr>\n<td><strong>ARK</strong></td>\n<td>Digital objects in libraries and archives</td>\n<td>California Digital Library</td>\n</tr>\n<tr>\n<td><strong>URN</strong></td>\n<td>Location-independent identification</td>\n<td>IETF</td>\n</tr>\n</table>\n\n<h4>Importance for academic journals</h4>\n<p>For scientific articles in institutional repositories or digital archive systems:</p>\n<ul>\n<li><strong>Digital preservation</strong>: Maintains long-term access to content</li>\n<li><strong>Traceability</strong>: Allows tracking of versions and changes</li>\n<li><strong>Regulatory compliance</strong>: Satisfies open access requirements in many institutions</li>\n<li><strong>CRIS integration</strong>: Facilitates integration with current research information systems</li>\n</ul>\n\n<h4>Use alongside DOI</h4>\n<p>It is common for an article to have both DOI and handle:</p>\n<ul>\n<li><strong>DOI</strong>: For standard academic citation</li>\n<li><strong>Handle</strong>: For access through the institutional repository</li>\n</ul>\n<p>Both identifiers can coexist and point to the same resource from different access points.</p>\n','elisa','2026-01-09 07:43:26','elisa','2026-01-09 08:16:50'),(77,'handle-system','handle_system','it','<!-- ITALIANO -->\n<h3>Cos\'è un handle?</h3>\n<p>Il campo <code>handle</code> contiene un identificatore persistente basato sul Handle System, un sistema di identificazione distribuito progettato per fornire nomi unici e permanenti per le risorse digitali su Internet.</p>\n\n<h4>Caratteristiche del Handle System</h4>\n<p>Il Handle System è un\'infrastruttura che fornisce:</p>\n<ul>\n<li><strong>Identificazione unica</strong>: Ogni handle identifica inequivocabilmente una singola risorsa digitale</li>\n<li><strong>Persistenza</strong>: L\'identificatore rimane valido anche se cambia la posizione della risorsa</li>\n<li><strong>Risoluzione globale</strong>: Sistema centralizzato che risolve gli handle alle loro posizioni attuali</li>\n<li><strong>Indipendenza dalla posizione</strong>: Non dipende da URL che possono cambiare nel tempo</li>\n</ul>\n\n<h4>Struttura di un handle</h4>\n<p>Un handle è composto da due parti separate da una barra:</p>\n<pre>prefisso/suffisso</pre>\n<ul>\n<li><strong>Prefisso</strong>: Identifica l\'autorità di denominazione (istituzione o organizzazione)</li>\n<li><strong>Suffisso</strong>: Descrive il nome locale della risorsa</li>\n</ul>\n<p><strong>Esempio</strong>:</p>\n<pre>11577/3159842</pre>\n<p>In questo esempio, <code>11577</code> identifica il repository istituzionale e <code>3159842</code> identifica la risorsa specifica all\'interno di quel repository.</p>\n\n<h4>Relazione con il DOI</h4>\n<p>Il DOI (Digital Object Identifier) è in realtà un\'implementazione specializzata del Handle System. Ogni DOI è un handle, ma non ogni handle è un DOI. I DOI aggiungono:</p>\n<ul>\n<li>Metadati strutturati aggiuntivi</li>\n<li>Infrastruttura sociale e di governance specifica</li>\n<li>Registrazione centralizzata attraverso agenzie come Crossref o DataCite</li>\n</ul>\n\n<h4>A cosa serve l\'handle?</h4>\n<p>Nel contesto di articoli scientifici, l\'handle è utilizzato per:</p>\n<ul>\n<li><strong>Citazione persistente</strong>: Garantire che i riferimenti rimangano validi a lungo termine</li>\n<li><strong>Accesso permanente</strong>: Permettere di localizzare l\'articolo anche se cambia server o repository</li>\n<li><strong>Identificazione nei repository</strong>: Particolarmente comune nei repository istituzionali che utilizzano software come DSpace</li>\n<li><strong>Interoperabilità</strong>: Facilitare lo scambio di metadati tra sistemi</li>\n</ul>\n\n<h4>Formato di inserimento</h4>\n<p>Il campo deve contenere l\'handle completo nel formato <code>prefisso/suffisso</code>.</p>\n<p><strong>Esempi corretti</strong>:</p>\n<p>Handle di un repository istituzionale:</p>\n<pre>11577/3159842</pre>\n<p>Handle di un archivio digitale:</p>\n<pre>2381/29652</pre>\n\n<h4>Differenze con altri identificatori persistenti</h4>\n<table border=\"1\" cellpadding=\"5\" cellspacing=\"0\">\n<tr>\n<th>Identificatore</th>\n<th>Uso principale</th>\n<th>Governance</th>\n</tr>\n<tr>\n<td><strong>Handle</strong></td>\n<td>Infrastruttura base per identificazione persistente</td>\n<td>Handle.Net Registry</td>\n</tr>\n<tr>\n<td><strong>DOI</strong></td>\n<td>Pubblicazioni accademiche, dati di ricerca</td>\n<td>International DOI Foundation</td>\n</tr>\n<tr>\n<td><strong>ARK</strong></td>\n<td>Oggetti digitali in biblioteche e archivi</td>\n<td>California Digital Library</td>\n</tr>\n<tr>\n<td><strong>URN</strong></td>\n<td>Identificazione indipendente dalla posizione</td>\n<td>IETF</td>\n</tr>\n</table>\n\n<h4>Importanza per le riviste accademiche</h4>\n<p>Per articoli scientifici in repository istituzionali o sistemi di archivio digitale:</p>\n<ul>\n<li><strong>Preservazione digitale</strong>: Mantiene l\'accesso al contenuto a lungo termine</li>\n<li><strong>Tracciabilità</strong>: Consente il monitoraggio di versioni e modifiche</li>\n<li><strong>Conformità normativa</strong>: Soddisfa i requisiti di accesso aperto in molte istituzioni</li>\n<li><strong>Integrazione CRIS</strong>: Facilita l\'integrazione con i sistemi informativi di ricerca attuali</li>\n</ul>\n\n<h4>Uso insieme al DOI</h4>\n<p>È comune che un articolo abbia sia DOI che handle:</p>\n<ul>\n<li><strong>DOI</strong>: Per la citazione accademica standard</li>\n<li><strong>Handle</strong>: Per l\'accesso attraverso il repository istituzionale</li>\n</ul>\n<p>Entrambi gli identificatori possono coesistere e puntare alla stessa risorsa da diversi punti di accesso.</p>\n','elisa','2026-01-09 07:43:26','elisa','2026-01-09 08:17:13'),(78,'handle-system','handle_system','fr','<!-- FRANCÉS -->\n<h3>Qu\'est-ce qu\'un handle?</h3>\n<p>Le champ <code>handle</code> contient un identifiant persistant basé sur le Handle System, un système d\'identification distribué conçu pour fournir des noms uniques et permanents aux ressources numériques sur Internet.</p>\n\n<h4>Caractéristiques du Handle System</h4>\n<p>Le Handle System est une infrastructure qui fournit:</p>\n<ul>\n<li><strong>Identification unique</strong>: Chaque handle identifie sans ambiguïté une seule ressource numérique</li>\n<li><strong>Persistance</strong>: L\'identifiant reste valide même si l\'emplacement de la ressource change</li>\n<li><strong>Résolution globale</strong>: Système centralisé qui résout les handles vers leurs emplacements actuels</li>\n<li><strong>Indépendance de localisation</strong>: Ne dépend pas des URL qui peuvent changer avec le temps</li>\n</ul>\n\n<h4>Structure d\'un handle</h4>\n<p>Un handle se compose de deux parties séparées par une barre oblique:</p>\n<pre>préfixe/suffixe</pre>\n<ul>\n<li><strong>Préfixe</strong>: Identifie l\'autorité de nommage (institution ou organisation)</li>\n<li><strong>Suffixe</strong>: Décrit le nom local de la ressource</li>\n</ul>\n<p><strong>Exemple</strong>:</p>\n<pre>11577/3159842</pre>\n<p>Dans cet exemple, <code>11577</code> identifie le dépôt institutionnel et <code>3159842</code> identifie la ressource spécifique au sein de ce dépôt.</p>\n\n<h4>Relation avec le DOI</h4>\n<p>Le DOI (Digital Object Identifier) est en réalité une implémentation spécialisée du Handle System. Tout DOI est un handle, mais tout handle n\'est pas un DOI. Les DOI ajoutent:</p>\n<ul>\n<li>Des métadonnées structurées supplémentaires</li>\n<li>Une infrastructure sociale et de gouvernance spécifique</li>\n<li>Un enregistrement centralisé via des agences comme Crossref ou DataCite</li>\n</ul>\n\n<h4>À quoi sert le handle?</h4>\n<p>Dans le contexte d\'articles scientifiques, le handle est utilisé pour:</p>\n<ul>\n<li><strong>Citation persistante</strong>: Garantir que les références restent valides à long terme</li>\n<li><strong>Accès permanent</strong>: Permettre de localiser l\'article même s\'il change de serveur ou de dépôt</li>\n<li><strong>Identification dans les dépôts</strong>: Particulièrement courant dans les dépôts institutionnels utilisant des logiciels comme DSpace</li>\n<li><strong>Interopérabilité</strong>: Faciliter l\'échange de métadonnées entre systèmes</li>\n</ul>\n\n<h4>Format de saisie</h4>\n<p>Le champ doit contenir le handle complet au format <code>préfixe/suffixe</code>.</p>\n<p><strong>Exemples corrects</strong>:</p>\n<p>Handle d\'un dépôt institutionnel:</p>\n<pre>11577/3159842</pre>\n<p>Handle d\'une archive numérique:</p>\n<pre>2381/29652</pre>\n\n<h4>Différences avec d\'autres identifiants persistants</h4>\n<table border=\"1\" cellpadding=\"5\" cellspacing=\"0\">\n<tr>\n<th>Identifiant</th>\n<th>Usage principal</th>\n<th>Gouvernance</th>\n</tr>\n<tr>\n<td><strong>Handle</strong></td>\n<td>Infrastructure de base pour l\'identification persistante</td>\n<td>Handle.Net Registry</td>\n</tr>\n<tr>\n<td><strong>DOI</strong></td>\n<td>Publications académiques, données de recherche</td>\n<td>International DOI Foundation</td>\n</tr>\n<tr>\n<td><strong>ARK</strong></td>\n<td>Objets numériques dans les bibliothèques et archives</td>\n<td>California Digital Library</td>\n</tr>\n<tr>\n<td><strong>URN</strong></td>\n<td>Identification indépendante de la localisation</td>\n<td>IETF</td>\n</tr>\n</table>\n\n<h4>Importance pour les revues académiques</h4>\n<p>Pour les articles scientifiques dans les dépôts institutionnels ou systèmes d\'archives numériques:</p>\n<ul>\n<li><strong>Préservation numérique</strong>: Maintient l\'accès au contenu à long terme</li>\n<li><strong>Traçabilité</strong>: Permet le suivi des versions et des changements</li>\n<li><strong>Conformité normative</strong>: Satisfait les exigences d\'accès ouvert dans de nombreuses institutions</li>\n<li><strong>Intégration CRIS</strong>: Facilite l\'intégration avec les systèmes d\'information de recherche actuels</li>\n</ul>\n\n<h4>Usage conjoint avec le DOI</h4>\n<p>Il est courant qu\'un article ait à la fois un DOI et un handle:</p>\n<ul>\n<li><strong>DOI</strong>: Pour la citation académique standard</li>\n<li><strong>Handle</strong>: Pour l\'accès via le dépôt institutionnel</li>\n</ul>\n<p>Les deux identifiants peuvent coexister et pointer vers la même ressource depuis différents points d\'accès.</p>\n','elisa','2026-01-09 07:43:26','elisa','2026-01-09 08:17:29'),(79,'handle-system','handle_system','de','<!-- ALEMÁN -->\n<h3>Was ist ein Handle?</h3>\n<p>Das Feld <code>handle</code> enthält einen persistenten Identifikator basierend auf dem Handle System, einem verteilten Identifikationssystem, das entwickelt wurde, um eindeutige und permanente Namen für digitale Ressourcen im Internet bereitzustellen.</p>\n\n<h4>Eigenschaften des Handle Systems</h4>\n<p>Das Handle System ist eine Infrastruktur, die Folgendes bietet:</p>\n<ul>\n<li><strong>Eindeutige Identifikation</strong>: Jeder Handle identifiziert eindeutig eine einzelne digitale Ressource</li>\n<li><strong>Persistenz</strong>: Der Identifikator bleibt gültig, auch wenn sich der Standort der Ressource ändert</li>\n<li><strong>Globale Auflösung</strong>: Zentralisiertes System, das Handles zu ihren aktuellen Standorten auflöst</li>\n<li><strong>Standortunabhängigkeit</strong>: Hängt nicht von URLs ab, die sich im Laufe der Zeit ändern können</li>\n</ul>\n\n<h4>Struktur eines Handles</h4>\n<p>Ein Handle besteht aus zwei Teilen, die durch einen Schrägstrich getrennt sind:</p>\n<pre>Präfix/Suffix</pre>\n<ul>\n<li><strong>Präfix</strong>: Identifiziert die Namensgebungsbehörde (Institution oder Organisation)</li>\n<li><strong>Suffix</strong>: Beschreibt den lokalen Namen der Ressource</li>\n</ul>\n<p><strong>Beispiel</strong>:</p>\n<pre>11577/3159842</pre>\n<p>In diesem Beispiel identifiziert <code>11577</code> das institutionelle Repository und <code>3159842</code> die spezifische Ressource innerhalb dieses Repositorys.</p>\n\n<h4>Beziehung zum DOI</h4>\n<p>Der DOI (Digital Object Identifier) ist tatsächlich eine spezialisierte Implementierung des Handle Systems. Jeder DOI ist ein Handle, aber nicht jeder Handle ist ein DOI. DOIs fügen hinzu:</p>\n<ul>\n<li>Zusätzliche strukturierte Metadaten</li>\n<li>Spezifische soziale und Governance-Infrastruktur</li>\n<li>Zentralisierte Registrierung über Agenturen wie Crossref oder DataCite</li>\n</ul>\n\n<h4>Wozu dient der Handle?</h4>\n<p>Im Kontext wissenschaftlicher Artikel wird der Handle verwendet für:</p>\n<ul>\n<li><strong>Persistente Zitation</strong>: Gewährleistung, dass Referenzen langfristig gültig bleiben</li>\n<li><strong>Permanenter Zugriff</strong>: Ermöglicht das Auffinden des Artikels, auch wenn er Server oder Repository wechselt</li>\n<li><strong>Repository-Identifikation</strong>: Besonders verbreitet in institutionellen Repositorien, die Software wie DSpace verwenden</li>\n<li><strong>Interoperabilität</strong>: Erleichtert den Metadatenaustausch zwischen Systemen</li>\n</ul>\n\n<h4>Eingabeformat</h4>\n<p>Das Feld muss den vollständigen Handle im Format <code>Präfix/Suffix</code> enthalten.</p>\n<p><strong>Korrekte Beispiele</strong>:</p>\n<p>Handle eines institutionellen Repositorys:</p>\n<pre>11577/3159842</pre>\n<p>Handle eines digitalen Archivs:</p>\n<pre>2381/29652</pre>\n\n<h4>Unterschiede zu anderen persistenten Identifikatoren</h4>\n<table border=\"1\" cellpadding=\"5\" cellspacing=\"0\">\n<tr>\n<th>Identifikator</th>\n<th>Hauptverwendung</th>\n<th>Governance</th>\n</tr>\n<tr>\n<td><strong>Handle</strong></td>\n<td>Basisinfrastruktur für persistente Identifikation</td>\n<td>Handle.Net Registry</td>\n</tr>\n<tr>\n<td><strong>DOI</strong></td>\n<td>Akademische Publikationen, Forschungsdaten</td>\n<td>International DOI Foundation</td>\n</tr>\n<tr>\n<td><strong>ARK</strong></td>\n<td>Digitale Objekte in Bibliotheken und Archiven</td>\n<td>California Digital Library</td>\n</tr>\n<tr>\n<td><strong>URN</strong></td>\n<td>Standortunabhängige Identifikation</td>\n<td>IETF</td>\n</tr>\n</table>\n\n<h4>Bedeutung für akademische Zeitschriften</h4>\n<p>Für wissenschaftliche Artikel in institutionellen Repositorien oder digitalen Archivsystemen:</p>\n<ul>\n<li><strong>Digitale Bewahrung</strong>: Erhält langfristigen Zugang zu Inhalten</li>\n<li><strong>Nachverfolgbarkeit</strong>: Ermöglicht Verfolgung von Versionen und Änderungen</li>\n<li><strong>Regulatorische Compliance</strong>: Erfüllt Open-Access-Anforderungen in vielen Institutionen</li>\n<li><strong>CRIS-Integration</strong>: Erleichtert die Integration mit aktuellen Forschungsinformationssystemen</li>\n</ul>\n\n<h4>Verwendung zusammen mit DOI</h4>\n<p>Es ist üblich, dass ein Artikel sowohl DOI als auch Handle hat:</p>\n<ul>\n<li><strong>DOI</strong>: Für die standardmäßige akademische Zitation</li>\n<li><strong>Handle</strong>: Für den Zugriff über das institutionelle Repository</li>\n</ul>\n<p>Beide Identifikatoren können koexistieren und von verschiedenen Zugangspunkten auf dieselbe Ressource verweisen.</p>','elisa','2026-01-09 07:43:26','elisa','2026-01-09 08:17:46'),(80,'arxiv-id','arxiv_id','es','<!-- ESPAÑOL -->\n<h3>¿Qué es arxiv-id?</h3>\n<p>El campo <code>arxiv-id</code> contiene el identificador único asignado por arXiv, el repositorio de preprints científicos más importante del mundo, especializado en física, matemáticas, ciencias de la computación, biología cuantitativa, finanzas cuantitativas, estadística, ingeniería eléctrica y ciencias de sistemas, y economía.</p>\n\n<h4>¿Qué es arXiv?</h4>\n<p>arXiv (pronunciado \"archive\") es un repositorio de acceso abierto operado por la Universidad Cornell que permite a investigadores compartir preprints (versiones preliminares) de artículos científicos antes de su publicación en revistas con revisión por pares.</p>\n\n<h4>Estructura del identificador arXiv</h4>\n<p>El formato del identificador ha cambiado a lo largo del tiempo:</p>\n<p><strong>Formato antiguo (antes de abril 2007)</strong>:</p>\n<pre>archivo/YYMMNNN</pre>\n<p>Ejemplo: <code>math/0703123</code></p>\n<p><strong>Formato nuevo (abril 2007 - diciembre 2014)</strong>:</p>\n<pre>YYMM.NNNN</pre>\n<p>Ejemplo: <code>0704.0001</code> (4 dígitos para el número de secuencia)</p>\n<p><strong>Formato actual (desde enero 2015)</strong>:</p>\n<pre>YYMM.NNNNN</pre>\n<p>Ejemplo: <code>1501.00001</code> (5 dígitos para el número de secuencia)</p>\n<p>Donde:</p>\n<ul>\n<li><strong>YY</strong>: Últimos dos dígitos del año</li>\n<li><strong>MM</strong>: Mes de envío (01-12)</li>\n<li><strong>NNNNN</strong>: Número de secuencia dentro del mes (con ceros a la izquierda)</li>\n</ul>\n\n<h4>Versiones de artículos</h4>\n<p>Los artículos en arXiv pueden tener múltiples versiones. Para referirse a una versión específica, se añade:</p>\n<pre>YYMM.NNNNNvN</pre>\n<p>Ejemplo: <code>2401.12345v2</code> (segunda versión del artículo)</p>\n<p>Sin el número de versión, el identificador se refiere siempre a la versión más reciente.</p>\n\n<h4>Formato de entrada</h4>\n<p>El campo debe contener el identificador arXiv completo, opcionalmente con el prefijo <code>arXiv:</code>.</p>\n<p><strong>Ejemplos correctos</strong>:</p>\n<p>Formato moderno:</p>\n<pre>2401.12345</pre>\n<p>Con prefijo (recomendado para citaciones):</p>\n<pre>arXiv:2401.12345</pre>\n<p>Con versión específica:</p>\n<pre>arXiv:2401.12345v1</pre>\n<p>Formato antiguo:</p>\n<pre>math/0703123</pre>\n\n<h4>Relación con DOI</h4>\n<p>A partir de enero de 2022, arXiv asigna automáticamente un DOI a cada artículo:</p>\n<ul>\n<li><strong>arXiv ID</strong>: <code>arXiv:2202.01037</code></li>\n<li><strong>DOI equivalente</strong>: <code>10.48550/arXiv.2202.01037</code></li>\n</ul>\n<p>Ambos identificadores pueden coexistir:</p>\n<ul>\n<li>El arXiv ID es el identificador nativo del repositorio</li>\n<li>El DOI facilita la interoperabilidad con otros sistemas</li>\n</ul>\n\n<h4>Categorías de arXiv</h4>\n<p>Cada artículo tiene una categoría principal. Algunas categorías principales incluyen:</p>\n<ul>\n<li><strong>physics</strong>: Física (varios subcampos)</li>\n<li><strong>math</strong>: Matemáticas</li>\n<li><strong>cs</strong>: Ciencias de la Computación</li>\n<li><strong>q-bio</strong>: Biología Cuantitativa</li>\n<li><strong>q-fin</strong>: Finanzas Cuantitativas</li>\n<li><strong>stat</strong>: Estadística</li>\n<li><strong>eess</strong>: Ingeniería Eléctrica y Ciencias de Sistemas</li>\n<li><strong>econ</strong>: Economía</li>\n</ul>\n\n<h4>¿Para qué sirve el arxiv-id?</h4>\n<p>En el contexto de metadatos de artículos científicos:</p>\n<ul>\n<li><strong>Citación de preprints</strong>: Permite citar trabajos antes de su publicación formal</li>\n<li><strong>Trazabilidad de versiones</strong>: Identifica inequívocamente cada versión de un manuscrito</li>\n<li><strong>Acceso abierto</strong>: Garantiza acceso libre y permanente al trabajo</li>\n<li><strong>Prioridad de descubrimiento</strong>: Establece fecha de publicación pública del preprint</li>\n<li><strong>Interoperabilidad</strong>: Facilita la conexión con otros sistemas bibliográficos</li>\n</ul>\n\n<h4>Importancia para la comunicación científica</h4>\n<p>El arXiv ID es especialmente relevante en:</p>\n<ul>\n<li><strong>Física y Matemáticas</strong>: Donde arXiv es el repositorio estándar de facto</li>\n<li><strong>Ciencias de la Computación</strong>: Para compartir resultados rápidamente</li>\n<li><strong>Publicación dual</strong>: Muchos artículos existen tanto en arXiv como en revistas con peer review</li>\n<li><strong>Acceso temprano</strong>: Permite a la comunidad científica acceder a resultados antes de la publicación formal</li>\n</ul>\n\n<h4>Uso junto con otros identificadores</h4>\n<p>Es común que un artículo tenga múltiples identificadores:</p>\n<ul>\n<li><strong>arXiv ID</strong>: Para la versión preprint</li>\n<li><strong>DOI de revista</strong>: Para la versión publicada con revisión por pares</li>\n<li><strong>DOI de arXiv</strong>: Asignado automáticamente por arXiv desde 2022</li>\n</ul>\n<p>Todos pueden coexistir y referenciar el mismo trabajo en diferentes etapas de publicación.</p>','elisa','2026-01-09 08:00:24','elisa','2026-01-09 08:00:24'),(81,'arxiv-id','arxiv_id','pt','<!-- PORTUGUÉS -->\n<h3>O que é arxiv-id?</h3>\n<p>O campo <code>arxiv-id</code> contém o identificador único atribuído pelo arXiv, o repositório de preprints científicos mais importante do mundo, especializado em física, matemática, ciências da computação, biologia quantitativa, finanças quantitativas, estatística, engenharia elétrica e ciências de sistemas, e economia.</p>\n\n<h4>O que é arXiv?</h4>\n<p>arXiv (pronunciado \"archive\") é um repositório de acesso aberto operado pela Universidade Cornell que permite aos pesquisadores compartilhar preprints (versões preliminares) de artigos científicos antes de sua publicação em revistas com revisão por pares.</p>\n\n<h4>Estrutura do identificador arXiv</h4>\n<p>O formato do identificador mudou ao longo do tempo:</p>\n<p><strong>Formato antigo (antes de abril 2007)</strong>:</p>\n<pre>arquivo/YYMMNNN</pre>\n<p>Exemplo: <code>math/0703123</code></p>\n<p><strong>Formato novo (abril 2007 - dezembro 2014)</strong>:</p>\n<pre>YYMM.NNNN</pre>\n<p>Exemplo: <code>0704.0001</code> (4 dígitos para o número de sequência)</p>\n<p><strong>Formato atual (desde janeiro 2015)</strong>:</p>\n<pre>YYMM.NNNNN</pre>\n<p>Exemplo: <code>1501.00001</code> (5 dígitos para o número de sequência)</p>\n<p>Onde:</p>\n<ul>\n<li><strong>YY</strong>: Últimos dois dígitos do ano</li>\n<li><strong>MM</strong>: Mês de envio (01-12)</li>\n<li><strong>NNNNN</strong>: Número de sequência dentro do mês (com zeros à esquerda)</li>\n</ul>\n\n<h4>Versões de artigos</h4>\n<p>Os artigos no arXiv podem ter múltiplas versões. Para se referir a uma versão específica, adiciona-se:</p>\n<pre>YYMM.NNNNNvN</pre>\n<p>Exemplo: <code>2401.12345v2</code> (segunda versão do artigo)</p>\n<p>Sem o número de versão, o identificador sempre se refere à versão mais recente.</p>\n\n<h4>Formato de entrada</h4>\n<p>O campo deve conter o identificador arXiv completo, opcionalmente com o prefixo <code>arXiv:</code>.</p>\n<p><strong>Exemplos corretos</strong>:</p>\n<p>Formato moderno:</p>\n<pre>2401.12345</pre>\n<p>Com prefixo (recomendado para citações):</p>\n<pre>arXiv:2401.12345</pre>\n<p>Com versão específica:</p>\n<pre>arXiv:2401.12345v1</pre>\n<p>Formato antigo:</p>\n<pre>math/0703123</pre>\n\n<h4>Relação com DOI</h4>\n<p>A partir de janeiro de 2022, o arXiv atribui automaticamente um DOI a cada artigo:</p>\n<ul>\n<li><strong>arXiv ID</strong>: <code>arXiv:2202.01037</code></li>\n<li><strong>DOI equivalente</strong>: <code>10.48550/arXiv.2202.01037</code></li>\n</ul>\n<p>Ambos os identificadores podem coexistir:</p>\n<ul>\n<li>O arXiv ID é o identificador nativo do repositório</li>\n<li>O DOI facilita a interoperabilidade com outros sistemas</li>\n</ul>\n\n<h4>Categorias do arXiv</h4>\n<p>Cada artigo tem uma categoria principal. Algumas categorias principais incluem:</p>\n<ul>\n<li><strong>physics</strong>: Física (vários subcampos)</li>\n<li><strong>math</strong>: Matemática</li>\n<li><strong>cs</strong>: Ciências da Computação</li>\n<li><strong>q-bio</strong>: Biologia Quantitativa</li>\n<li><strong>q-fin</strong>: Finanças Quantitativas</li>\n<li><strong>stat</strong>: Estatística</li>\n<li><strong>eess</strong>: Engenharia Elétrica e Ciências de Sistemas</li>\n<li><strong>econ</strong>: Economia</li>\n</ul>\n\n<h4>Para que serve o arxiv-id?</h4>\n<p>No contexto de metadados de artigos científicos:</p>\n<ul>\n<li><strong>Citação de preprints</strong>: Permite citar trabalhos antes de sua publicação formal</li>\n<li><strong>Rastreabilidade de versões</strong>: Identifica inequivocamente cada versão de um manuscrito</li>\n<li><strong>Acesso aberto</strong>: Garante acesso livre e permanente ao trabalho</li>\n<li><strong>Prioridade de descoberta</strong>: Estabelece data de publicação pública do preprint</li>\n<li><strong>Interoperabilidade</strong>: Facilita a conexão com outros sistemas bibliográficos</li>\n</ul>\n\n<h4>Importância para a comunicação científica</h4>\n<p>O arXiv ID é especialmente relevante em:</p>\n<ul>\n<li><strong>Física e Matemática</strong>: Onde o arXiv é o repositório padrão de facto</li>\n<li><strong>Ciências da Computação</strong>: Para compartilhar resultados rapidamente</li>\n<li><strong>Publicação dual</strong>: Muitos artigos existem tanto no arXiv quanto em revistas com peer review</li>\n<li><strong>Acesso antecipado</strong>: Permite à comunidade científica acessar resultados antes da publicação formal</li>\n</ul>\n\n<h4>Uso junto com outros identificadores</h4>\n<p>É comum que um artigo tenha múltiplos identificadores:</p>\n<ul>\n<li><strong>arXiv ID</strong>: Para a versão preprint</li>\n<li><strong>DOI de revista</strong>: Para a versão publicada com revisão por pares</li>\n<li><strong>DOI do arXiv</strong>: Atribuído automaticamente pelo arXiv desde 2022</li>\n</ul>\n<p>Todos podem coexistir e referenciar o mesmo trabalho em diferentes etapas de publicação.</p>\n','elisa','2026-01-09 08:00:24','elisa','2026-01-09 08:00:24'),(82,'arxiv-id','arxiv_id','en','<!-- INGLÉS -->\n<h3>What is arxiv-id?</h3>\n<p>The <code>arxiv-id</code> field contains the unique identifier assigned by arXiv, the world\'s most important scientific preprint repository, specializing in physics, mathematics, computer science, quantitative biology, quantitative finance, statistics, electrical engineering and systems science, and economics.</p>\n\n<h4>What is arXiv?</h4>\n<p>arXiv (pronounced \"archive\") is an open access repository operated by Cornell University that allows researchers to share preprints (preliminary versions) of scientific articles before their publication in peer-reviewed journals.</p>\n\n<h4>arXiv identifier structure</h4>\n<p>The identifier format has changed over time:</p>\n<p><strong>Old format (before April 2007)</strong>:</p>\n<pre>archive/YYMMNNN</pre>\n<p>Example: <code>math/0703123</code></p>\n<p><strong>New format (April 2007 - December 2014)</strong>:</p>\n<pre>YYMM.NNNN</pre>\n<p>Example: <code>0704.0001</code> (4 digits for sequence number)</p>\n<p><strong>Current format (since January 2015)</strong>:</p>\n<pre>YYMM.NNNNN</pre>\n<p>Example: <code>1501.00001</code> (5 digits for sequence number)</p>\n<p>Where:</p>\n<ul>\n<li><strong>YY</strong>: Last two digits of the year</li>\n<li><strong>MM</strong>: Submission month (01-12)</li>\n<li><strong>NNNNN</strong>: Sequence number within the month (zero-padded)</li>\n</ul>\n\n<h4>Article versions</h4>\n<p>Articles in arXiv can have multiple versions. To refer to a specific version, add:</p>\n<pre>YYMM.NNNNNvN</pre>\n<p>Example: <code>2401.12345v2</code> (second version of the article)</p>\n<p>Without the version number, the identifier always refers to the most recent version.</p>\n\n<h4>Input format</h4>\n<p>The field must contain the complete arXiv identifier, optionally with the <code>arXiv:</code> prefix.</p>\n<p><strong>Correct examples</strong>:</p>\n<p>Modern format:</p>\n<pre>2401.12345</pre>\n<p>With prefix (recommended for citations):</p>\n<pre>arXiv:2401.12345</pre>\n<p>With specific version:</p>\n<pre>arXiv:2401.12345v1</pre>\n<p>Old format:</p>\n<pre>math/0703123</pre>\n\n<h4>Relationship with DOI</h4>\n<p>Since January 2022, arXiv automatically assigns a DOI to each article:</p>\n<ul>\n<li><strong>arXiv ID</strong>: <code>arXiv:2202.01037</code></li>\n<li><strong>Equivalent DOI</strong>: <code>10.48550/arXiv.2202.01037</code></li>\n</ul>\n<p>Both identifiers can coexist:</p>\n<ul>\n<li>The arXiv ID is the repository\'s native identifier</li>\n<li>The DOI facilitates interoperability with other systems</li>\n</ul>\n\n<h4>arXiv categories</h4>\n<p>Each article has a primary category. Some main categories include:</p>\n<ul>\n<li><strong>physics</strong>: Physics (various subfields)</li>\n<li><strong>math</strong>: Mathematics</li>\n<li><strong>cs</strong>: Computer Science</li>\n<li><strong>q-bio</strong>: Quantitative Biology</li>\n<li><strong>q-fin</strong>: Quantitative Finance</li>\n<li><strong>stat</strong>: Statistics</li>\n<li><strong>eess</strong>: Electrical Engineering and Systems Science</li>\n<li><strong>econ</strong>: Economics</li>\n</ul>\n\n<h4>What is arxiv-id used for?</h4>\n<p>In the context of scientific article metadata:</p>\n<ul>\n<li><strong>Preprint citation</strong>: Allows citing works before formal publication</li>\n<li><strong>Version traceability</strong>: Unambiguously identifies each version of a manuscript</li>\n<li><strong>Open access</strong>: Guarantees free and permanent access to the work</li>\n<li><strong>Discovery priority</strong>: Establishes public publication date of the preprint</li>\n<li><strong>Interoperability</strong>: Facilitates connection with other bibliographic systems</li>\n</ul>\n\n<h4>Importance for scientific communication</h4>\n<p>The arXiv ID is especially relevant in:</p>\n<ul>\n<li><strong>Physics and Mathematics</strong>: Where arXiv is the de facto standard repository</li>\n<li><strong>Computer Science</strong>: For quickly sharing results</li>\n<li><strong>Dual publication</strong>: Many articles exist both in arXiv and in peer-reviewed journals</li>\n<li><strong>Early access</strong>: Allows the scientific community to access results before formal publication</li>\n</ul>\n\n<h4>Use alongside other identifiers</h4>\n<p>It is common for an article to have multiple identifiers:</p>\n<ul>\n<li><strong>arXiv ID</strong>: For the preprint version</li>\n<li><strong>Journal DOI</strong>: For the peer-reviewed published version</li>\n<li><strong>arXiv DOI</strong>: Automatically assigned by arXiv since 2022</li>\n</ul>\n<p>All can coexist and reference the same work at different publication stages.</p>\n','elisa','2026-01-09 08:00:24','elisa','2026-01-09 08:00:24'),(83,'arxiv-id','arxiv_id','it','<!-- ITALIANO -->\n<h3>Cos\'è arxiv-id?</h3>\n<p>Il campo <code>arxiv-id</code> contiene l\'identificatore unico assegnato da arXiv, il più importante repository di preprint scientifici al mondo, specializzato in fisica, matematica, informatica, biologia quantitativa, finanza quantitativa, statistica, ingegneria elettrica e scienze dei sistemi, ed economia.</p>\n\n<h4>Cos\'è arXiv?</h4>\n<p>arXiv (pronunciato \"archive\") è un repository ad accesso aperto gestito dalla Cornell University che permette ai ricercatori di condividere preprint (versioni preliminari) di articoli scientifici prima della loro pubblicazione in riviste con peer review.</p>\n\n<h4>Struttura dell\'identificatore arXiv</h4>\n<p>Il formato dell\'identificatore è cambiato nel tempo:</p>\n<p><strong>Formato vecchio (prima di aprile 2007)</strong>:</p>\n<pre>archivio/YYMMNNN</pre>\n<p>Esempio: <code>math/0703123</code></p>\n<p><strong>Formato nuovo (aprile 2007 - dicembre 2014)</strong>:</p>\n<pre>YYMM.NNNN</pre>\n<p>Esempio: <code>0704.0001</code> (4 cifre per il numero di sequenza)</p>\n<p><strong>Formato attuale (da gennaio 2015)</strong>:</p>\n<pre>YYMM.NNNNN</pre>\n<p>Esempio: <code>1501.00001</code> (5 cifre per il numero di sequenza)</p>\n<p>Dove:</p>\n<ul>\n<li><strong>YY</strong>: Ultime due cifre dell\'anno</li>\n<li><strong>MM</strong>: Mese di invio (01-12)</li>\n<li><strong>NNNNN</strong>: Numero di sequenza nel mese (con zeri iniziali)</li>\n</ul>\n\n<h4>Versioni degli articoli</h4>\n<p>Gli articoli in arXiv possono avere più versioni. Per riferirsi a una versione specifica, si aggiunge:</p>\n<pre>YYMM.NNNNNvN</pre>\n<p>Esempio: <code>2401.12345v2</code> (seconda versione dell\'articolo)</p>\n<p>Senza il numero di versione, l\'identificatore si riferisce sempre alla versione più recente.</p>\n\n<h4>Formato di inserimento</h4>\n<p>Il campo deve contenere l\'identificatore arXiv completo, opzionalmente con il prefisso <code>arXiv:</code>.</p>\n<p><strong>Esempi corretti</strong>:</p>\n<p>Formato moderno:</p>\n<pre>2401.12345</pre>\n<p>Con prefisso (consigliato per le citazioni):</p>\n<pre>arXiv:2401.12345</pre>\n<p>Con versione specifica:</p>\n<pre>arXiv:2401.12345v1</pre>\n<p>Formato vecchio:</p>\n<pre>math/0703123</pre>\n\n<h4>Relazione con il DOI</h4>\n<p>Da gennaio 2022, arXiv assegna automaticamente un DOI a ogni articolo:</p>\n<ul>\n<li><strong>arXiv ID</strong>: <code>arXiv:2202.01037</code></li>\n<li><strong>DOI equivalente</strong>: <code>10.48550/arXiv.2202.01037</code></li>\n</ul>\n<p>Entrambi gli identificatori possono coesistere:</p>\n<ul>\n<li>L\'arXiv ID è l\'identificatore nativo del repository</li>\n<li>Il DOI facilita l\'interoperabilità con altri sistemi</li>\n</ul>\n\n<h4>Categorie di arXiv</h4>\n<p>Ogni articolo ha una categoria principale. Alcune categorie principali includono:</p>\n<ul>\n<li><strong>physics</strong>: Fisica (vari sottocampi)</li>\n<li><strong>math</strong>: Matematica</li>\n<li><strong>cs</strong>: Informatica</li>\n<li><strong>q-bio</strong>: Biologia Quantitativa</li>\n<li><strong>q-fin</strong>: Finanza Quantitativa</li>\n<li><strong>stat</strong>: Statistica</li>\n<li><strong>eess</strong>: Ingegneria Elettrica e Scienze dei Sistemi</li>\n<li><strong>econ</strong>: Economia</li>\n</ul>\n\n<h4>A cosa serve l\'arxiv-id?</h4>\n<p>Nel contesto dei metadati di articoli scientifici:</p>\n<ul>\n<li><strong>Citazione di preprint</strong>: Permette di citare lavori prima della pubblicazione formale</li>\n<li><strong>Tracciabilità delle versioni</strong>: Identifica inequivocabilmente ogni versione di un manoscritto</li>\n<li><strong>Accesso aperto</strong>: Garantisce accesso libero e permanente al lavoro</li>\n<li><strong>Priorità di scoperta</strong>: Stabilisce la data di pubblicazione pubblica del preprint</li>\n<li><strong>Interoperabilità</strong>: Facilita la connessione con altri sistemi bibliografici</li>\n</ul>\n\n<h4>Importanza per la comunicazione scientifica</h4>\n<p>L\'arXiv ID è particolarmente rilevante in:</p>\n<ul>\n<li><strong>Fisica e Matematica</strong>: Dove arXiv è il repository standard de facto</li>\n<li><strong>Informatica</strong>: Per condividere rapidamente i risultati</li>\n<li><strong>Pubblicazione doppia</strong>: Molti articoli esistono sia in arXiv che in riviste con peer review</li>\n<li><strong>Accesso anticipato</strong>: Permette alla comunità scientifica di accedere ai risultati prima della pubblicazione formale</li>\n</ul>\n\n<h4>Uso insieme ad altri identificatori</h4>\n<p>È comune che un articolo abbia più identificatori:</p>\n<ul>\n<li><strong>arXiv ID</strong>: Per la versione preprint</li>\n<li><strong>DOI di rivista</strong>: Per la versione pubblicata con peer review</li>\n<li><strong>DOI di arXiv</strong>: Assegnato automaticamente da arXiv dal 2022</li>\n</ul>\n<p>Tutti possono coesistere e riferirsi allo stesso lavoro in diverse fasi di pubblicazione.</p>\n','elisa','2026-01-09 08:00:24','elisa','2026-01-09 08:00:24'),(84,'arxiv-id','arxiv_id','fr','<!-- FRANCÉS -->\n<h3>Qu\'est-ce que arxiv-id?</h3>\n<p>Le champ <code>arxiv-id</code> contient l\'identifiant unique attribué par arXiv, le dépôt de preprints scientifiques le plus important au monde, spécialisé en physique, mathématiques, informatique, biologie quantitative, finance quantitative, statistiques, ingénierie électrique et sciences des systèmes, et économie.</p>\n\n<h4>Qu\'est-ce qu\'arXiv?</h4>\n<p>arXiv (prononcé \"archive\") est un dépôt en libre accès géré par l\'Université Cornell qui permet aux chercheurs de partager des preprints (versions préliminaires) d\'articles scientifiques avant leur publication dans des revues à comité de lecture.</p>\n\n<h4>Structure de l\'identifiant arXiv</h4>\n<p>Le format de l\'identifiant a changé au fil du temps:</p>\n<p><strong>Ancien format (avant avril 2007)</strong>:</p>\n<pre>archive/YYMMNNN</pre>\n<p>Exemple: <code>math/0703123</code></p>\n<p><strong>Nouveau format (avril 2007 - décembre 2014)</strong>:</p>\n<pre>YYMM.NNNN</pre>\n<p>Exemple: <code>0704.0001</code> (4 chiffres pour le numéro de séquence)</p>\n<p><strong>Format actuel (depuis janvier 2015)</strong>:</p>\n<pre>YYMM.NNNNN</pre>\n<p>Exemple: <code>1501.00001</code> (5 chiffres pour le numéro de séquence)</p>\n<p>Où:</p>\n<ul>\n<li><strong>YY</strong>: Deux derniers chiffres de l\'année</li>\n<li><strong>MM</strong>: Mois de soumission (01-12)</li>\n<li><strong>NNNNN</strong>: Numéro de séquence dans le mois (complété par des zéros)</li>\n</ul>\n\n<h4>Versions d\'articles</h4>\n<p>Les articles dans arXiv peuvent avoir plusieurs versions. Pour faire référence à une version spécifique, on ajoute:</p>\n<pre>YYMM.NNNNNvN</pre>\n<p>Exemple: <code>2401.12345v2</code> (deuxième version de l\'article)</p>\n<p>Sans le numéro de version, l\'identifiant se réfère toujours à la version la plus récente.</p>\n\n<h4>Format de saisie</h4>\n<p>Le champ doit contenir l\'identifiant arXiv complet, optionnellement avec le préfixe <code>arXiv:</code>.</p>\n<p><strong>Exemples corrects</strong>:</p>\n<p>Format moderne:</p>\n<pre>2401.12345</pre>\n<p>Avec préfixe (recommandé pour les citations):</p>\n<pre>arXiv:2401.12345</pre>\n<p>Avec version spécifique:</p>\n<pre>arXiv:2401.12345v1</pre>\n<p>Format ancien:</p>\n<pre>math/0703123</pre>\n\n<h4>Relation avec le DOI</h4>\n<p>Depuis janvier 2022, arXiv attribue automatiquement un DOI à chaque article:</p>\n<ul>\n<li><strong>arXiv ID</strong>: <code>arXiv:2202.01037</code></li>\n<li><strong>DOI équivalent</strong>: <code>10.48550/arXiv.2202.01037</code></li>\n</ul>\n<p>Les deux identifiants peuvent coexister:</p>\n<ul>\n<li>L\'arXiv ID est l\'identifiant natif du dépôt</li>\n<li>Le DOI facilite l\'interopérabilité avec d\'autres systèmes</li>\n</ul>\n\n<h4>Catégories d\'arXiv</h4>\n<p>Chaque article a une catégorie principale. Quelques catégories principales incluent:</p>\n<ul>\n<li><strong>physics</strong>: Physique (plusieurs sous-domaines)</li>\n<li><strong>math</strong>: Mathématiques</li>\n<li><strong>cs</strong>: Informatique</li>\n<li><strong>q-bio</strong>: Biologie Quantitative</li>\n<li><strong>q-fin</strong>: Finance Quantitative</li>\n<li><strong>stat</strong>: Statistiques</li>\n<li><strong>eess</strong>: Ingénierie Électrique et Sciences des Systèmes</li>\n<li><strong>econ</strong>: Économie</li>\n</ul>\n\n<h4>À quoi sert l\'arxiv-id?</h4>\n<p>Dans le contexte des métadonnées d\'articles scientifiques:</p>\n<ul>\n<li><strong>Citation de preprints</strong>: Permet de citer des travaux avant leur publication formelle</li>\n<li><strong>Traçabilité des versions</strong>: Identifie sans ambiguïté chaque version d\'un manuscrit</li>\n<li><strong>Accès ouvert</strong>: Garantit un accès libre et permanent au travail</li>\n<li><strong>Priorité de découverte</strong>: Établit la date de publication publique du preprint</li>\n<li><strong>Interopérabilité</strong>: Facilite la connexion avec d\'autres systèmes bibliographiques</li>\n</ul>\n\n<h4>Importance pour la communication scientifique</h4>\n<p>L\'arXiv ID est particulièrement pertinent dans:</p>\n<ul>\n<li><strong>Physique et Mathématiques</strong>: Où arXiv est le dépôt standard de facto</li>\n<li><strong>Informatique</strong>: Pour partager rapidement les résultats</li>\n<li><strong>Publication double</strong>: De nombreux articles existent à la fois dans arXiv et dans des revues à comité de lecture</li>\n<li><strong>Accès anticipé</strong>: Permet à la communauté scientifique d\'accéder aux résultats avant la publication formelle</li>\n</ul>\n\n<h4>Utilisation avec d\'autres identifiants</h4>\n<p>Il est courant qu\'un article ait plusieurs identifiants:</p>\n<ul>\n<li><strong>arXiv ID</strong>: Pour la version preprint</li>\n<li><strong>DOI de revue</strong>: Pour la version publiée avec révision par les pairs</li>\n<li><strong>DOI d\'arXiv</strong>: Attribué automatiquement par arXiv depuis 2022</li>\n</ul>\n<p>Tous peuvent coexister et référencer le même travail à différentes étapes de publication.</p>\n','elisa','2026-01-09 08:00:24','elisa','2026-01-09 08:00:24'),(85,'arxiv-id','arxiv_id','de','<!-- ALEMÁN -->\n<h3>Was ist arxiv-id?</h3>\n<p>Das Feld <code>arxiv-id</code> enthält die eindeutige Kennung, die von arXiv vergeben wird, dem weltweit wichtigsten wissenschaftlichen Preprint-Repository, spezialisiert auf Physik, Mathematik, Informatik, quantitative Biologie, quantitative Finanzen, Statistik, Elektrotechnik und Systemwissenschaften sowie Wirtschaft.</p>\n\n<h4>Was ist arXiv?</h4>\n<p>arXiv (ausgesprochen \"archive\") ist ein Open-Access-Repository, das von der Cornell University betrieben wird und es Forschern ermöglicht, Preprints (Vorabversionen) wissenschaftlicher Artikel vor ihrer Veröffentlichung in begutachteten Zeitschriften zu teilen.</p>\n\n<h4>Struktur der arXiv-Kennung</h4>\n<p>Das Format der Kennung hat sich im Laufe der Zeit geändert:</p>\n<p><strong>Altes Format (vor April 2007)</strong>:</p>\n<pre>archiv/YYMMNNN</pre>\n<p>Beispiel: <code>math/0703123</code></p>\n<p><strong>Neues Format (April 2007 - Dezember 2014)</strong>:</p>\n<pre>YYMM.NNNN</pre>\n<p>Beispiel: <code>0704.0001</code> (4 Ziffern für die Sequenznummer)</p>\n<p><strong>Aktuelles Format (seit Januar 2015)</strong>:</p>\n<pre>YYMM.NNNNN</pre>\n<p>Beispiel: <code>1501.00001</code> (5 Ziffern für die Sequenznummer)</p>\n<p>Wobei:</p>\n<ul>\n<li><strong>YY</strong>: Letzte zwei Ziffern des Jahres</li>\n<li><strong>MM</strong>: Einreichungsmonat (01-12)</li>\n<li><strong>NNNNN</strong>: Sequenznummer innerhalb des Monats (mit führenden Nullen)</li>\n</ul>\n\n<h4>Artikelversionen</h4>\n<p>Artikel in arXiv können mehrere Versionen haben. Um auf eine bestimmte Version zu verweisen, wird hinzugefügt:</p>\n<pre>YYMM.NNNNNvN</pre>\n<p>Beispiel: <code>2401.12345v2</code> (zweite Version des Artikels)</p>\n<p>Ohne Versionsnummer bezieht sich die Kennung immer auf die neueste Version.</p>\n\n<h4>Eingabeformat</h4>\n<p>Das Feld muss die vollständige arXiv-Kennung enthalten, optional mit dem Präfix <code>arXiv:</code>.</p>\n<p><strong>Korrekte Beispiele</strong>:</p>\n<p>Modernes Format:</p>\n<pre>2401.12345</pre>\n<p>Mit Präfix (empfohlen für Zitationen):</p>\n<pre>arXiv:2401.12345</pre>\n<p>Mit spezifischer Version:</p>\n<pre>arXiv:2401.12345v1</pre>\n<p>Altes Format:</p>\n<pre>math/0703123</pre>\n\n<h4>Beziehung zum DOI</h4>\n<p>Seit Januar 2022 weist arXiv jedem Artikel automatisch einen DOI zu:</p>\n<ul>\n<li><strong>arXiv ID</strong>: <code>arXiv:2202.01037</code></li>\n<li><strong>Äquivalenter DOI</strong>: <code>10.48550/arXiv.2202.01037</code></li>\n</ul>\n<p>Beide Identifikatoren können koexistieren:</p>\n<ul>\n<li>Die arXiv ID ist der native Identifikator des Repositorys</li>\n<li>Der DOI erleichtert die Interoperabilität mit anderen Systemen</li>\n</ul>\n\n<h4>arXiv-Kategorien</h4>\n<p>Jeder Artikel hat eine Hauptkategorie. Einige Hauptkategorien umfassen:</p>\n<ul>\n<li><strong>physics</strong>: Physik (verschiedene Teilgebiete)</li>\n<li><strong>math</strong>: Mathematik</li>\n<li><strong>cs</strong>: Informatik</li>\n<li><strong>q-bio</strong>: Quantitative Biologie</li>\n<li><strong>q-fin</strong>: Quantitative Finanzen</li>\n<li><strong>stat</strong>: Statistik</li>\n<li><strong>eess</strong>: Elektrotechnik und Systemwissenschaften</li>\n<li><strong>econ</strong>: Wirtschaft</li>\n</ul>\n\n<h4>Wozu dient die arxiv-id?</h4>\n<p>Im Kontext wissenschaftlicher Artikelmetadaten:</p>\n<ul>\n<li><strong>Preprint-Zitation</strong>: Ermöglicht das Zitieren von Arbeiten vor formeller Veröffentlichung</li>\n<li><strong>Versionsverfolgung</strong>: Identifiziert eindeutig jede Version eines Manuskripts</li>\n<li><strong>Offener Zugang</strong>: Garantiert freien und permanenten Zugang zur Arbeit</li>\n<li><strong>Entdeckungspriorität</strong>: Legt das öffentliche Veröffentlichungsdatum des Preprints fest</li>\n<li><strong>Interoperabilität</strong>: Erleichtert die Verbindung mit anderen bibliographischen Systemen</li>\n</ul>\n\n<h4>Bedeutung für die wissenschaftliche Kommunikation</h4>\n<p>Die arXiv ID ist besonders relevant in:</p>\n<ul>\n<li><strong>Physik und Mathematik</strong>: Wo arXiv das De-facto-Standard-Repository ist</li>\n<li><strong>Informatik</strong>: Zum schnellen Teilen von Ergebnissen</li>\n<li><strong>Doppelveröffentlichung</strong>: Viele Artikel existieren sowohl in arXiv als auch in begutachteten Zeitschriften</li>\n<li><strong>Früher Zugang</strong>: Ermöglicht der wissenschaftlichen Gemeinschaft Zugang zu Ergebnissen vor formeller Veröffentlichung</li>\n</ul>\n\n<h4>Verwendung zusammen mit anderen Identifikatoren</h4>\n<p>Es ist üblich, dass ein Artikel mehrere Identifikatoren hat:</p>\n<ul>\n<li><strong>arXiv ID</strong>: Für die Preprint-Version</li>\n<li><strong>Journal DOI</strong>: Für die begutachtete veröffentlichte Version</li>\n<li><strong>arXiv DOI</strong>: Automatisch von arXiv seit 2022 zugewiesen</li>\n</ul>\n<p>Alle können koexistieren und auf dieselbe Arbeit in verschiedenen Veröffentlichungsphasen verweisen.</p>','elisa','2026-01-09 08:00:24','elisa','2026-01-09 08:00:24'),(86,'tipo-sujetos-investigación','tipo_sujetos_investigacion','es','<!-- ESPAÑOL -->\n<h3>¿Qué es el tipo de sujeto de investigación?</h3>\n<p>El campo <code>tipo-sujeto-investigacion</code> es un <strong>metadato de clasificación</strong> que especifica de manera general la naturaleza de los sujetos utilizados en el estudio científico. Este campo sirve para indexación, búsquedas y filtrado rápido de artículos, <strong>no reemplaza la descripción detallada</strong> que debe aparecer en la sección de Metodología del artículo.</p>\n\n<h4>Diferencia con otros campos</h4>\n<p><strong>Este campo es para clasificación general</strong>:</p>\n<ul>\n<li>Propósito: Indexación, filtrado, búsquedas en bases de datos</li>\n<li>Contenido: Categoría amplia (Humanos / Animales / In vitro)</li>\n<li>Ubicación: Metadatos del artículo</li>\n</ul>\n<p><strong>La información detallada va en otros campos</strong>:</p>\n<ul>\n<li>Especies exactas, cepas, edades → Sección \"Materiales y Métodos\"</li>\n<li>Aprobaciones éticas → Campo \"Declaraciones éticas\" o \"Ethics statements\"</li>\n<li>Número de sujetos, criterios de inclusión → Sección \"Métodos\"</li>\n<li>Condiciones experimentales → Sección \"Procedimientos\"</li>\n</ul>\n\n<h4>Categorías principales</h4>\n<p>Este campo típicamente acepta valores de una lista controlada:</p>\n<p><strong>Valores comunes</strong>:</p>\n<ul>\n<li><strong>Humanos</strong></li>\n<li><strong>Animales</strong></li>\n<li><strong>In vitro</strong></li>\n<li><strong>In silico</strong> (modelos computacionales)</li>\n<li><strong>Ex vivo</strong> (tejidos fuera del organismo)</li>\n<li><strong>Mixto</strong> (combinación de tipos)</li>\n<li><strong>No aplica</strong> (estudios teóricos, revisiones)</li>\n</ul>\n\n<h4>¿Para qué sirve este campo?</h4>\n<p><strong>Funciones principales</strong>:</p>\n<ol>\n<li><strong>Filtrado de búsquedas</strong>: Permite a investigadores buscar solo estudios con humanos, o solo con modelos animales</li>\n<li><strong>Cumplimiento normativo</strong>: Bases de datos pueden requerir esta clasificación</li>\n<li><strong>Análisis bibliométricos</strong>: Facilita estadísticas sobre tipos de estudios publicados</li>\n<li><strong>Indexación automática</strong>: Sistemas automatizados categorizan el artículo</li>\n<li><strong>Alertas y notificaciones</strong>: Usuarios pueden suscribirse a tipos específicos de estudios</li>\n</ol>\n\n<h4>Formato de entrada</h4>\n<p>El campo generalmente acepta <strong>valores únicos o múltiples</strong> de una lista predefinida.</p>\n<p><strong>Ejemplos correctos</strong>:</p>\n<p>Estudio con sujetos humanos:</p>\n<pre>Humanos</pre>\n<p>Estudio con animales:</p>\n<pre>Animales</pre>\n<p>Estudio con cultivos celulares:</p>\n<pre>In vitro</pre>\n<p>Estudio combinado:</p>\n<pre>Animales; In vitro</pre>\n\n<h4>Relación con otros metadatos</h4>\n<p>Este campo se complementa con:</p>\n<ul>\n<li><strong>Tipo de estudio</strong>: Observacional, experimental, revisión sistemática</li>\n<li><strong>Área temática</strong>: Biomedicina, farmacología, toxicología</li>\n<li><strong>Palabras clave</strong>: Detalles específicos del modelo utilizado</li>\n<li><strong>Resumen/Abstract</strong>: Descripción metodológica breve</li>\n<li><strong>Metodología completa</strong>: Descripción exhaustiva en el texto del artículo</li>\n</ul>\n\n<h4>Importancia para bases de datos</h4>\n<p>Las bases de datos académicas utilizan este campo para:</p>\n<ul>\n<li><strong>PubMed</strong>: Filtro \"Species\" permite buscar por tipo de sujeto</li>\n<li><strong>Scopus</strong>: Clasificación de estudios preclínicos vs clínicos</li>\n<li><strong>Web of Science</strong>: Refinamiento de resultados por metodología</li>\n<li><strong>SciELO</strong>: Categorización de artículos biomédicos</li>\n</ul>\n\n<h4>Nota importante</h4>\n<p><strong>Este campo NO contiene ni reemplaza</strong>:</p>\n<ul>\n<li>Detalles de las especies o cepas utilizadas</li>\n<li>Número de sujetos o tamaño muestral</li>\n<li>Procedimientos experimentales específicos</li>\n<li>Declaraciones de aprobación ética</li>\n<li>Protocolos de manejo de sujetos</li>\n</ul>\n<p>Toda esa información detallada debe estar en las secciones correspondientes del artículo completo.</p>\n','franco','2026-01-09 08:35:02','franco','2026-01-09 08:35:02'),(87,'tipo-sujetos-investigación','tipo_sujetos_investigacion','pt','<!-- PORTUGUÉS -->\n<h3>O que é o tipo de sujeito de pesquisa?</h3>\n<p>O campo <code>tipo-sujeto-investigacion</code> é um <strong>metadado de classificação</strong> que especifica de maneira geral a natureza dos sujeitos utilizados no estudo científico. Este campo serve para indexação, buscas e filtragem rápida de artigos; <strong>não substitui a descrição detalhada</strong> que deve aparecer na seção de Metodologia do artigo.</p>\n\n<h4>Diferença com outros campos</h4>\n<p><strong>Este campo é para classificação geral</strong>:</p>\n<ul>\n<li>Propósito: Indexação, filtragem, buscas em bases de dados</li>\n<li>Conteúdo: Categoria ampla (Humanos / Animais / In vitro)</li>\n<li>Localização: Metadados do artigo</li>\n</ul>\n<p><strong>A informação detalhada vai em outros campos</strong>:</p>\n<ul>\n<li>Espécies exatas, linhagens, idades → Seção \"Materiais e Métodos\"</li>\n<li>Aprovações éticas → Campo \"Declarações éticas\" ou \"Ethics statements\"</li>\n<li>Número de sujeitos, critérios de inclusão → Seção \"Métodos\"</li>\n<li>Condições experimentais → Seção \"Procedimentos\"</li>\n</ul>\n\n<h4>Categorias principais</h4>\n<p>Este campo tipicamente aceita valores de uma lista controlada:</p>\n<p><strong>Valores comuns</strong>:</p>\n<ul>\n<li><strong>Humanos</strong></li>\n<li><strong>Animais</strong></li>\n<li><strong>In vitro</strong></li>\n<li><strong>In silico</strong> (modelos computacionais)</li>\n<li><strong>Ex vivo</strong> (tecidos fora do organismo)</li>\n<li><strong>Misto</strong> (combinação de tipos)</li>\n<li><strong>Não se aplica</strong> (estudos teóricos, revisões)</li>\n</ul>\n\n<h4>Para que serve este campo?</h4>\n<p><strong>Funções principais</strong>:</p>\n<ol>\n<li><strong>Filtragem de buscas</strong>: Permite aos pesquisadores buscar apenas estudos com humanos, ou apenas com modelos animais</li>\n<li><strong>Cumprimento normativo</strong>: Bases de dados podem requerer esta classificação</li>\n<li><strong>Análises bibliométricas</strong>: Facilita estatísticas sobre tipos de estudos publicados</li>\n<li><strong>Indexação automática</strong>: Sistemas automatizados categorizam o artigo</li>\n<li><strong>Alertas e notificações</strong>: Usuários podem se inscrever em tipos específicos de estudos</li>\n</ol>\n\n<h4>Formato de entrada</h4>\n<p>O campo geralmente aceita <strong>valores únicos ou múltiplos</strong> de uma lista predefinida.</p>\n<p><strong>Exemplos corretos</strong>:</p>\n<p>Estudo com sujeitos humanos:</p>\n<pre>Humanos</pre>\n<p>Estudo com animais:</p>\n<pre>Animais</pre>\n<p>Estudo com culturas celulares:</p>\n<pre>In vitro</pre>\n<p>Estudo combinado:</p>\n<pre>Animais; In vitro</pre>\n\n<h4>Relação com outros metadados</h4>\n<p>Este campo se complementa com:</p>\n<ul>\n<li><strong>Tipo de estudo</strong>: Observacional, experimental, revisão sistemática</li>\n<li><strong>Área temática</strong>: Biomedicina, farmacologia, toxicologia</li>\n<li><strong>Palavras-chave</strong>: Detalhes específicos do modelo utilizado</li>\n<li><strong>Resumo/Abstract</strong>: Descrição metodológica breve</li>\n<li><strong>Metodologia completa</strong>: Descrição exaustiva no texto do artigo</li>\n</ul>\n\n<h4>Importância para bases de dados</h4>\n<p>As bases de dados acadêmicas utilizam este campo para:</p>\n<ul>\n<li><strong>PubMed</strong>: Filtro \"Species\" permite buscar por tipo de sujeito</li>\n<li><strong>Scopus</strong>: Classificação de estudos pré-clínicos vs clínicos</li>\n<li><strong>Web of Science</strong>: Refinamento de resultados por metodologia</li>\n<li><strong>SciELO</strong>: Categorização de artigos biomédicos</li>\n</ul>\n\n<h4>Nota importante</h4>\n<p><strong>Este campo NÃO contém nem substitui</strong>:</p>\n<ul>\n<li>Detalhes das espécies ou linhagens utilizadas</li>\n<li>Número de sujeitos ou tamanho amostral</li>\n<li>Procedimentos experimentais específicos</li>\n<li>Declarações de aprovação ética</li>\n<li>Protocolos de manejo de sujeitos</li>\n</ul>\n<p>Toda essa informação detalhada deve estar nas seções correspondentes do artigo completo.</p>\n','franco','2026-01-09 08:35:02','franco','2026-01-09 08:35:02'),(88,'tipo-sujetos-investigación','tipo_sujetos_investigacion','en','<!-- INGLÉS -->\n<h3>What is research subject type?</h3>\n<p>The <code>tipo-sujeto-investigacion</code> field is a <strong>classification metadata</strong> that specifies in general terms the nature of the subjects used in the scientific study. This field serves for indexing, searching, and quick filtering of articles; it <strong>does not replace the detailed description</strong> that should appear in the article\'s Methodology section.</p>\n\n<h4>Difference from other fields</h4>\n<p><strong>This field is for general classification</strong>:</p>\n<ul>\n<li>Purpose: Indexing, filtering, database searches</li>\n<li>Content: Broad category (Humans / Animals / In vitro)</li>\n<li>Location: Article metadata</li>\n</ul>\n<p><strong>Detailed information goes in other fields</strong>:</p>\n<ul>\n<li>Exact species, strains, ages → \"Materials and Methods\" section</li>\n<li>Ethical approvals → \"Ethics statements\" field</li>\n<li>Number of subjects, inclusion criteria → \"Methods\" section</li>\n<li>Experimental conditions → \"Procedures\" section</li>\n</ul>\n\n<h4>Main categories</h4>\n<p>This field typically accepts values from a controlled list:</p>\n<p><strong>Common values</strong>:</p>\n<ul>\n<li><strong>Humans</strong></li>\n<li><strong>Animals</strong></li>\n<li><strong>In vitro</strong></li>\n<li><strong>In silico</strong> (computational models)</li>\n<li><strong>Ex vivo</strong> (tissues outside the organism)</li>\n<li><strong>Mixed</strong> (combination of types)</li>\n<li><strong>Not applicable</strong> (theoretical studies, reviews)</li>\n</ul>\n\n<h4>What is this field used for?</h4>\n<p><strong>Main functions</strong>:</p>\n<ol>\n<li><strong>Search filtering</strong>: Allows researchers to search only for studies with humans, or only with animal models</li>\n<li><strong>Regulatory compliance</strong>: Databases may require this classification</li>\n<li><strong>Bibliometric analysis</strong>: Facilitates statistics on types of studies published</li>\n<li><strong>Automatic indexing</strong>: Automated systems categorize the article</li>\n<li><strong>Alerts and notifications</strong>: Users can subscribe to specific types of studies</li>\n</ol>\n\n<h4>Input format</h4>\n<p>The field generally accepts <strong>single or multiple values</strong> from a predefined list.</p>\n<p><strong>Correct examples</strong>:</p>\n<p>Study with human subjects:</p>\n<pre>Humans</pre>\n<p>Study with animals:</p>\n<pre>Animals</pre>\n<p>Study with cell cultures:</p>\n<pre>In vitro</pre>\n<p>Combined study:</p>\n<pre>Animals; In vitro</pre>\n\n<h4>Relationship with other metadata</h4>\n<p>This field complements:</p>\n<ul>\n<li><strong>Study type</strong>: Observational, experimental, systematic review</li>\n<li><strong>Subject area</strong>: Biomedicine, pharmacology, toxicology</li>\n<li><strong>Keywords</strong>: Specific details of the model used</li>\n<li><strong>Abstract</strong>: Brief methodological description</li>\n<li><strong>Complete methodology</strong>: Exhaustive description in the article text</li>\n</ul>\n\n<h4>Importance for databases</h4>\n<p>Academic databases use this field for:</p>\n<ul>\n<li><strong>PubMed</strong>: \"Species\" filter allows searching by subject type</li>\n<li><strong>Scopus</strong>: Classification of preclinical vs clinical studies</li>\n<li><strong>Web of Science</strong>: Results refinement by methodology</li>\n<li><strong>SciELO</strong>: Categorization of biomedical articles</li>\n</ul>\n\n<h4>Important note</h4>\n<p><strong>This field does NOT contain or replace</strong>:</p>\n<ul>\n<li>Details of species or strains used</li>\n<li>Number of subjects or sample size</li>\n<li>Specific experimental procedures</li>\n<li>Ethical approval declarations</li>\n<li>Subject handling protocols</li>\n</ul>\n<p>All that detailed information must be in the corresponding sections of the complete article.</p>\n','franco','2026-01-09 08:35:02','franco','2026-01-09 08:35:02'),(89,'tipo-sujetos-investigación','tipo_sujetos_investigacion','it','<!-- ITALIANO -->\n<h3>Cos\'è il tipo di soggetto di ricerca?</h3>\n<p>Il campo <code>tipo-sujeto-investigacion</code> è un <strong>metadato di classificazione</strong> che specifica in modo generale la natura dei soggetti utilizzati nello studio scientifico. Questo campo serve per indicizzazione, ricerche e filtro rapido di articoli; <strong>non sostituisce la descrizione dettagliata</strong> che deve apparire nella sezione Metodologia dell\'articolo.</p>\n\n<h4>Differenza con altri campi</h4>\n<p><strong>Questo campo è per la classificazione generale</strong>:</p>\n<ul>\n<li>Scopo: Indicizzazione, filtraggio, ricerche nei database</li>\n<li>Contenuto: Categoria ampia (Umani / Animali / In vitro)</li>\n<li>Posizione: Metadati dell\'articolo</li>\n</ul>\n<p><strong>L\'informazione dettagliata va in altri campi</strong>:</p>\n<ul>\n<li>Specie esatte, ceppi, età → Sezione \"Materiali e Metodi\"</li>\n<li>Approvazioni etiche → Campo \"Dichiarazioni etiche\"</li>\n<li>Numero di soggetti, criteri di inclusione → Sezione \"Metodi\"</li>\n<li>Condizioni sperimentali → Sezione \"Procedure\"</li>\n</ul>\n\n<h4>Categorie principali</h4>\n<p>Questo campo accetta tipicamente valori da una lista controllata:</p>\n<p><strong>Valori comuni</strong>:</p>\n<ul>\n<li><strong>Umani</strong></li>\n<li><strong>Animali</strong></li>\n<li><strong>In vitro</strong></li>\n<li><strong>In silico</strong> (modelli computazionali)</li>\n<li><strong>Ex vivo</strong> (tessuti fuori dall\'organismo)</li>\n<li><strong>Misto</strong> (combinazione di tipi)</li>\n<li><strong>Non applicabile</strong> (studi teorici, revisioni)</li>\n</ul>\n\n<h4>A cosa serve questo campo?</h4>\n<p><strong>Funzioni principali</strong>:</p>\n<ol>\n<li><strong>Filtro delle ricerche</strong>: Permette ai ricercatori di cercare solo studi con umani, o solo con modelli animali</li>\n<li><strong>Conformità normativa</strong>: I database possono richiedere questa classificazione</li>\n<li><strong>Analisi bibliometriche</strong>: Facilita le statistiche sui tipi di studi pubblicati</li>\n<li><strong>Indicizzazione automatica</strong>: I sistemi automatizzati categorizzano l\'articolo</li>\n<li><strong>Avvisi e notifiche</strong>: Gli utenti possono iscriversi a tipi specifici di studi</li>\n</ol>\n\n<h4>Formato di inserimento</h4>\n<p>Il campo generalmente accetta <strong>valori singoli o multipli</strong> da una lista predefinita.</p>\n<p><strong>Esempi corretti</strong>:</p>\n<p>Studio con soggetti umani:</p>\n<pre>Umani</pre>\n<p>Studio con animali:</p>\n<pre>Animali</pre>\n<p>Studio con colture cellulari:</p>\n<pre>In vitro</pre>\n<p>Studio combinato:</p>\n<pre>Animali; In vitro</pre>\n\n<h4>Relazione con altri metadati</h4>\n<p>Questo campo si integra con:</p>\n<ul>\n<li><strong>Tipo di studio</strong>: Osservazionale, sperimentale, revisione sistematica</li>\n<li><strong>Area tematica</strong>: Biomedicina, farmacologia, tossicologia</li>\n<li><strong>Parole chiave</strong>: Dettagli specifici del modello utilizzato</li>\n<li><strong>Abstract</strong>: Descrizione metodologica breve</li>\n<li><strong>Metodologia completa</strong>: Descrizione esaustiva nel testo dell\'articolo</li>\n</ul>\n\n<h4>Importanza per i database</h4>\n<p>I database accademici utilizzano questo campo per:</p>\n<ul>\n<li><strong>PubMed</strong>: Il filtro \"Species\" permette di cercare per tipo di soggetto</li>\n<li><strong>Scopus</strong>: Classificazione di studi preclinici vs clinici</li>\n<li><strong>Web of Science</strong>: Raffinamento dei risultati per metodologia</li>\n<li><strong>SciELO</strong>: Categorizzazione di articoli biomedici</li>\n</ul>\n\n<h4>Nota importante</h4>\n<p><strong>Questo campo NON contiene né sostituisce</strong>:</p>\n<ul>\n<li>Dettagli delle specie o ceppi utilizzati</li>\n<li>Numero di soggetti o dimensione del campione</li>\n<li>Procedure sperimentali specifiche</li>\n<li>Dichiarazioni di approvazione etica</li>\n<li>Protocolli di gestione dei soggetti</li>\n</ul>\n<p>Tutta questa informazione dettagliata deve essere nelle sezioni corrispondenti dell\'articolo completo.</p>\n','franco','2026-01-09 08:35:02','franco','2026-01-09 08:35:02'),(90,'tipo-sujetos-investigación','tipo_sujetos_investigacion','fr','<!-- FRANCÉS -->\n<h3>Qu\'est-ce que le type de sujet de recherche?</h3>\n<p>Le champ <code>tipo-sujeto-investigacion</code> est une <strong>métadonnée de classification</strong> qui spécifie de manière générale la nature des sujets utilisés dans l\'étude scientifique. Ce champ sert à l\'indexation, aux recherches et au filtrage rapide d\'articles; il <strong>ne remplace pas la description détaillée</strong> qui doit apparaître dans la section Méthodologie de l\'article.</p>\n\n<h4>Différence avec d\'autres champs</h4>\n<p><strong>Ce champ est pour la classification générale</strong>:</p>\n<ul>\n<li>Objectif: Indexation, filtrage, recherches dans les bases de données</li>\n<li>Contenu: Catégorie large (Humains / Animaux / In vitro)</li>\n<li>Localisation: Métadonnées de l\'article</li>\n</ul>\n<p><strong>L\'information détaillée va dans d\'autres champs</strong>:</p>\n<ul>\n<li>Espèces exactes, souches, âges → Section \"Matériels et Méthodes\"</li>\n<li>Approbations éthiques → Champ \"Déclarations éthiques\"</li>\n<li>Nombre de sujets, critères d\'inclusion → Section \"Méthodes\"</li>\n<li>Conditions expérimentales → Section \"Procédures\"</li>\n</ul>\n\n<h4>Catégories principales</h4>\n<p>Ce champ accepte typiquement des valeurs d\'une liste contrôlée:</p>\n<p><strong>Valeurs courantes</strong>:</p>\n<ul>\n<li><strong>Humains</strong></li>\n<li><strong>Animaux</strong></li>\n<li><strong>In vitro</strong></li>\n<li><strong>In silico</strong> (modèles informatiques)</li>\n<li><strong>Ex vivo</strong> (tissus en dehors de l\'organisme)</li>\n<li><strong>Mixte</strong> (combinaison de types)</li>\n<li><strong>Non applicable</strong> (études théoriques, revues)</li>\n</ul>\n\n<h4>À quoi sert ce champ?</h4>\n<p><strong>Fonctions principales</strong>:</p>\n<ol>\n<li><strong>Filtrage des recherches</strong>: Permet aux chercheurs de rechercher uniquement des études avec des humains, ou uniquement avec des modèles animaux</li>\n<li><strong>Conformité réglementaire</strong>: Les bases de données peuvent exiger cette classification</li>\n<li><strong>Analyses bibliométriques</strong>: Facilite les statistiques sur les types d\'études publiées</li>\n<li><strong>Indexation automatique</strong>: Les systèmes automatisés catégorisent l\'article</li>\n<li><strong>Alertes et notifications</strong>: Les utilisateurs peuvent s\'abonner à des types spécifiques d\'études</li>\n</ol>\n\n<h4>Format de saisie</h4>\n<p>Le champ accepte généralement des <strong>valeurs uniques ou multiples</strong> d\'une liste prédéfinie.</p>\n<p><strong>Exemples corrects</strong>:</p>\n<p>Étude avec sujets humains:</p>\n<pre>Humains</pre>\n<p>Étude avec animaux:</p>\n<pre>Animaux</pre>\n<p>Étude avec cultures cellulaires:</p>\n<pre>In vitro</pre>\n<p>Étude combinée:</p>\n<pre>Animaux; In vitro</pre>\n\n<h4>Relation avec d\'autres métadonnées</h4>\n<p>Ce champ complète:</p>\n<ul>\n<li><strong>Type d\'étude</strong>: Observationnelle, expérimentale, revue systématique</li>\n<li><strong>Domaine thématique</strong>: Biomédecine, pharmacologie, toxicologie</li>\n<li><strong>Mots-clés</strong>: Détails spécifiques du modèle utilisé</li>\n<li><strong>Résumé/Abstract</strong>: Description méthodologique brève</li>\n<li><strong>Méthodologie complète</strong>: Description exhaustive dans le texte de l\'article</li>\n</ul>\n\n<h4>Importance pour les bases de données</h4>\n<p>Les bases de données académiques utilisent ce champ pour:</p>\n<ul>\n<li><strong>PubMed</strong>: Le filtre \"Species\" permet de rechercher par type de sujet</li>\n<li><strong>Scopus</strong>: Classification des études précliniques vs cliniques</li>\n<li><strong>Web of Science</strong>: Raffinement des résultats par méthodologie</li>\n<li><strong>SciELO</strong>: Catégorisation des articles biomédicaux</li>\n</ul>\n\n<h4>Note importante</h4>\n<p><strong>Ce champ NE contient NI ne remplace</strong>:</p>\n<ul>\n<li>Détails des espèces ou souches utilisées</li>\n<li>Nombre de sujets ou taille de l\'échantillon</li>\n<li>Procédures expérimentales spécifiques</li>\n<li>Déclarations d\'approbation éthique</li>\n<li>Protocoles de manipulation des sujets</li>\n</ul>\n<p>Toute cette information détaillée doit être dans les sections correspondantes de l\'article complet.</p>\n','franco','2026-01-09 08:35:02','franco','2026-01-09 08:35:02'),(91,'tipo-sujetos-investigación','tipo_sujetos_investigacion','de','<!-- ALEMÁN -->\n<h3>Was ist der Forschungssubjekttyp?</h3>\n<p>Das Feld <code>tipo-sujeto-investigacion</code> ist ein <strong>Klassifizierungsmetadatum</strong>, das allgemein die Art der in der wissenschaftlichen Studie verwendeten Subjekte angibt. Dieses Feld dient der Indexierung, Suche und schnellen Filterung von Artikeln; es <strong>ersetzt nicht die detaillierte Beschreibung</strong>, die im Methodikteil des Artikels erscheinen sollte.</p>\n\n<h4>Unterschied zu anderen Feldern</h4>\n<p><strong>Dieses Feld dient der allgemeinen Klassifizierung</strong>:</p>\n<ul>\n<li>Zweck: Indexierung, Filterung, Datenbanksuchen</li>\n<li>Inhalt: Breite Kategorie (Menschen / Tiere / In vitro)</li>\n<li>Position: Artikel-Metadaten</li>\n</ul>\n<p><strong>Detaillierte Informationen gehören in andere Felder</strong>:</p>\n<ul>\n<li>Genaue Arten, Stämme, Alter → Abschnitt \"Material und Methoden\"</li>\n<li>Ethische Genehmigungen → Feld \"Ethikerklärungen\"</li>\n<li>Anzahl der Probanden, Einschlusskriterien → Abschnitt \"Methoden\"</li>\n<li>Experimentelle Bedingungen → Abschnitt \"Verfahren\"</li>\n</ul>\n\n<h4>Hauptkategorien</h4>\n<p>Dieses Feld akzeptiert typischerweise Werte aus einer kontrollierten Liste:</p>\n<p><strong>Häufige Werte</strong>:</p>\n<ul>\n<li><strong>Menschen</strong></li>\n<li><strong>Tiere</strong></li>\n<li><strong>In vitro</strong></li>\n<li><strong>In silico</strong> (Computermodelle)</li>\n<li><strong>Ex vivo</strong> (Gewebe außerhalb des Organismus)</li>\n<li><strong>Gemischt</strong> (Kombination von Typen)</li>\n<li><strong>Nicht zutreffend</strong> (theoretische Studien, Übersichtsarbeiten)</li>\n</ul>\n\n<h4>Wozu dient dieses Feld?</h4>\n<p><strong>Hauptfunktionen</strong>:</p>\n<ol>\n<li><strong>Suchfilterung</strong>: Ermöglicht Forschern, nur nach Studien mit Menschen oder nur mit Tiermodellen zu suchen</li>\n<li><strong>Regulatorische Compliance</strong>: Datenbanken können diese Klassifizierung erfordern</li>\n<li><strong>Bibliometrische Analysen</strong>: Erleichtert Statistiken über veröffentlichte Studientypen</li>\n<li><strong>Automatische Indexierung</strong>: Automatisierte Systeme kategorisieren den Artikel</li>\n<li><strong>Benachrichtigungen</strong>: Benutzer können bestimmte Studientypen abonnieren</li>\n</ol>\n\n<h4>Eingabeformat</h4>\n<p>Das Feld akzeptiert im Allgemeinen <strong>einzelne oder mehrere Werte</strong> aus einer vordefinierten Liste.</p>\n<p><strong>Korrekte Beispiele</strong>:</p>\n<p>Studie mit menschlichen Probanden:</p>\n<pre>Menschen</pre>\n<p>Studie mit Tieren:</p>\n<pre>Tiere</pre>\n<p>Studie mit Zellkulturen:</p>\n<pre>In vitro</pre>\n<p>Kombinierte Studie:</p>\n<pre>Tiere; In vitro</pre>\n\n<h4>Beziehung zu anderen Metadaten</h4>\n<p>Dieses Feld ergänzt:</p>\n<ul>\n<li><strong>Studientyp</strong>: Beobachtend, experimentell, systematische Übersicht</li>\n<li><strong>Themenbereich</strong>: Biomedizin, Pharmakologie, Toxikologie</li>\n<li><strong>Schlüsselwörter</strong>: Spezifische Details des verwendeten Modells</li>\n<li><strong>Abstract</strong>: Kurze methodische Beschreibung</li>\n<li><strong>Vollständige Methodik</strong>: Ausführliche Beschreibung im Artikeltext</li>\n</ul>\n\n<h4>Bedeutung für Datenbanken</h4>\n<p>Akademische Datenbanken verwenden dieses Feld für:</p>\n<ul>\n<li><strong>PubMed</strong>: Der \"Species\"-Filter ermöglicht die Suche nach Subjekttyp</li>\n<li><strong>Scopus</strong>: Klassifizierung von präklinischen vs. klinischen Studien</li>\n<li><strong>Web of Science</strong>: Verfeinerung der Ergebnisse nach Methodik</li>\n<li><strong>SciELO</strong>: Kategorisierung biomedizinischer Artikel</li>\n</ul>\n\n<h4>Wichtiger Hinweis</h4>\n<p><strong>Dieses Feld enthält NICHT und ersetzt NICHT</strong>:</p>\n<ul>\n<li>Details zu verwendeten Arten oder Stämmen</li>\n<li>Anzahl der Probanden oder Stichprobengröße</li>\n<li>Spezifische experimentelle Verfahren</li>\n<li>Erklärungen zur ethischen Genehmigung</li>\n<li>Protokolle zum Umgang mit Probanden</li>\n</ul>\n<p>All diese detaillierten Informationen müssen in den entsprechenden Abschnitten des vollständigen Artikels enthalten sein.</p>','franco','2026-01-09 08:35:02','franco','2026-01-09 08:35:02');
