INSERT INTO `shortcodes` VALUES (1,'epigraph','Epígrafe','Cita breve al inicio de un artículo o sección, generalmente de otro autor, que introduce o contextualiza el tema.','::: epigraph',':::',1,NULL,'<disp-quote content-type=\"epigraph\">','<disp-quote content-type=\"epigraph\">\n  <p>{{contenido}}</p>\n  <attrib>{{atribucion}}</attrib>\n</disp-quote>','body','::: epigraph\nEl conocimiento es poder.\n— Francis Bacon\n:::',NULL,1,1,'comun','semantico',1,'2025-12-19 02:23:35','2025-12-19 02:23:35'),(3,'figure','Figura','Imagen, gráfico o ilustración con leyenda y fuente opcional.','::: {.fig #fig-id}',':::',1,'id','<fig>','<fig id=\"{{id}}\">\n  <label>{{label}}</label>\n  <caption><p>{{caption}}</p></caption>\n  <graphic xlink:href=\"{{archivo}}\"/>\n</fig>','body','::: {.fig #fig-resultados}\r\n![Resultados del experimento](imagen.png)\r\n\r\nFigura 1. Distribución de resultados por grupo etario.\r\n:::',NULL,1,3,'comun','semantico',1,'2025-12-19 02:23:35','2026-02-20 01:41:04'),(4,'table-wrap','Tabla','Tabla de datos con título y notas al pie opcionales.','::: {.table #tbl-id}',':::',1,'id','<table-wrap>','<table-wrap id=\"{{id}}\">\n  <label>{{label}}</label>\n  <caption><p>{{caption}}</p></caption>\n  <table>{{contenido}}</table>\n</table-wrap>','body','::: {.table #tbl-datos}\n| Variable | Grupo A | Grupo B |\n|----------|---------|----------|\n| Media    | 45.2    | 52.1     |\n\nTabla 1. Comparación de medias entre grupos.\n:::',NULL,1,4,'comun','semantico',1,'2025-12-19 02:23:35','2025-12-19 02:23:35'),(6,'boxed-text','Recuadro','Texto destacado en un recuadro, usado para resúmenes, advertencias o información complementaria.','::: {.box type=\"info\"}',':::',1,'type','<boxed-text>','<boxed-text content-type=\"{{type}}\">\n  <p>{{contenido}}</p>\n</boxed-text>','body','::: {.box type=\"warning\"}\n**Advertencia**: Los resultados pueden variar según las condiciones ambientales.\n:::',NULL,1,6,'comun','semantico',1,'2025-12-19 02:23:35','2025-12-19 02:23:35'),(7,'verse','Verso','Texto poético que preserva saltos de línea y formato original.','::: verse',':::',1,NULL,'<verse-group>','<verse-group>\n  <verse-line>{{linea}}</verse-line>\n</verse-group>','body','::: verse\nCaminante, son tus huellas\nel camino y nada más;\ncaminante, no hay camino,\nse hace camino al andar.\n:::',NULL,1,7,'comun','semantico',1,'2025-12-19 02:23:35','2025-12-19 02:23:35'),(8,'code','Código fuente','Bloque de código de programación con resaltado de sintaxis.','::: {.code language=\"python\"}\r\n~~~',':::',1,'language','<code>','<code language=\"{{language}}\">\r\n~~~\r\n{{contenido}}\r\n~~~\r\n</code>','body','::: {.code language=\"python\"}\r\n~~~\r\ndef factorial(n):\r\n    if n <= 1:\r\n        return 1\r\n    return n * factorial(n-1)\r\n~~~\r\n:::',NULL,1,8,'comun','semantico',1,'2025-12-19 02:23:35','2026-02-20 01:42:52'),(13,'chem-struct','Estructura química','Fórmula o estructura química representada en formato estándar.','::: chem-struct',':::',1,NULL,'<chem-struct>','<chem-struct>\n  {{contenido}}\n</chem-struct>','body','::: chem-struct\nH₂SO₄\n:::',NULL,1,20,'quimica','semantico',1,'2025-12-19 02:23:35','2025-12-31 20:14:44'),(14,'disp-formula','Fórmula matemática','Ecuación o fórmula matemática destacada en línea aparte.','::: {.formula #eq-id}',':::',1,'id','<disp-formula>','<disp-formula id=\"{{id}}\">\n  <tex-math>{{contenido}}</tex-math>\n</disp-formula>','body','::: {.formula #eq-einstein}\n$$E = mc^2$$\n:::',NULL,1,21,'matematicas','semantico',1,'2025-12-19 02:23:35','2025-12-31 20:14:57'),(15,'supplementary','Material suplementario','Referencia a datos, archivos o contenido adicional disponible como anexo.','::: {.supplementary #supp-id}',':::',1,'id','<supplementary-material>','<supplementary-material id=\"{{id}}\" xlink:href=\"{{archivo}}\">\n  <caption><p>{{descripcion}}</p></caption>\n</supplementary-material>','body','::: {.supplementary #supp-datos}\nDataset completo disponible en: datos_experimento.xlsx\n:::',NULL,1,22,'comun','semantico',1,'2025-12-19 02:23:35','2025-12-19 02:23:35'),(16,'clinical-trial','Ensayo clínico','Información de registro de ensayo clínico.','::: clinical-trial',':::',1,'registro,numero','<clinical-trial>','<clinical-trial>\r\n  <registry>{{registro}}</registry>\r\n  <trial-id>{{numero}}</trial-id>\r\n</clinical-trial>','body','::: clinical-trial\r\nRegistro: ClinicalTrials.gov\r\nNúmero: NCT01234567\r\n:::','Extrae \"Registro:\" y \"Número:\" del contenido.\r\nCompatible con ClinicalTrials.gov, ISRCTN, EudraCT.\r\nRequiere función Lua custom para parsear texto en español.',1,23,'medicina','semantico',1,'2025-12-19 02:23:35','2025-12-31 20:16:09'),(17,'source-quote','Cita de fuente primaria','Cita textual de documento histórico o fuente primaria con referencia archivística.','::: {.source archivo=\"\"}',':::',1,'archivo','<disp-quote content-type=\"primary-source\">','<disp-quote content-type=\"primary-source\">\n  <p>{{contenido}}</p>\n  <attrib>{{archivo}}</attrib>\n</disp-quote>','body','::: {.source archivo=\"AGN, Sala IX, Legajo 23-5-6\"}\nEn el día de la fecha se procedió a la lectura del acta...\n:::',NULL,1,30,'comun','semantico',1,'2025-12-19 02:23:35','2025-12-19 02:23:35'),(18,'glossary','Glosario','Definición de término técnico o especializado.','::: {.glossary term=\"\"}',':::',1,'term','<glossary>','<def-list>\n  <def-item>\n    <term>{{term}}</term>\n    <def><p>{{contenido}}</p></def>\n  </def-item>\n</def-list>','body','::: {.glossary term=\"Hermenéutica\"}\nMétodo de interpretación de textos que busca comprender el significado\na partir del contexto histórico y cultural del autor.\n:::',NULL,1,31,'ciencias-sociales','semantico',1,'2025-12-19 02:23:35','2025-12-31 20:15:25'),(19,'speech','Entrevista/Discurso/Diálogo','Transcripción de discurso oral o diálogo con identificación del hablante.','::: {.speech speaker=\"\"}',':::',1,'speaker','<speech>','<speech>\n  <speaker>{{speaker}}</speaker>\n  <p>{{contenido}}</p>\n</speech>','body','::: {.speech speaker=\"Entrevistado A\"}\nYo creo que la situación cambió radicalmente a partir de 1990...\n:::',NULL,1,32,'ciencias-sociales','semantico',1,'2025-12-19 02:23:35','2026-04-24 19:04:19'),(21,'field-note','Nota de campo','Observación etnográfica o nota de trabajo de campo.','::: {.fieldnote date=\"\"}',':::',1,'date','<disp-quote content-type=\"field-note\">','<disp-quote content-type=\"field-note\">\n  <attrib>Nota de campo, {{date}}</attrib>\n  <p>{{contenido}}</p>\n</disp-quote>','body','::: {.fieldnote date=\"2024-03-15\"}\nLlegué al mercado a las 7am. Los vendedores ya estaban\norganizando sus puestos...\n:::',NULL,1,41,'ciencias-sociales','semantico',1,'2025-12-19 02:23:35','2025-12-31 20:15:25'),(22,'case-study','Estudio de caso','Descripción de caso analizado con identificador.','::: {.case id=\"\"}',':::',1,'id','<boxed-text content-type=\"case-study\">','<boxed-text content-type=\"case-study\">\n  <caption><title>Caso {{id}}</title></caption>\n  <p>{{contenido}}</p>\n</boxed-text>','body','::: {.case id=\"Empresa-Alpha\"}\n**Contexto**: Empresa mediana del sector manufacturero...\n**Problema**: Caída de productividad del 15%...\n:::',NULL,1,42,'medicina','semantico',1,'2025-12-19 02:23:35','2025-12-31 20:14:29'),(24,'chem-equation','Ecuación química','Ecuación química balanceada con reactivos y productos. Permite notación estándar con flechas de reacción.','::: chem-equation',':::',1,NULL,'disp-formula','<disp-formula content-type=\"chem-equation\"><alternatives><tex-math>{{contenido}}</tex-math></alternatives></disp-formula>','body','::: chem-equation\n2H₂ + O₂ → 2H₂O\n:::',NULL,1,0,'quimica','semantico',1,'2025-12-19 18:45:21','2025-12-31 20:14:44'),(25,'reaction-scheme','Esquema de reacción','Esquema de reacción química con múltiples pasos, intermediarios y condiciones.','::: reaction-scheme',':::',1,NULL,'fig','<fig fig-type=\"reaction-scheme\"><caption><title>{{titulo}}</title></caption><graphic/></fig>','body','::: reaction-scheme\n[Esquema con pasos de síntesis]\n:::',NULL,1,0,'quimica','semantico',1,'2025-12-19 18:45:21','2025-12-31 20:32:02'),(26,'reaction-mechanism','Mecanismo de reacción','Descripción paso a paso del mecanismo de una reacción química.','::: reaction-mechanism',':::',1,NULL,'boxed-text','<boxed-text content-type=\"reaction-mechanism\"><caption><title>Mecanismo</title></caption>{{contenido}}</boxed-text>','body','::: reaction-mechanism\nPaso 1: Ataque nucleofílico...\nPaso 2: Eliminación...\n:::',NULL,1,0,'quimica','semantico',1,'2025-12-19 18:45:21','2025-12-31 20:32:02'),(27,'spectral-data','Datos espectroscópicos','Datos de caracterización espectroscópica: RMN, IR, MS, UV-Vis.','::: spectral-data',':::',1,'tipo','supplementary-material','<supplementary-material content-type=\"spectral-data\" specific-use=\"{{tipo}}\">{{contenido}}</supplementary-material>','body','::: spectral-data {tipo=\"RMN-1H\"}\n¹H NMR (400 MHz, CDCl₃): δ 7.26 (s, 1H)...\n:::',NULL,1,0,'quimica','semantico',1,'2025-12-19 18:45:21','2025-12-31 20:26:16'),(28,'experimental-procedure','Procedimiento experimental','Descripción detallada de un procedimiento de síntesis o análisis.','::: experimental-procedure',':::',1,NULL,'sec','<sec sec-type=\"experimental-procedure\"><title>Procedimiento</title>{{contenido}}</sec>','body','::: experimental-procedure\nEn un matraz de 250 mL se añadieron...\n:::',NULL,1,0,'quimica','semantico',1,'2025-12-19 18:45:21','2025-12-31 20:14:44'),(29,'crystal-data','Datos cristalográficos','Datos de estructura cristalina obtenidos por difracción de rayos X.','::: crystal-data',':::',1,NULL,'supplementary-material','<supplementary-material content-type=\"crystal-data\">{{contenido}}</supplementary-material>','body','::: crystal-data\nSistema cristalino: monoclínico\nGrupo espacial: P2₁/c\n:::',NULL,1,0,'quimica','semantico',1,'2025-12-19 18:45:21','2025-12-31 20:14:44'),(30,'theorem','Teorema','Enunciado de un teorema matemático con nombre opcional.','::: theorem',':::',1,NULL,'statement','<statement content-type=\"theorem\"><label>Teorema</label><title>{{titulo}}</title><p>{{contenido}}</p></statement>','body','::: theorem {nombre=\"Pitágoras\"}\nEn un triángulo rectángulo, el cuadrado de la hipotenusa...\n:::',NULL,1,0,'matematicas','semantico',1,'2025-12-19 18:45:21','2025-12-31 20:26:26'),(31,'proof','Demostración','Demostración formal de un teorema o proposición.','::: proof',':::',1,NULL,'statement','<statement content-type=\"proof\"><label>Demostración</label>{{contenido}}<p>∎</p></statement>','body','::: proof\nSea a, b, c los lados del triángulo...\n:::',NULL,1,0,'matematicas','semantico',1,'2025-12-19 18:45:21','2025-12-31 20:26:26'),(32,'definition','Definición','Definición formal de un concepto matemático.','::: definition',':::',1,NULL,'statement','<statement content-type=\"definition\"><label>Definición</label><title>{{titulo}}</title><p>{{contenido}}</p></statement>','body','::: definition {nombre=\"Límite\"}\nSea f una función definida en un intervalo abierto...\n:::',NULL,1,0,'matematicas','semantico',1,'2025-12-19 18:45:21','2025-12-31 20:14:57'),(33,'lemma','Lema','Proposición auxiliar utilizada para demostrar un teorema.','::: lemma',':::',1,NULL,'statement','<statement content-type=\"lemma\"><label>Lema</label><title>{{titulo}}</title><p>{{contenido}}</p></statement>','body','::: lemma\nSi n es par, entonces n² es par.\n:::',NULL,1,0,'matematicas','semantico',1,'2025-12-19 18:45:21','2025-12-31 20:26:26'),(34,'corollary','Corolario','Consecuencia directa de un teorema ya demostrado.','::: corollary',':::',1,NULL,'statement','<statement content-type=\"corollary\"><label>Corolario</label><p>{{contenido}}</p></statement>','body','::: corollary\nTodo número primo mayor que 2 es impar.\n:::',NULL,1,0,'matematicas','semantico',1,'2025-12-19 18:45:21','2025-12-31 20:14:57'),(35,'proposition','Proposición','Afirmación matemática que requiere demostración.','::: proposition',':::',1,NULL,'statement','<statement content-type=\"proposition\"><label>Proposición</label><p>{{contenido}}</p></statement>','body','::: proposition\nLa suma de los ángulos internos de un triángulo es 180°.\n:::',NULL,1,0,'matematicas','semantico',1,'2025-12-19 18:45:21','2025-12-31 20:31:47'),(36,'axiom','Axioma','Verdad evidente que se acepta sin demostración.','::: axiom',':::',1,NULL,'statement','<statement content-type=\"axiom\"><label>Axioma</label><p>{{contenido}}</p></statement>','body','::: axiom\nPor dos puntos distintos pasa una única recta.\n:::',NULL,1,0,'matematicas','semantico',1,'2025-12-19 18:45:21','2025-12-31 20:14:57'),(37,'math-example','Ejemplo matemático','Ejemplo que ilustra la aplicación de un concepto o teorema.','::: math-example',':::',1,NULL,'boxed-text','<boxed-text content-type=\"example\"><label>Ejemplo</label>{{contenido}}</boxed-text>','body','::: math-example\nCalcular el límite de f(x) = (x²-1)/(x-1) cuando x→1...\n:::',NULL,1,0,'matematicas','semantico',1,'2025-12-19 18:45:21','2025-12-31 20:31:47'),(38,'numbered-equation','Ecuación numerada','Ecuación matemática con número de referencia.','::: numbered-equation',':::',1,'id','disp-formula','<disp-formula id=\"{{id}}\"><label>({{numero}})</label><alternatives><tex-math>{{contenido}}</tex-math></alternatives></disp-formula>','body','::: numbered-equation {id=\"eq-euler\"}\ne^{iπ} + 1 = 0\n:::',NULL,1,0,'matematicas','semantico',1,'2025-12-19 18:45:21','2025-12-31 20:31:47'),(39,'notation','Notación','Definición de notación o símbolos utilizados.','::: notation',':::',1,NULL,'def-list','<def-list list-type=\"notation\"><title>Notación</title>{{contenido}}</def-list>','body','::: notation\n- ∀: para todo\n- ∃: existe\n- ∈: pertenece a\n:::',NULL,1,0,'matematicas','semantico',1,'2025-12-19 18:45:21','2025-12-31 20:31:47'),(40,'problem','Problema','Enunciado de un problema matemático o físico.','::: problem',':::',1,NULL,'boxed-text','<boxed-text content-type=\"problem\"><label>Problema</label>{{contenido}}</boxed-text>','body','::: problem\nUn proyectil se lanza con velocidad inicial v₀...\n:::',NULL,1,0,'matematicas','semantico',1,'2025-12-19 18:45:21','2025-12-31 20:31:47'),(41,'solution','Solución','Desarrollo de la solución de un problema.','::: solution',':::',1,NULL,'boxed-text','<boxed-text content-type=\"solution\"><label>Solución</label>{{contenido}}</boxed-text>','body','::: solution\nAplicando las ecuaciones de movimiento...\n:::',NULL,1,0,'matematicas','semantico',1,'2025-12-19 18:45:21','2025-12-31 20:31:47'),(42,'primary-source','Fuente primaria','Cita de una fuente primaria (manuscrito, inscripción, texto antiguo) con referencia.','::: primary-source',':::',1,'fuente','disp-quote','<disp-quote content-type=\"primary-source\"><attrib>{{fuente}}</attrib>{{contenido}}</disp-quote>','body','::: primary-source {fuente=\"BNE Ms. 1234, f. 23r\"}\nEn aquel tiempo moraua en Toledo...\n:::',NULL,1,0,'filologia','semantico',1,'2025-12-19 18:45:21','2025-12-31 20:31:30'),(43,'apparatus','Aparato crítico','Notas del aparato crítico con variantes textuales entre manuscritos.','::: apparatus',':::',1,NULL,'fn-group','<fn-group content-type=\"apparatus\">{{contenido}}</fn-group>','body','::: apparatus\n¹ moraua] moraba B, morava C\n² Toledo] Toleto A\n:::',NULL,1,0,'filologia','semantico',1,'2025-12-19 18:45:21','2025-12-31 20:15:10'),(44,'variant','Variante textual','Indica una variante de lectura entre diferentes testimonios.','::: variant',':::',1,'testigos','app','<app><rdg wit=\"{{testigos}}\">{{contenido}}</rdg></app>','body','::: variant {testigos=\"A B\"}\nmoraua\n::: variant {testigos=\"C D\"}\nmoraba\n:::',NULL,1,0,'filologia','semantico',1,'2025-12-19 18:45:21','2025-12-31 20:31:30'),(45,'gloss','Glosa','Explicación o comentario sobre una palabra o pasaje del texto.','::: gloss',':::',1,'lema','gloss','<gloss><term>{{lema}}</term><def>{{contenido}}</def></gloss>','body','::: gloss {lema=\"fazaña\"}\nHecho notable, hazaña. Del lat. *facianea.\n:::',NULL,1,0,'filologia','semantico',1,'2025-12-19 18:45:21','2025-12-31 20:15:10'),(46,'ling-example','Ejemplo lingüístico','Ejemplo de uso lingüístico con glosa interlineal opcional.','::: ling-example',':::',1,NULL,'disp-quote','<disp-quote content-type=\"linguistic-example\"><label>{{numero}}</label>{{contenido}}</disp-quote>','body','::: ling-example\n(1) a. *El niño parece dormir.\n    b. El niño parece estar dormido.\n:::',NULL,1,0,'filologia','semantico',1,'2025-12-19 18:45:21','2025-12-31 20:31:30'),(47,'interlinear','Glosa interlineal','Texto con glosa morfológica interlineal (formato Leipzig).','::: interlinear',':::',1,'lengua','disp-quote','<disp-quote content-type=\"interlinear-gloss\" xml:lang=\"{{lengua}}\">{{contenido}}</disp-quote>','body','::: interlinear {lengua=\"lat\"}\nPuer        libr-um      leg-it\nniño.NOM    libro-AC     leer-3SG.PRES\n\'El niño lee el libro\'\n:::',NULL,1,0,'filologia','semantico',1,'2025-12-19 18:45:21','2025-12-31 20:15:10'),(48,'paleographic','Transcripción paleográfica','Transcripción de un manuscrito con convenciones paleográficas.','::: paleographic',':::',1,'tipo','disp-quote','<disp-quote content-type=\"paleographic\" specific-use=\"{{tipo}}\">{{contenido}}</disp-quote>','body','::: paleographic {tipo=\"diplomática\"}\nen aq<ue>l t<iem>po moraua en toledo | vn cauall<er>o...\n:::',NULL,1,0,'filologia','semantico',1,'2025-12-19 18:45:21','2025-12-31 20:31:30'),(49,'stemma','Stemma codicum','Representación del árbol genealógico de manuscritos.','::: stemma',':::',1,NULL,'fig','<fig fig-type=\"stemma\"><caption><title>Stemma codicum</title></caption><graphic/></fig>','body','::: stemma\n[Diagrama de relaciones entre manuscritos]\n:::',NULL,1,0,'filologia','semantico',1,'2025-12-19 18:45:21','2025-12-31 20:31:30'),(50,'etymology','Etimología','Explicación del origen y evolución de una palabra.','::: etymology',':::',1,'voz','def-item','<def-item><term>{{voz}}</term><def content-type=\"etymology\">{{contenido}}</def></def-item>','body','::: etymology {voz=\"palabra\"}\nDel lat. PARABOLA, y este del gr. παραβολή \'comparación\'.\n:::',NULL,1,0,'filologia','semantico',1,'2025-12-19 18:45:21','2025-12-31 20:15:10'),(51,'reconstructed','Texto reconstruido','Texto reconstruido o hipotético, marcado con asterisco convencional.','::: reconstructed',':::',1,NULL,'styled-content','<styled-content specific-use=\"reconstructed\">*{{contenido}}</styled-content>','body','::: reconstructed\n*FACIANEA > fazaña\n:::',NULL,1,0,'filologia','semantico',1,'2025-12-19 18:45:21','2025-12-31 20:31:30'),(52,'siglum','Sigla','Definición de sigla utilizada para un manuscrito o testimonio.','::: siglum',':::',0,'codigo,nombre','def-item','<def-item><term>{{codigo}}</term><def>{{nombre}}</def></def-item>','body','::: siglum {codigo=\"A\", nombre=\"BNE Ms. 1234\"}\n:::',NULL,1,0,'filologia','semantico',1,'2025-12-19 18:45:21','2025-12-31 20:31:30'),(53,'dosage','Dosis farmacológica','Indicación de dosis con fármaco, cantidad, unidad y frecuencia.','::: dosage',':::',1,'farmaco,cantidad,unidad,frecuencia','dosage','<dosage>\r\n  <drug>{{farmaco}}</drug>\r\n  <value>{{cantidad}}</value>\r\n  <unit>{{unidad}}</unit>\r\n  <frequency>{{frecuencia}}</frequency>\r\n</dosage>','body','::: dosage\r\nFármaco: enalapril\r\nCantidad: 10\r\nUnidad: mg\r\nFrecuencia: diaria\r\n:::',NULL,1,24,'medicina','semantico',0,'2025-12-31 20:17:00','2025-12-31 20:17:00'),(54,'patient-data','Datos de paciente','Características demográficas del paciente (edad, sexo).','::: patient-data',':::',1,'edad,sexo','patient-data','<patient-data>\r\n  <age units=\"years\">{{edad}}</age>\r\n  <sex>{{sexo}}</sex>\r\n</patient-data>','body','::: patient-data\r\nEdad: 45\r\nSexo: masculino\r\n:::',NULL,1,25,'medicina','metadata',0,'2025-12-31 20:17:15','2025-12-31 20:17:15'),(55,'diagnosis','Diagnóstico','Diagnóstico médico con código ICD si está disponible.','::: diagnosis',':::',1,NULL,'named-content','<named-content content-type=\"diagnosis\">{{contenido}}</named-content>','body','::: diag